{
  "name": "GitNotes - Personal Markdown Manager",
  "description": "A GitHub-inspired personal knowledge base for storing, editing, and previewing Markdown files locally."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface FileItem {
  id: string;
  name: string;
  content: string;
  updatedAt: string;
  language: string;
  size: number;
}

export interface Repository {
  id: string;
  name: string;
  description: string;
  isPrivate: boolean;
  updatedAt: string;
  files: FileItem[];
  stars: number;
  language: string;
}

export type ViewMode = 'read' | 'edit';

import { Repository } from '../types';
import { INITIAL_REPOS } from '../constants';

const STORAGE_KEY = 'gitnotes_data_v1';

export const loadRepositories = (): Repository[] => {
  try {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      return JSON.parse(saved);
    }
    // Initialize if empty
    localStorage.setItem(STORAGE_KEY, JSON.stringify(INITIAL_REPOS));
    return INITIAL_REPOS;
  } catch (error) {
    console.error('Failed to load repositories', error);
    return INITIAL_REPOS;
  }
};

export const saveRepositories = (repos: Repository[]): void => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(repos));
  } catch (error) {
    console.error('Failed to save repositories', error);
  }
};

import React from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';

interface MarkdownPreviewProps {
  content: string;
}

const MarkdownPreview: React.FC<MarkdownPreviewProps> = ({ content }) => {
  return (
    <div className="prose prose-slate max-w-none dark:prose-invert">
      <ReactMarkdown 
        remarkPlugins={[remarkGfm]}
        components={{
          code({node, inline, className, children, ...props}: any) {
            const match = /language-(\w+)/.exec(className || '')
            return !inline && match ? (
              <div className="bg-slate-100 p-4 rounded-md overflow-x-auto my-4 border border-border-default">
                <code className={className} {...props}>
                  {children}
                </code>
              </div>
            ) : (
              <code className="bg-slate-100 px-1.5 py-0.5 rounded text-sm font-mono text-fg-default" {...props}>
                {children}
              </code>
            )
          },
          h1: ({node, ...props}) => <h1 className="text-3xl font-semibold border-b border-border-default pb-2 mb-4 mt-6" {...props} />,
          h2: ({node, ...props}) => <h2 className="text-2xl font-semibold border-b border-border-default pb-2 mb-3 mt-5" {...props} />,
          blockquote: ({node, ...props}) => <blockquote className="border-l-4 border-border-default pl-4 text-fg-muted italic my-4" {...props} />,
          ul: ({node, ...props}) => <ul className="list-disc list-inside my-4 space-y-1" {...props} />,
          ol: ({node, ...props}) => <ol className="list-decimal list-inside my-4 space-y-1" {...props} />,
          a: ({node, ...props}) => <a className="text-accent-fg hover:underline cursor-pointer" {...props} />,
          table: ({node, ...props}) => <div className="overflow-x-auto my-4"><table className="min-w-full divide-y divide-border-default border border-border-default rounded-lg" {...props} /></div>,
          th: ({node, ...props}) => <th className="px-3 py-2 bg-canvas-subtle font-semibold text-left text-sm" {...props} />,
          td: ({node, ...props}) => <td className="px-3 py-2 border-t border-border-default text-sm" {...props} />,
          img: ({node, ...props}) => <img className="max-w-full rounded-lg border border-border-default my-4" {...props} />,
        }}
      >
        {content}
      </ReactMarkdown>
    </div>
  );
};

export default MarkdownPreview;

