                <Icons.Book size={20} className="text-fg-muted" />
                <Link to="/" className="hover:underline">username</Link>
                <span className="text-fg-muted">/</span>
                <span className="font-bold text-fg-default">{repo.name}</span>
                <span className="text-xs border border-border-default rounded-full px-2 py-0.5 text-fg-muted font-medium ml-2 text-fg-default">
                    {repo.isPrivate ? 'Private' : 'Public'}
                </span>
            </div>

            <div className="flex gap-3">
                <button className="bg-canvas-subtle border border-border-default text-xs font-bold px-3 py-1 rounded-md flex items-center gap-2 hover:bg-gray-100">
                   <Icons.Star size={14} /> Star
                </button>
                <button className="bg-canvas-subtle border border-border-default text-xs font-bold px-3 py-1 rounded-md flex items-center gap-2 hover:bg-gray-100">
                   <Icons.GitBranch size={14} /> Fork
