            </div>
        </div>

        <nav className="flex gap-6 mt-6 overflow-x-auto">
             <button className="flex items-center gap-2 font-semibold border-b-2 border-orange-500 pb-2 px-1 text-sm whitespace-nowrap">
                <span className="text-fg-default"><Icons.File size={16} className="inline mr-1"/> Code</span>
             </button>
             <button className="flex items-center gap-2 font-medium text-fg-muted hover:text-fg-default pb-2 px-1 text-sm whitespace-nowrap">
                <span className=""><Icons.Search size={16} className="inline mr-1"/> Issues</span>
             </button>
             <button className="flex items-center gap-2 font-medium text-fg-muted hover:text-fg-default pb-2 px-1 text-sm whitespace-nowrap">
                <span className=""><Icons.GitBranch size={16} className="inline mr-1"/> Pull requests</span>
             </button>
             <button className="flex items-center gap-2 font-medium text-fg-muted hover:text-fg-default pb-2 px-1 text-sm whitespace-nowrap">
                 <span className=""><Icons.Book size={16} className="inline mr-1"/> Wiki</span>
             </button>
             <button onClick={handleDeleteRepo} className="flex items-center gap-2 font-medium text-red-600 hover:text-red-700 pb-2 px-1 text-sm whitespace-nowrap ml-auto">
                 <Icons.Trash size={14} className="inline mr-1"/> Settings
             </button>
        </nav>
      </div>

      {/* Controls */}
      <div className="flex justify-between items-center mb-4">
        <div className="flex items-center gap-2">
            <button className="bg-canvas-subtle border border-border-default px-3 py-1.5 rounded-md text-sm font-semibold flex items-center gap-2 hover:bg-gray-100">
                <Icons.GitBranch size={14} /> main <span className="text-[10px]">▼</span>
            </button>
            <div className="hidden md:flex items-center gap-2 text-fg-muted text-sm ml-2">
                <Icons.GitBranch size={14} /> <strong>1</strong> branch
            </div>
        </div>
        <div className="flex items-center gap-2">
            <button 
                onClick={() => setShowAddFile(true)}
                className="bg-canvas-subtle border border-border-default px-3 py-1.5 rounded-md text-sm font-semibold hover:bg-gray-100 hidden md:block"
            >
                Add file
