         <div className="divide-y divide-border-default">
             {/* Header Row (Pseudo) */}
             {repo.files.map(file => (
                 <div key={file.id} className="px-4 py-2 hover:bg-canvas-subtle flex items-center group transition-colors">
                     <div className="w-8 text-fg-muted">
                        <Icons.File size={16} />
                     </div>
                     <div className="flex-1">
                        <Link to={`/${repo.id}/${file.id}`} className="text-fg-default hover:text-accent-fg hover:underline text-sm font-medium">
                            {file.name}
                        </Link>
                     </div>
                     <div className="hidden md:block flex-1 text-sm text-fg-muted">
                        Update {file.name}
                     </div>
                     <div className="text-xs text-fg-muted text-right w-24">
                        {new Date(file.updatedAt).toLocaleDateString()}
                     </div>
                 </div>
             ))}
             {repo.files.length === 0 && (
                 <div className="p-8 text-center text-fg-muted text-sm">
                     This repository is empty. Add a file to get started.
                 </div>
             )}
         </div>
      </div>

      {/* README Preview */}
      {readme && (
          <div className="border border-border-default rounded-md overflow-hidden bg-white">
              <div className="bg-canvas-subtle px-4 py-2 border-b border-border-default flex items-center gap-2 sticky top-0">
                  <Icons.Menu size={14} className="text-fg-muted" />
                  <span className="font-bold text-xs uppercase tracking-wider text-fg-default">README.md</span>
              </div>
              <div className="p-8 md:p-12">
                  <MarkdownPreview content={readme.content} />
              </div>
          </div>
      )}
    </div>
  );
};

export default RepositoryView;

import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { Repository } from '../types';
import { Icons } from '../components/Icon';
import MarkdownPreview from '../components/MarkdownPreview';

interface FileEditorProps {
  repos: Repository[];
  onUpdateFile: (repoId: string, fileId: string, newContent: string) => void;
  onDeleteFile: (repoId: string, fileId: string) => void;
}

const FileEditor: React.FC<FileEditorProps> = ({ repos, onUpdateFile, onDeleteFile }) => {
  const { repoId, fileId } = useParams<{ repoId: string; fileId: string }>();
  const navigate = useNavigate();

  const repo = repos.find(r => r.id === repoId);
  const file = repo?.files.find(f => f.id === fileId);

  const [isEditing, setIsEditing] = useState(false);
  const [content, setContent] = useState('');
  const [copyFeedback, setCopyFeedback] = useState(false);

  useEffect(() => {
    if (file) {
      setContent(file.content);
    }
  }, [file]);

  if (!repo || !file) {
    return <div className="p-10 text-center">File not found</div>;
  }

  const handleSave = () => {
    onUpdateFile(repoId!, fileId!, content);
    setIsEditing(false);
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(content);
    setCopyFeedback(true);
    setTimeout(() => setCopyFeedback(false), 2000);
  };

  const handleDelete = () => {
      if(window.confirm(`Are you sure you want to delete ${file.name}?`)) {
          onDeleteFile(repoId!, fileId!);
          navigate(`/${repoId}`);
      }
  }

  const lineCount = content.split('\n').length;
  const wordCount = content.split(/\s+/g).length;
  const sizeKB = (new Blob([content]).size / 1024).toFixed(2);

  return (
    <div className="container mx-auto max-w-7xl p-4 md:p-6 lg:p-8 bg-canvas-default min-h-screen">

      {/* Breadcrumbs */}
      <div className="flex items-center gap-2 text-lg text-fg-muted mb-6">
          <Icons.Book size={18} />
          <Link to="/" className="text-accent-fg hover:underline">username</Link>
          <span>/</span>
          <Link to={`/${repo.id}`} className="text-accent-fg hover:underline font-bold">{repo.name}</Link>
          <span>/</span>
          <span className="text-fg-default font-medium">{file.name}</span>
      </div>

      {/* File Header */}
      <div className="border border-border-default rounded-t-md bg-canvas-subtle p-3 flex flex-col sm:flex-row sm:items-center justify-between gap-3">
         <div className="flex items-center gap-3 text-xs text-fg-default font-mono">
            <span className="font-bold border border-border-default bg-white px-2 py-0.5 rounded-full">main</span>
            <span className="hidden sm:inline text-fg-muted">|</span>
            <span>{lineCount} lines</span>
            <span>{wordCount} words</span>
            <span>{sizeKB} KB</span>
         </div>

         <div className="flex items-center gap-2">
            <div className="flex bg-white rounded-md border border-border-default overflow-hidden">
                <button 
                    onClick={() => setIsEditing(false)}
                    className={`px-3 py-1.5 text-sm font-medium flex items-center gap-2 ${!isEditing ? 'bg-canvas-subtle text-fg-default' : 'text-fg-muted hover:bg-gray-50'}`}
                >
                    <Icons.Book size={14} /> Preview
                </button>
                <button 
                    onClick={() => setIsEditing(true)}
                    className={`px-3 py-1.5 text-sm font-medium flex items-center gap-2 ${isEditing ? 'bg-canvas-subtle text-fg-default' : 'text-fg-muted hover:bg-gray-50'}`}
                >
                    <Icons.Edit size={14} /> Code
                </button>
            </div>

            <div className="h-4 w-px bg-border-default mx-1"></div>

            <button 
                onClick={handleCopy} 
                className="p-1.5 text-fg-muted hover:bg-gray-200 rounded-md relative group"
                title="Copy raw contents"
            >
                {copyFeedback ? <Icons.Check size={16} className="text-success-emphasis" /> : <Icons.Copy size={16} />}
            </button>
            <button 
                onClick={handleDelete}
                className="p-1.5 text-fg-muted hover:text-red-600 hover:bg-gray-200 rounded-md"
                title="Delete file"
            >
                <Icons.Trash size={16} />
            </button>
         </div>
      </div>

      {/* Editor / Preview Area */}
      <div className="border-x border-b border-border-default rounded-b-md min-h-[500px] bg-white relative">
         {isEditing ? (
             <div className="flex flex-col h-full">
                 <div className="bg-slate-50 border-b border-border-default p-2 flex items-center gap-2 text-xs text-fg-muted">
                    <span className="ml-auto">Markdown supported</span>
                 </div>
                 <textarea
                    value={content}
                    onChange={(e) => setContent(e.target.value)}
                    className="w-full h-[500px] p-4 font-mono text-sm resize-y outline-none focus:bg-slate-50 transition-colors"
                    spellCheck={false}
                 />
                 <div className="bg-canvas-subtle p-4 border-t border-border-default flex justify-end gap-3 sticky bottom-0">
                    <button 
                        onClick={() => {
                            setContent(file.content);
                            setIsEditing(false);
                        }}
                        className="px-4 py-1.5 border border-border-default rounded-md text-sm font-medium bg-white hover:bg-gray-50"
                    >
                        Cancel
                    </button>
                    <button 
                        onClick={handleSave}
                        className="px-4 py-1.5 bg-success-emphasis text-white rounded-md text-sm font-medium hover:opacity-90 flex items-center gap-2"
                    >
                        <Icons.Save size={14} /> Commit changes
                    </button>
                 </div>
             </div>
         ) : (
             <div className="p-8 md:p-12">
                 <MarkdownPreview content={content} />
             </div>
         )}
      </div>
    </div>
  );
};

