import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route } from 'react-router-dom';
import Header from './components/Header';
import Dashboard from './pages/Dashboard';
import RepositoryView from './pages/RepositoryView';
import FileEditor from './pages/FileEditor';
import { loadRepositories, saveRepositories } from './services/storage';
import { Repository } from './types';
import { v4 as uuidv4 } from 'uuid'; // Actually we don't have uuid package, use simple random

const simpleId = () => Math.random().toString(36).substr(2, 9);

function App() {
  const [repos, setRepos] = useState<Repository[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const data = loadRepositories();
    setRepos(data);
    setLoading(false);
  }, []);

  useEffect(() => {
    if (!loading) {
      saveRepositories(repos);
    }
  }, [repos, loading]);

  const handleCreateRepo = (name: string, description: string, isPrivate: boolean) => {
    const newRepo: Repository = {
      id: `repo-${simpleId()}`,
      name,
      description,
      isPrivate,
      updatedAt: new Date().toISOString(),
      stars: 0,
      language: 'Markdown',
      files: [{
        id: `file-${simpleId()}`,
        name: 'README.md',
        content: `# ${name}\n\n${description}`,
        updatedAt: new Date().toISOString(),
        language: 'markdown',
        size: 0
      }]
    };
    setRepos([newRepo, ...repos]);
  };

  const handleAddFile = (repoId: string, filename: string) => {
    setRepos(prevRepos => prevRepos.map(repo => {
      if (repo.id === repoId) {
        return {
          ...repo,
          updatedAt: new Date().toISOString(),
          files: [...repo.files, {
            id: `file-${simpleId()}`,
            name: filename,
            content: `# ${filename.replace('.md', '')}\n\nNew file created.`,
            updatedAt: new Date().toISOString(),
            language: 'markdown',
            size: 0
          }]
        };
      }
      return repo;
    }));
  };

  const handleUpdateFile = (repoId: string, fileId: string, newContent: string) => {
    setRepos(prevRepos => prevRepos.map(repo => {
        if (repo.id === repoId) {
            return {
                ...repo,
                updatedAt: new Date().toISOString(),
                files: repo.files.map(file => {
                    if (file.id === fileId) {
                        return {
                            ...file,
                            content: newContent,
                            updatedAt: new Date().toISOString(),
                            size: new Blob([newContent]).size
                        };
                    }
                    return file;
                })
            }
        }
        return repo;
    }));
  };

  const handleDeleteFile = (repoId: string, fileId: string) => {
      setRepos(prevRepos => prevRepos.map(repo => {
          if (repo.id === repoId) {
              return {
                  ...repo,
                  updatedAt: new Date().toISOString(),
                  files: repo.files.filter(f => f.id !== fileId)
              };
          }
          return repo;
      }));
  }

  const handleDeleteRepo = (repoId: string) => {
      setRepos(prevRepos => prevRepos.filter(r => r.id !== repoId));
  }

  if (loading) {
      return <div className="h-screen flex items-center justify-center">Loading...</div>;
  }

  return (
    <Router>
      <div className="min-h-screen bg-canvas-default text-fg-default font-sans">
        <Header />
        <Routes>
          <Route 
            path="/" 
            element={
                <Dashboard 
                    repos={repos} 
                    onCreateRepo={handleCreateRepo} 
                />
            } 
          />
          <Route 
            path="/:repoId" 
            element={
                <RepositoryView 
                    repos={repos} 
                    onAddFile={handleAddFile}
                    onDeleteRepo={handleDeleteRepo}
                />
            } 
          />
          <Route 
            path="/:repoId/:fileId" 
            element={
                <FileEditor 
                    repos={repos} 
                    onUpdateFile={handleUpdateFile} 
                    onDeleteFile={handleDeleteFile}
                />
            } 
          />
        </Routes>
        <footer className="mt-12 py-8 border-t border-border-default text-center text-xs text-fg-muted">
            <div className="flex justify-center gap-4 mb-2">
                <span className="hover:text-accent-fg cursor-pointer">Terms</span>
                <span className="hover:text-accent-fg cursor-pointer">Privacy</span>
                <span className="hover:text-accent-fg cursor-pointer">Security</span>
                <span className="hover:text-accent-fg cursor-pointer">Status</span>
                <span className="hover:text-accent-fg cursor-pointer">Docs</span>
                <span className="hover:text-accent-fg cursor-pointer">Contact GitNotes</span>
            </div>
            <p>© 2024 GitNotes Personal Edition</p>
        </footer>
      </div>
    </Router>
  );
}

export default App;

