import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { Repository } from '../types';
import { Icons } from '../components/Icon';
import MarkdownPreview from '../components/MarkdownPreview';

interface FileEditorProps {
  repos: Repository[];
  onUpdateFile: (repoId: string, fileId: string, newContent: string) => void;
  onDeleteFile: (repoId: string, fileId: string) => void;
}

const FileEditor: React.FC<FileEditorProps> = ({ repos, onUpdateFile, onDeleteFile }) => {
  const { repoId, fileId } = useParams<{ repoId: string; fileId: string }>();
  const navigate = useNavigate();

  const repo = repos.find(r => r.id === repoId);
  const file = repo?.files.find(f => f.id === fileId);

  const [isEditing, setIsEditing] = useState(true);
  const [content, setContent] = useState('');
  const [hasChanges, setHasChanges] = useState(false);

  useEffect(() => {
    if (file) {
      setContent(file.content);
    }
  }, [file]);

  if (!repo || !file) {
    return <div className="h-screen flex items-center justify-center font-mono text-zenith-orange">ERROR: FILE DATA CORRUPTED OR MISSING</div>;
  }

  const handleSave = () => {
    onUpdateFile(repoId!, fileId!, content);
    setHasChanges(false);
  };

  const handleContentChange = (val: string) => {
      setContent(val);
      setHasChanges(val !== file.content);
  }

  const handleDelete = () => {
      if(window.confirm(`CONFIRM DELETION: ${file.name}?`)) {
          onDeleteFile(repoId!, fileId!);
          navigate(`/${repoId}`);
      }
  }

  return (
    <div className="h-[calc(100vh-56px)] flex flex-col bg-zenith-bg">

      {/* File Toolbar */}
      <div className="h-14 border-b border-zenith-border bg-zenith-bg flex items-center justify-between px-6 shrink-0">
          <div className="flex items-center gap-4">
              <Link to={`/${repoId}`} className="text-zenith-muted hover:text-white transition-colors">
                  <Icons.ChevronRight className="rotate-180" size={18} />
              </Link>
              <div className="h-6 w-px bg-zenith-border"></div>
              <span className="font-mono text-sm text-white font-bold tracking-wide">{file.name}</span>
              {hasChanges && <span className="text-[10px] bg-zenith-orange text-black px-2 py-0.5 font-bold font-mono">UNSAVED</span>}
          </div>

          <div className="flex items-center gap-3">
             {/* Mode Switcher */}
             <div className="flex border border-zenith-border p-0.5 bg-zenith-surface">
                 <button 
                    onClick={() => setIsEditing(true)}
                    className={`px-4 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all ${isEditing ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                 >
                    Write
                 </button>
                 <button 
                    onClick={() => setIsEditing(false)}
                    className={`px-4 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all ${!isEditing ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                 >
                    Render
                 </button>
             </div>

             <button 
                onClick={handleSave}
                disabled={!hasChanges}
                className={`flex items-center gap-2 px-4 py-2 border text-xs font-mono tracking-widest uppercase transition-colors ${hasChanges ? 'border-zenith-orange text-zenith-orange hover:bg-zenith-orange hover:text-black' : 'border-zenith-border text-zenith-muted cursor-not-allowed'}`}
             >
                <Icons.Save size={14} /> Save
             </button>

             <button onClick={handleDelete} className="p-2 text-zenith-muted hover:text-red-600 transition-colors">
                 <Icons.Trash size={16} />
             </button>
          </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-hidden relative flex">

         {/* Line Numbers (Decorative mostly) */}
         <div className="hidden md:block w-12 bg-zenith-surface border-r border-zenith-border text-right py-6 pr-3 font-mono text-xs text-zenith-border select-none">
             {Array.from({length: 20}).map((_, i) => <div key={i}>{i+1}</div>)}
         </div>

         <div className="flex-1 relative overflow-auto">
             {isEditing ? (
                 <textarea
                    value={content}
                    onChange={(e) => handleContentChange(e.target.value)}
                    className="w-full h-full bg-zenith-bg text-zenith-text font-mono text-sm p-6 resize-none outline-none focus:bg-[#050505] transition-colors leading-relaxed"
                    spellCheck={false}
                 />
             ) : (
                 <div className="p-8 max-w-4xl mx-auto">
                     <MarkdownPreview content={content} />
                 </div>
             )}
         </div>

      </div>

      {/* Footer Info */}
      <div className="h-8 border-t border-zenith-border bg-zenith-surface flex items-center justify-between px-4 font-mono text-[10px] text-zenith-muted uppercase tracking-widest">
         <div>Ln {content.split('\n').length}, Col {content.length}</div>
         <div>Markdown Environment</div>
      </div>
    </div>
  );
};

export default FileEditor;

import React, { useState, useEffect, useRef } from 'react';
import { Icons } from './Icon';

interface LoginModalProps {
  isOpen: boolean;
  onClose: () => void;
  onLogin: (password: string) => boolean;
}

const LoginModal: React.FC<LoginModalProps> = ({ isOpen, onClose, onLogin }) => {
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen && inputRef.current) {
      inputRef.current.focus();
    }
    if (!isOpen) {
      setPassword('');
      setError(false);
    }
  }, [isOpen]);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (onLogin(password)) {
      onClose();
    } else {
      setError(true);
      setPassword('');
    }
  };

  return (
    <div className="fixed inset-0 bg-black/90 backdrop-blur-sm flex items-center justify-center z-[100]">
      <div className="bg-zenith-bg border border-zenith-orange w-full max-w-sm p-0 shadow-[0_0_30px_rgba(255,77,0,0.1)] relative">
        {/* Decorative elements */}
        <div className="absolute top-0 left-0 w-2 h-2 bg-zenith-orange"></div>
        <div className="absolute top-0 right-0 w-2 h-2 bg-zenith-orange"></div>
        <div className="absolute bottom-0 left-0 w-2 h-2 bg-zenith-orange"></div>
        <div className="absolute bottom-0 right-0 w-2 h-2 bg-zenith-orange"></div>

        <div className="bg-zenith-surface border-b border-zenith-border p-4 flex justify-between items-center">
            <span className="font-mono text-xs tracking-widest text-zenith-orange uppercase flex items-center gap-2">
                <Icons.User size={12} />
                Security Clearance
            </span>
            <button onClick={onClose} className="text-zenith-muted hover:text-white transition-colors">
                <Icons.Close size={18}/>
            </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6">
          <div className="text-center space-y-2">
             <div className="font-mono text-zenith-text text-sm tracking-wide">AUTHENTICATION REQUIRED</div>
             <div className="text-[10px] text-zenith-muted font-mono uppercase tracking-widest">Enter Access Code</div>
          </div>

          <div className="space-y-2">
            <input 
              ref={inputRef}
              type="password"
              autoFocus
              value={password}
              onChange={e => {
                setPassword(e.target.value);
                setError(false);
              }}
              className={`w-full bg-black border ${error ? 'border-red-500 animate-pulse' : 'border-zenith-border'} p-3 text-white font-mono text-center text-lg focus:border-zenith-orange focus:outline-none transition-colors tracking-widest`}
              placeholder="••••••••"
            />
            {error && <div className="text-red-500 text-[10px] font-mono text-center tracking-widest pt-2">ACCESS DENIED // INVALID CODE</div>}
          </div>

          <button type="submit" className="w-full bg-zenith-orange text-black px-6 py-3 text-sm font-bold tracking-widest uppercase hover:bg-white transition-colors duration-75 flex items-center justify-center gap-2">
            <Icons.Check size={16} />
            Verify Identity
          </button>
        </form>
      </div>
    </div>
  );
};

export default LoginModal;

