            path="/:repoId/:fileId" 
            element={
                <FileEditor 
                    repos={repos} 
                    onUpdateFile={handleUpdateFile} 
                    onDeleteFile={handleDeleteFile}
                    isAuthenticated={isAuthenticated}
                />
            } 
          />
        </Routes>

        <footer className="mt-20 py-8 border-t border-zenith-border text-center">
            <div className="text-[10px] tracking-widest text-zenith-muted font-mono uppercase">
                <span className="mx-2">System Status: {isAuthenticated ? 'Admin' : 'Guest'}</span>
                <span className="mx-2">Encrypted: Local</span>
                <span className="mx-2">Ver: 2.5.0 (Optimized)</span>
            </div>
        </footer>

        <LoginModal 
            isOpen={isLoginModalOpen} 
            onClose={() => setIsLoginModalOpen(false)}
            onLogin={handleLogin}
        />
      </div>
    </Router>
  );
}

export default App;

import React, { useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { Repository } from '../types';
import { Icons } from '../components/Icon';
import MarkdownPreview from '../components/MarkdownPreview';
import DeleteConfirmModal from '../components/DeleteConfirmModal';
import RepoSettingsModal from '../components/RepoSettingsModal';

interface RepositoryViewProps {
  repos: Repository[];
  onAddFile: (repoId: string, filename: string) => void;
  onDeleteRepo: (repoId: string) => void;
  onUpdateRepo: (repoId: string, name: string, description: string) => void;
  isAuthenticated: boolean;
}

const RepositoryView: React.FC<RepositoryViewProps> = ({ repos, onAddFile, onDeleteRepo, onUpdateRepo, isAuthenticated }) => {
  const { repoId } = useParams<{ repoId: string }>();
  const navigate = useNavigate();
  const repo = repos.find(r => r.id === repoId);

  const [showAddFile, setShowAddFile] = useState(false);
  const [newFileName, setNewFileName] = useState('');

  // Modal states
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);

  if (!repo) {
    return <div className="h-screen flex items-center justify-center font-mono text-zenith-orange">ERROR: MODULE NOT FOUND</div>;
  }

  const handleAddFile = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newFileName.trim()) return;
    let name = newFileName.trim();
    if (!name.endsWith('.md')) name += '.md';

    onAddFile(repo.id, name);
    setShowAddFile(false);
    setNewFileName('');
  };

  const handleDeleteConfirm = () => {
    onDeleteRepo(repo.id);
    navigate('/');
  };

  // Find README for preview
  const readme = repo.files.find(f => f.name.toLowerCase() === 'readme.md');

  return (
    <div className="min-h-screen bg-zenith-bg p-6 md:p-12 max-w-[1600px] mx-auto">

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 mb-8 border-b border-zenith-border pb-6">
        <div>
            <div className="flex items-center gap-2 font-mono text-xs text-zenith-muted mb-2">
                <Link to="/" className="hover:text-zenith-orange">ROOT</Link>
                <span>/</span>
                <span className="text-white">{repo.id.toUpperCase()}</span>
            </div>
            <h1 className="text-4xl font-bold tracking-tight text-white mb-2">{repo.name}</h1>
            <p className="text-zenith-muted font-mono text-sm max-w-2xl">{repo.description}</p>
        </div>

        {isAuthenticated && (
          <div className="flex items-center gap-4">
              <button 
                  onClick={() => setIsSettingsModalOpen(true)}
                  className="bg-zenith-surface border border-zenith-border text-zenith-muted px-3 py-2 text-xs font-mono uppercase hover:text-white hover:border-white transition-colors duration-75 flex items-center gap-2"
                  title="Configure Module"
              >
                  <Icons.Settings size={14} />
              </button>
              <div className="w-px h-6 bg-zenith-border"></div>
              <button 
                  onClick={() => setShowAddFile(true)}
                  className="bg-zenith-surface border border-zenith-border text-white px-4 py-2 text-xs font-mono tracking-widest uppercase hover:bg-white hover:text-black transition-colors duration-75 flex items-center gap-2"
              >
                  <Icons.Plus size={14} /> Add File
              </button>
              <button 
                  onClick={() => setIsDeleteModalOpen(true)}
                  className="border border-zenith-border text-zenith-muted px-4 py-2 text-xs font-mono tracking-widest uppercase hover:border-zenith-orange hover:text-zenith-orange transition-colors duration-75"
              >
                  Delete
              </button>
          </div>
        )}
      </div>

      {/* Add File Input */}
      {showAddFile && isAuthenticated && (
        <div className="mb-8 p-6 border border-zenith-orange bg-zenith-surface/50">
           <form onSubmit={handleAddFile} className="flex gap-4 items-center">
               <span className="font-mono text-zenith-orange text-lg">/</span>
               <input 
                 autoFocus
                 type="text" 
                 placeholder="filename.md" 
                 className="bg-transparent border-b border-zenith-border text-white p-2 font-mono text-sm flex-1 outline-none focus:border-zenith-orange"
                 value={newFileName}
                 onChange={e => setNewFileName(e.target.value)}
               />
               <button type="submit" className="text-zenith-orange font-mono text-xs uppercase hover:underline">Create</button>
               <button type="button" onClick={() => setShowAddFile(false)} className="text-zenith-muted font-mono text-xs uppercase hover:text-white">Cancel</button>
           </form>
        </div>
      )}

      <div className="grid lg:grid-cols-3 gap-8">
          {/* File List Table */}
          <div className="lg:col-span-2">
             <div className="border border-zenith-border">
                <div className="bg-zenith-surface border-b border-zenith-border px-4 py-2 font-mono text-[10px] tracking-widest text-zenith-muted uppercase flex justify-between">
                    <span>File Index</span>
                    <span>Count: {repo.files.length}</span>
                </div>

                <div className="divide-y divide-zenith-border bg-black">
                    {repo.files.map(file => (
                        <div key={file.id} className="group flex items-center justify-between p-4 hover:bg-zenith-surface transition-colors duration-75">
                            <div className="flex items-center gap-4">
                                <Icons.File size={16} className="text-zenith-muted group-hover:text-zenith-orange" />
                                <Link to={`/${repo.id}/${file.id}`} className="font-mono text-sm text-zenith-text group-hover:text-white group-hover:underline decoration-zenith-orange underline-offset-4">
                                    {file.name}
                                </Link>
                            </div>
                            <div className="flex items-center gap-6">
                                <span className="font-mono text-[10px] text-zenith-muted hidden sm:block">
                                    {(file.size / 1024).toFixed(2)} KB
                                </span>
                                <span className="font-mono text-[10px] text-zenith-muted">
                                    {new Date(file.updatedAt).toLocaleDateString()}
                                </span>
                            </div>
                        </div>
                    ))}
                    {repo.files.length === 0 && (
                        <div className="p-8 text-center font-mono text-xs text-zenith-muted uppercase">
                            No files detected in sector
                        </div>
                    )}
                </div>
             </div>
          </div>

          {/* README Preview Panel */}
          <div className="lg:col-span-1">
             {readme ? (
                 <div className="border border-zenith-border sticky top-20">
                    <div className="bg-zenith-surface border-b border-zenith-border px-4 py-2 font-mono text-[10px] tracking-widest text-zenith-muted uppercase flex items-center gap-2">
                        <div className="w-2 h-2 bg-zenith-green rounded-full"></div>
                        <span>Preview: README.md</span>
                    </div>
                    <div className="p-6 bg-zenith-bg max-h-[calc(100vh-200px)] overflow-y-auto">
                        <MarkdownPreview content={readme.content} />
                    </div>
                 </div>
             ) : (
                 <div className="border border-zenith-border border-dashed p-8 text-center">
                     <span className="font-mono text-xs text-zenith-muted">NO README DETECTED</span>
                 </div>
             )}
          </div>
      </div>

      <DeleteConfirmModal 
        isOpen={isDeleteModalOpen}
        onClose={() => setIsDeleteModalOpen(false)}
        onConfirm={handleDeleteConfirm}
        title="Delete Module"
        itemName={repo.name}
        warningText="Deleting this repository will permanently erase all contained files and version history. This action cannot be reversed."
      />

      <RepoSettingsModal 
        isOpen={isSettingsModalOpen}
        onClose={() => setIsSettingsModalOpen(false)}
        onSave={(name, desc) => onUpdateRepo(repo.id, name, desc)}
        initialName={repo.name}
        initialDesc={repo.description}
      />
    </div>
  );
};

export default RepositoryView;

import React, { useState, useEffect } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { Repository } from '../types';
import { Icons } from '../components/Icon';
import MarkdownPreview from '../components/MarkdownPreview';
import DeleteConfirmModal from '../components/DeleteConfirmModal';

interface FileEditorProps {
  repos: Repository[];
  onUpdateFile: (repoId: string, fileId: string, newContent: string) => void;
  onDeleteFile: (repoId: string, fileId: string) => void;
  isAuthenticated: boolean;
}

const FileEditor: React.FC<FileEditorProps> = ({ repos, onUpdateFile, onDeleteFile, isAuthenticated }) => {
  const { repoId, fileId } = useParams<{ repoId: string; fileId: string }>();
  const navigate = useNavigate();

  const repo = repos.find(r => r.id === repoId);
  const file = repo?.files.find(f => f.id === fileId);

  // Default to rendering mode for visitors
  const [isEditing, setIsEditing] = useState(false);
  const [content, setContent] = useState('');
  const [hasChanges, setHasChanges] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);

  useEffect(() => {
    if (file) {
      setContent(file.content);
      // Auto-switch to edit mode only for authenticated users upon opening
      if (isAuthenticated) {
          setIsEditing(false); // keep false initially to encourage reading first
      }
    }
  }, [file, isAuthenticated]);

  if (!repo || !file) {
    return <div className="h-screen flex items-center justify-center font-mono text-zenith-orange">ERROR: FILE DATA CORRUPTED OR MISSING</div>;
  }

  const handleSave = () => {
    if (!isAuthenticated) return;
    onUpdateFile(repoId!, fileId!, content);
    setHasChanges(false);
  };

  const handleContentChange = (val: string) => {
      setContent(val);
      setHasChanges(val !== file.content);
  }

  const handleDeleteConfirm = () => {
      if (!isAuthenticated) return;
      onDeleteFile(repoId!, fileId!);
      navigate(`/${repoId}`);
  }

  const lineCount = content.split('\n').length;

  return (
    <div className="h-[calc(100vh-56px)] flex flex-col bg-zenith-bg">

      {/* File Toolbar */}
      <div className="h-14 border-b border-zenith-border bg-zenith-bg flex items-center justify-between px-6 shrink-0">
          <div className="flex items-center gap-4">
              <Link to={`/${repoId}`} className="text-zenith-muted hover:text-white transition-colors">
                  <Icons.ChevronRight className="rotate-180" size={18} />
              </Link>
              <div className="h-6 w-px bg-zenith-border"></div>
              <span className="font-mono text-sm text-white font-bold tracking-wide">{file.name}</span>
              {hasChanges && <span className="text-[10px] bg-zenith-orange text-black px-2 py-0.5 font-bold font-mono">UNSAVED</span>}
              {!isAuthenticated && <span className="text-[10px] border border-zenith-border text-zenith-muted px-2 py-0.5 font-mono uppercase">Read Only</span>}
          </div>

          <div className="flex items-center gap-3">
             {/* Mode Switcher */}
             <div className="flex border border-zenith-border p-0.5 bg-zenith-surface">
                 <button 
                    onClick={() => setIsEditing(true)}
                    className={`px-4 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all ${isEditing ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                 >
                    Write
                 </button>
                 <button 
                    onClick={() => setIsEditing(false)}
                    className={`px-4 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all ${!isEditing ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                 >
                    Render
                 </button>
             </div>

             {isAuthenticated && (
                <>
                 <button 
                    onClick={handleSave}
                    disabled={!hasChanges}
                    className={`flex items-center gap-2 px-4 py-2 border text-xs font-mono tracking-widest uppercase transition-colors ${hasChanges ? 'border-zenith-orange text-zenith-orange hover:bg-zenith-orange hover:text-black' : 'border-zenith-border text-zenith-muted cursor-not-allowed'}`}
                 >
                    <Icons.Save size={14} /> Save
                 </button>

                 <button onClick={() => setIsDeleteModalOpen(true)} className="p-2 text-zenith-muted hover:text-red-600 transition-colors">
                     <Icons.Trash size={16} />
                 </button>
                </>
             )}
          </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-hidden relative flex">

         {/* Line Numbers (Dynamic) */}
         <div className="hidden md:block w-12 bg-zenith-surface border-r border-zenith-border text-right py-6 pr-3 font-mono text-xs text-zenith-border select-none overflow-hidden">
             {Array.from({length: Math.max(lineCount, 20)}).map((_, i) => <div key={i}>{i+1}</div>)}
         </div>

         <div className="flex-1 relative overflow-auto">
             {isEditing ? (
                 <textarea
                    readOnly={!isAuthenticated}
                    value={content}
                    onChange={(e) => handleContentChange(e.target.value)}
                    className={`w-full h-full bg-zenith-bg text-zenith-text font-mono text-sm p-6 resize-none outline-none transition-colors leading-relaxed ${!isAuthenticated ? 'cursor-not-allowed text-zenith-muted' : 'focus:bg-[#050505]'}`}
                    spellCheck={false}
                    placeholder={!isAuthenticated ? "Editing is disabled in visitor mode." : "Start typing..."}
                 />
             ) : (
                 <div className="p-8 max-w-4xl mx-auto">
                     <MarkdownPreview content={content} />
                 </div>
             )}
         </div>

      </div>

      {/* Footer Info */}
      <div className="h-8 border-t border-zenith-border bg-zenith-surface flex items-center justify-between px-4 font-mono text-[10px] text-zenith-muted uppercase tracking-widest">
         <div>Ln {lineCount}, Col {content.length}</div>
         <div>{isAuthenticated ? 'Markdown Environment' : 'Visitor View'}</div>
      </div>

      <DeleteConfirmModal 
        isOpen={isDeleteModalOpen}
        onClose={() => setIsDeleteModalOpen(false)}
        onConfirm={handleDeleteConfirm}
        title="Delete File"
        itemName={file.name}
      />
    </div>
  );
};

export default FileEditor;

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route } from 'react-router-dom';
import { v4 as uuidv4 } from 'uuid';
import Header from './components/Header';
import Dashboard from './pages/Dashboard';
import RepositoryView from './pages/RepositoryView';
import FileEditor from './pages/FileEditor';
import LoginModal from './components/LoginModal';
import SocialBar from './components/SocialBar';
import { loadRepositories, saveRepositories } from './services/storage';
import { Repository } from './types';

const ADMIN_PASSWORD = 'wildsalt3980';

function App() {
  const [repos, setRepos] = useState<Repository[]>([]);
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoginModalOpen, setIsLoginModalOpen] = useState(false);

  useEffect(() => {
    const data = loadRepositories();
    setRepos(data);
    setLoading(false);
  }, []);

  useEffect(() => {
    if (!loading) {
      saveRepositories(repos);
    }
  }, [repos, loading]);

  const handleLogin = (password: string) => {
    if (password === ADMIN_PASSWORD) {
        setIsAuthenticated(true);
        return true;
    }
    return false;
  };

  const handleCreateRepo = (name: string, description: string, isPrivate: boolean) => {
    if (!isAuthenticated) return;
    const newRepo: Repository = {
      id: `repo-${uuidv4()}`,
      name,
      description,
      isPrivate,
      updatedAt: new Date().toISOString(),
      stars: 0,
      language: 'MARKDOWN',
      files: [{
        id: `file-${uuidv4()}`,
        name: 'README.md',
        content: `# ${name}\n\n${description}`,
        updatedAt: new Date().toISOString(),
        language: 'markdown',
        size: 0
      }]
    };
    setRepos([newRepo, ...repos]);
  };

  const handleUpdateRepo = (repoId: string, name: string, description: string) => {
    if (!isAuthenticated) return;
    setRepos(prevRepos => prevRepos.map(repo => {
        if (repo.id === repoId) {
            return {
                ...repo,
                name,
                description,
                updatedAt: new Date().toISOString()
            };
        }
        return repo;
    }));
  };

  const handleAddFile = (repoId: string, filename: string) => {
    if (!isAuthenticated) return;
    setRepos(prevRepos => prevRepos.map(repo => {
      if (repo.id === repoId) {
        return {
          ...repo,
          updatedAt: new Date().toISOString(),
          files: [...repo.files, {
            id: `file-${uuidv4()}`,
            name: filename,
            content: `# ${filename.replace('.md', '')}\n\nNew file created.`,
            updatedAt: new Date().toISOString(),
            language: 'markdown',
            size: 0
          }]
        };
      }
      return repo;
    }));
  };

  const handleUpdateFile = (repoId: string, fileId: string, newContent: string) => {
    if (!isAuthenticated) return;
    setRepos(prevRepos => prevRepos.map(repo => {
        if (repo.id === repoId) {
            return {
                ...repo,
                updatedAt: new Date().toISOString(),
                files: repo.files.map(file => {
                    if (file.id === fileId) {
                        return {
                            ...file,
                            content: newContent,
                            updatedAt: new Date().toISOString(),
                            size: new Blob([newContent]).size
                        };
                    }
                    return file;
                })
            }
        }
        return repo;
    }));
  };

  const handleDeleteFile = (repoId: string, fileId: string) => {
      if (!isAuthenticated) return;
      setRepos(prevRepos => prevRepos.map(repo => {
          if (repo.id === repoId) {
              return {
                  ...repo,
                  updatedAt: new Date().toISOString(),
                  files: repo.files.filter(f => f.id !== fileId)
              };
          }
          return repo;
      }));
  }

  const handleDeleteRepo = (repoId: string) => {
      if (!isAuthenticated) return;
      setRepos(prevRepos => prevRepos.filter(r => r.id !== repoId));
  }

  if (loading) {
      return <div className="h-screen bg-zenith-bg text-zenith-text flex items-center justify-center font-mono tracking-widest text-xs">INITIALIZING SYSTEM...</div>;
  }

  return (
    <Router>
      <div className="min-h-screen bg-zenith-bg text-zenith-text font-sans selection:bg-zenith-orange selection:text-black">
        <Header 
            isAuthenticated={isAuthenticated} 
            onLoginClick={() => setIsLoginModalOpen(true)}
            onLogoutClick={() => setIsAuthenticated(false)}
        />

        <Routes>
          <Route 
            path="/" 
            element={
                <Dashboard 
                    repos={repos} 
                    onCreateRepo={handleCreateRepo} 
                    isAuthenticated={isAuthenticated}
                />
            } 
          />
          <Route 
            path="/:repoId" 
            element={
                <RepositoryView 
                    repos={repos} 
                    onAddFile={handleAddFile}
                    onDeleteRepo={handleDeleteRepo}
                    onUpdateRepo={handleUpdateRepo}
                    isAuthenticated={isAuthenticated}
                />
            } 
          />
          <Route 
            path="/:repoId/:fileId" 
            element={
                <FileEditor 
                    repos={repos} 
                    onUpdateFile={handleUpdateFile} 
                    onDeleteFile={handleDeleteFile}
                    isAuthenticated={isAuthenticated}
                />
            } 
          />
        </Routes>

        <footer className="mt-20 py-12 border-t border-zenith-border flex flex-col items-center gap-8 bg-zenith-bg/50">
            <SocialBar />

            <div className="text-[10px] tracking-widest text-zenith-muted font-mono uppercase flex items-center gap-4 opacity-60 hover:opacity-100 transition-opacity">
                <span className="">System Status: <span className={isAuthenticated ? "text-zenith-orange" : "text-white"}>{isAuthenticated ? 'Admin' : 'Guest'}</span></span>
                <span className="w-px h-3 bg-zenith-muted"></span>
                <span className="">Encrypted: Local</span>
                <span className="w-px h-3 bg-zenith-muted"></span>
                <span className="">Ver: 2.5.0 (Optimized)</span>
            </div>
        </footer>

        <LoginModal 
            isOpen={isLoginModalOpen} 
            onClose={() => setIsLoginModalOpen(false)}
            onLogin={handleLogin}
        />
      </div>
    </Router>
  );
}

export default App;

