import React, { useState, useEffect, useRef } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { Repository } from '../types';
import { Icons } from '../components/Icon';
import MarkdownPreview from '../components/MarkdownPreview';
import DeleteConfirmModal from '../components/DeleteConfirmModal';
import EditorToolbar from '../components/EditorToolbar';

interface FileEditorProps {
  repos: Repository[];
  onUpdateFile: (repoId: string, fileId: string, newContent: string) => void;
  onDeleteFile: (repoId: string, fileId: string) => void;
  isAuthenticated: boolean;
}

type ViewMode = 'write' | 'preview' | 'split';

const FileEditor: React.FC<FileEditorProps> = ({ repos, onUpdateFile, onDeleteFile, isAuthenticated }) => {
  const { repoId, fileId } = useParams<{ repoId: string; fileId: string }>();
  const navigate = useNavigate();
  const textAreaRef = useRef<HTMLTextAreaElement>(null);

  const repo = repos.find(r => r.id === repoId);
  const file = repo?.files.find(f => f.id === fileId);

  const [viewMode, setViewMode] = useState<ViewMode>('preview');
  const [content, setContent] = useState('');
  const [hasChanges, setHasChanges] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);

  useEffect(() => {
    if (file) {
      setContent(file.content);
      // Auto-switch to preview mode for visitors, write for admin if desired, 
      // but 'preview' is a safe default for reading.
    }
  }, [file]);

  if (!repo || !file) {
    return <div className="h-screen flex items-center justify-center font-mono text-zenith-orange">ERROR: FILE DATA CORRUPTED OR MISSING</div>;
  }

  const handleSave = () => {
    if (!isAuthenticated) return;
    onUpdateFile(repoId!, fileId!, content);
    setHasChanges(false);
  };

  const handleContentChange = (val: string) => {
      setContent(val);
      setHasChanges(val !== file.content);
  }

  const handleDeleteConfirm = () => {
      if (!isAuthenticated) return;
      onDeleteFile(repoId!, fileId!);
      navigate(`/${repoId}`);
  }

  const handleInsert = (prefix: string, suffix: string = '') => {
    if (!textAreaRef.current) return;
    const start = textAreaRef.current.selectionStart;
    const end = textAreaRef.current.selectionEnd;
    const text = textAreaRef.current.value;
    const before = text.substring(0, start);
    const selection = text.substring(start, end);
    const after = text.substring(end);

    const newText = before + prefix + selection + suffix + after;
    handleContentChange(newText);

    // Defer focus to allow React render
    setTimeout(() => {
      if(textAreaRef.current) {
        textAreaRef.current.focus();
        textAreaRef.current.selectionStart = start + prefix.length;
        textAreaRef.current.selectionEnd = end + prefix.length;
      }
    }, 0);
  };

  const lineCount = content.split('\n').length;

  return (
    <div className="h-[calc(100vh-56px)] flex flex-col bg-zenith-bg">

      {/* File Toolbar */}
      <div className="h-14 border-b border-zenith-border bg-zenith-bg flex items-center justify-between px-6 shrink-0">
          <div className="flex items-center gap-4">
              <Link to={`/${repoId}`} className="text-zenith-muted hover:text-white transition-colors">
                  <Icons.ChevronRight className="rotate-180" size={18} />
              </Link>
              <div className="h-6 w-px bg-zenith-border"></div>
              <span className="font-mono text-sm text-white font-bold tracking-wide">{file.name}</span>
              {hasChanges && <span className="text-[10px] bg-zenith-orange text-black px-2 py-0.5 font-bold font-mono">UNSAVED</span>}
              {!isAuthenticated && <span className="text-[10px] border border-zenith-border text-zenith-muted px-2 py-0.5 font-mono uppercase">Read Only</span>}
          </div>

          <div className="flex items-center gap-3">
             {/* Mode Switcher */}
             <div className="flex border border-zenith-border p-0.5 bg-zenith-surface">
                 <button 
                    onClick={() => setViewMode('write')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'write' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Write Mode"
                 >
                    <Icons.Edit size={12} /> <span className="hidden sm:inline">Write</span>
                 </button>
                 <button 
                    onClick={() => setViewMode('split')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 border-l border-r border-zenith-border ${viewMode === 'split' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Split View"
                 >
                    <Icons.Layout size={12} /> <span className="hidden sm:inline">Split</span>
                 </button>
                 <button 
                    onClick={() => setViewMode('preview')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'preview' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Preview Mode"
                 >
                    <Icons.File size={12} /> <span className="hidden sm:inline">Render</span>
                 </button>
             </div>

             {isAuthenticated && (
                <>
                 <button 
                    onClick={handleSave}
                    disabled={!hasChanges}
                    className={`flex items-center gap-2 px-4 py-2 border text-xs font-mono tracking-widest uppercase transition-colors ${hasChanges ? 'border-zenith-orange text-zenith-orange hover:bg-zenith-orange hover:text-black' : 'border-zenith-border text-zenith-muted cursor-not-allowed'}`}
                 >
                    <Icons.Save size={14} /> Save
                 </button>

                 <button onClick={() => setIsDeleteModalOpen(true)} className="p-2 text-zenith-muted hover:text-red-600 transition-colors">
                     <Icons.Trash size={16} />
                 </button>
                </>
             )}
          </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-hidden relative flex">

         {/* Write Panel */}
         {(viewMode === 'write' || viewMode === 'split') && (
           <div className={`flex flex-col border-r border-zenith-border ${viewMode === 'split' ? 'w-1/2' : 'w-full'}`}>
             {isAuthenticated && <EditorToolbar onInsert={handleInsert} />}
             <div className="flex flex-1 overflow-hidden">
                {/* Line Numbers */}
                <div className="hidden sm:block w-10 bg-zenith-surface border-r border-zenith-border text-right py-4 pr-2 font-mono text-xs text-zenith-border select-none overflow-hidden shrink-0">
                    {Array.from({length: Math.max(lineCount, 20)}).map((_, i) => <div key={i}>{i+1}</div>)}
                </div>

                <textarea
                    ref={textAreaRef}
                    readOnly={!isAuthenticated}
                    value={content}
                    onChange={(e) => handleContentChange(e.target.value)}
                    className={`w-full h-full bg-zenith-bg text-zenith-text font-mono text-sm p-4 resize-none outline-none transition-colors leading-relaxed ${!isAuthenticated ? 'cursor-not-allowed text-zenith-muted' : 'focus:bg-[#050505]'}`}
                    spellCheck={false}
                    placeholder={!isAuthenticated ? "Editing is disabled in visitor mode." : "Start typing..."}
                />
             </div>
           </div>
         )}

         {/* Preview Panel */}
         {(viewMode === 'preview' || viewMode === 'split') && (
           <div className={`flex-1 overflow-auto bg-zenith-bg ${viewMode === 'split' ? 'bg-[#080808]' : ''}`}>
               <div className={`p-8 mx-auto ${viewMode === 'split' ? 'max-w-none' : 'max-w-4xl'}`}>
                   <MarkdownPreview content={content} />
               </div>
           </div>
         )}

      </div>

      {/* Footer Info */}
      <div className="h-8 border-t border-zenith-border bg-zenith-surface flex items-center justify-between px-4 font-mono text-[10px] text-zenith-muted uppercase tracking-widest">
         <div>Ln {lineCount}, Col {content.length}</div>
         <div>{isAuthenticated ? 'Markdown Environment' : 'Visitor View'}</div>
      </div>

      <DeleteConfirmModal 
        isOpen={isDeleteModalOpen}
        onClose={() => setIsDeleteModalOpen(false)}
        onConfirm={handleDeleteConfirm}
        title="Delete File"
        itemName={file.name}
      />
    </div>
  );
};

export default FileEditor;

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { Repository } from '../types';
import { Icons } from './Icon';

interface GlobalSearchProps {
  isOpen: boolean;
  onClose: () => void;
  repos: Repository[];
}

interface SearchResult {
  type: 'repo' | 'file';
  id: string;
  name: string;
  repoId: string; // needed for file navigation
  pathStr: string;
  matchType: 'title' | 'content';
}

const GlobalSearch: React.FC<GlobalSearchProps> = ({ isOpen, onClose, repos }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<SearchResult[]>([]);
  const [selectedIndex, setSelectedIndex] = useState(0);
  const inputRef = useRef<HTMLInputElement>(null);
  const navigate = useNavigate();

  useEffect(() => {
    if (isOpen && inputRef.current) {
      inputRef.current.focus();
    }
    if (!isOpen) {
      setQuery('');
      setResults([]);
    }
  }, [isOpen]);

  useEffect(() => {
    if (!query.trim()) {
      setResults([]);
      return;
    }

    const lowerQuery = query.toLowerCase();
    const hits: SearchResult[] = [];

    // Search Repos
    repos.forEach(repo => {
      if (repo.name.toLowerCase().includes(lowerQuery)) {
        hits.push({
          type: 'repo',
          id: repo.id,
          name: repo.name,
          repoId: repo.id,
          pathStr: repo.name,
          matchType: 'title'
        });
      }

      // Search Files
      repo.files.forEach(file => {
        if (file.name.toLowerCase().includes(lowerQuery)) {
          hits.push({
            type: 'file',
            id: file.id,
            name: file.name,
            repoId: repo.id,
            pathStr: `${repo.name} / ${file.name}`,
            matchType: 'title'
          });
        } else if (file.content.toLowerCase().includes(lowerQuery)) {
             hits.push({
            type: 'file',
            id: file.id,
            name: file.name,
            repoId: repo.id,
            pathStr: `${repo.name} / ${file.name}`,
            matchType: 'content'
          });
        }
      });
    });

    setResults(hits.slice(0, 10)); // Limit to 10
    setSelectedIndex(0);
  }, [query, repos]);

  const handleSelect = (result: SearchResult) => {
    if (result.type === 'repo') {
      navigate(`/${result.id}`);
    } else {
      navigate(`/${result.repoId}/${result.id}`);
    }
    onClose();
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex(prev => (prev + 1) % results.length);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex(prev => (prev - 1 + results.length) % results.length);
    } else if (e.key === 'Enter') {
      e.preventDefault();
      if (results[selectedIndex]) {
        handleSelect(results[selectedIndex]);
      }
    } else if (e.key === 'Escape') {
      onClose();
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex items-start justify-center pt-[20vh] z-[150]" onClick={onClose}>
      <div 
        className="bg-zenith-bg border border-zenith-border w-full max-w-xl shadow-2xl overflow-hidden flex flex-col max-h-[60vh]"
        onClick={e => e.stopPropagation()}
      >
        <div className="flex items-center px-4 py-3 border-b border-zenith-border gap-3">
          <Icons.Search className="text-zenith-orange" size={20} />
          <input
            ref={inputRef}
            type="text"
            className="flex-1 bg-transparent text-white font-mono text-sm outline-none placeholder:text-zenith-muted"
            placeholder="Search modules and files..."
            value={query}
            onChange={e => setQuery(e.target.value)}
            onKeyDown={handleKeyDown}
          />
          <div className="px-1.5 py-0.5 border border-zenith-border rounded text-[10px] text-zenith-muted font-mono">ESC</div>
        </div>

        <div className="overflow-y-auto">
          {results.length > 0 ? (
            <div className="py-2">
              {results.map((result, idx) => (
                <div
                  key={`${result.id}-${idx}`}
                  onClick={() => handleSelect(result)}
                  className={`px-4 py-3 flex items-center justify-between cursor-pointer font-mono text-sm group ${idx === selectedIndex ? 'bg-zenith-surface border-l-2 border-zenith-orange' : 'border-l-2 border-transparent'}`}
                >
                  <div className="flex items-center gap-3">
                    {result.type === 'repo' ? <Icons.GitBranch size={14} className="text-zenith-muted" /> : <Icons.File size={14} className="text-zenith-muted" />}
                    <div>
                      <div className={`text-white ${idx === selectedIndex ? 'text-zenith-orange' : ''}`}>{result.name}</div>
                      <div className="text-[10px] text-zenith-muted">{result.pathStr}</div>
                    </div>
                  </div>
                  {result.matchType === 'content' && <span className="text-[10px] text-zenith-muted uppercase border border-zenith-border px-1">Content</span>}
                </div>
              ))}
            </div>
          ) : query ? (
            <div className="p-8 text-center text-zenith-muted font-mono text-xs uppercase">No Results Found</div>
          ) : (
            <div className="p-8 text-center text-zenith-muted font-mono text-xs uppercase">Type to search knowledge base...</div>
          )}
        </div>

        {results.length > 0 && (
            <div className="bg-zenith-surface border-t border-zenith-border px-4 py-2 flex justify-between text-[10px] font-mono text-zenith-muted uppercase">
                <span>Navigate: Arrows</span>
                <span>Select: Enter</span>
            </div>
        )}
      </div>
    </div>
  );
};

export default GlobalSearch;

import React, { useState, useRef } from 'react';
import { Icons } from './Icon';
import { Repository } from '../types';

interface SystemSettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  repos: Repository[];
  onImport: (repos: Repository[]) => void;
}

const SystemSettingsModal: React.FC<SystemSettingsModalProps> = ({ isOpen, onClose, repos, onImport }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [importError, setImportError] = useState('');

  if (!isOpen) return null;

  // Calculate Storage Size
  const jsonString = JSON.stringify(repos);
  const bytes = new Blob([jsonString]).size;
  const megaBytes = (bytes / (1024 * 1024)).toFixed(2);
  const percent = Math.min((bytes / (5 * 1024 * 1024)) * 100, 100).toFixed(1);

  const handleExport = () => {
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `gitnotes_backup_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const result = event.target?.result as string;
        const parsed = JSON.parse(result);
        if (Array.isArray(parsed)) {
            // Basic validation
            onImport(parsed);
            onClose();
        } else {
            setImportError('Invalid JSON structure.');
        }
      } catch (err) {
        setImportError('Failed to parse JSON file.');
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="fixed inset-0 bg-black/90 backdrop-blur-sm flex items-center justify-center z-[120]">
      <div className="bg-zenith-bg border border-zenith-border w-full max-w-lg p-0 shadow-2xl relative">
        <div className="bg-zenith-surface border-b border-zenith-border p-4 flex justify-between items-center">
            <span className="font-mono text-xs tracking-widest text-zenith-orange uppercase flex items-center gap-2">
                <Icons.Database size={14} />
                System Maintenance
            </span>
            <button onClick={onClose} className="text-zenith-muted hover:text-white transition-colors">
                <Icons.Close size={18}/>
            </button>
        </div>

        <div className="p-8 space-y-8">

            {/* Storage Status */}
            <div>
                <h4 className="text-white font-bold font-mono text-sm uppercase mb-4 flex items-center gap-2">
                    <Icons.LayoutTemplate size={14} /> Storage Status
                </h4>
                <div className="bg-zenith-surface border border-zenith-border p-4">
                    <div className="flex justify-between text-xs font-mono text-zenith-muted mb-2">
                        <span>Local Storage Usage</span>
                        <span>{megaBytes} MB / 5.00 MB</span>
                    </div>
                    <div className="w-full h-2 bg-black border border-zenith-border">
                        <div 
                            className={`h-full ${Number(percent) > 80 ? 'bg-red-500' : 'bg-zenith-green'}`} 
                            style={{ width: `${percent}%` }}
                        ></div>
                    </div>
                </div>
            </div>

            {/* Backup & Restore */}
            <div>
                <h4 className="text-white font-bold font-mono text-sm uppercase mb-4 flex items-center gap-2">
                    <Icons.Save size={14} /> Data Management
                </h4>
                <div className="grid grid-cols-2 gap-4">
                    <button 
                        onClick={handleExport}
                        className="flex flex-col items-center justify-center gap-2 p-6 border border-zenith-border hover:border-zenith-orange hover:bg-zenith-surface transition-all group"
                    >
                        <Icons.Download size={24} className="text-zenith-muted group-hover:text-zenith-orange" />
                        <span className="font-mono text-xs uppercase tracking-widest text-zenith-text">Export Backup</span>
                    </button>

                    <button 
                         onClick={handleImportClick}
                        className="flex flex-col items-center justify-center gap-2 p-6 border border-zenith-border hover:border-white hover:bg-zenith-surface transition-all group"
                    >
                        <Icons.Upload size={24} className="text-zenith-muted group-hover:text-white" />
                        <span className="font-mono text-xs uppercase tracking-widest text-zenith-text">Restore Data</span>
                    </button>
                    <input 
                        type="file" 
                        ref={fileInputRef} 
                        className="hidden" 
                        accept=".json"
                        onChange={handleFileChange}
                    />
                </div>
                {importError && (
                    <div className="mt-4 p-2 border border-red-500/50 bg-red-500/10 text-red-500 text-xs font-mono text-center">
                        ERROR: {importError}
                    </div>
                )}
            </div>

            <div className="text-[10px] text-zenith-muted font-mono leading-relaxed border-t border-zenith-border pt-4">
                NOTE: Data is stored exclusively in your browser (LocalStorage). Exporting backups regularly is recommended to prevent data loss.
            </div>
        </div>
      </div>
    </div>
  );
};

