import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route } from 'react-router-dom';
import { v4 as uuidv4 } from 'uuid';
import Header from './components/Header';
import Dashboard from './pages/Dashboard';
import RepositoryView from './pages/RepositoryView';
import FileEditor from './pages/FileEditor';
import LoginModal from './components/LoginModal';
import SocialBar from './components/SocialBar';
import GlobalSearch from './components/GlobalSearch';
import SystemSettingsModal from './components/SystemSettingsModal';
import { loadRepositories, saveRepositories } from './services/storage';
import { Repository } from './types';
import { Icons } from './components/Icon';

const ADMIN_PASSWORD = 'wildsalt3980';

function App() {
  const [repos, setRepos] = useState<Repository[]>([]);
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoginModalOpen, setIsLoginModalOpen] = useState(false);

  // New Modals
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  useEffect(() => {
    const data = loadRepositories();
    setRepos(data);
    setLoading(false);
  }, []);

  useEffect(() => {
    if (!loading) {
      saveRepositories(repos);
    }
  }, [repos, loading]);

  // Global Key Listener for Search
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        setIsSearchOpen(true);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const handleLogin = (password: string) => {
    if (password === ADMIN_PASSWORD) {
        setIsAuthenticated(true);
        return true;
    }
    return false;
  };

  const handleCreateRepo = (name: string, description: string, isPrivate: boolean) => {
    if (!isAuthenticated) return;
    const newRepo: Repository = {
      id: `repo-${uuidv4()}`,
      name,
      description,
      isPrivate,
      updatedAt: new Date().toISOString(),
      stars: 0,
      language: 'MARKDOWN',
      files: [{
        id: `file-${uuidv4()}`,
        name: 'README.md',
        content: `# ${name}\n\n${description}`,
        updatedAt: new Date().toISOString(),
        language: 'markdown',
        size: 0
      }]
    };
    setRepos([newRepo, ...repos]);
  };

  const handleUpdateRepo = (repoId: string, name: string, description: string) => {
    if (!isAuthenticated) return;
    setRepos(prevRepos => prevRepos.map(repo => {
        if (repo.id === repoId) {
            return {
                ...repo,
                name,
                description,
                updatedAt: new Date().toISOString()
            };
        }
        return repo;
    }));
  };

  const handleAddFile = (repoId: string, filename: string) => {
    if (!isAuthenticated) return;
    setRepos(prevRepos => prevRepos.map(repo => {
      if (repo.id === repoId) {
        return {
          ...repo,
          updatedAt: new Date().toISOString(),
          files: [...repo.files, {
            id: `file-${uuidv4()}`,
            name: filename,
            content: `# ${filename.replace('.md', '')}\n\nNew file created.`,
            updatedAt: new Date().toISOString(),
            language: 'markdown',
            size: 0
          }]
        };
      }
      return repo;
    }));
  };

  const handleUpdateFile = (repoId: string, fileId: string, newContent: string) => {
    if (!isAuthenticated) return;
    setRepos(prevRepos => prevRepos.map(repo => {
        if (repo.id === repoId) {
            return {
                ...repo,
                updatedAt: new Date().toISOString(),
                files: repo.files.map(file => {
                    if (file.id === fileId) {
                        return {
                            ...file,
                            content: newContent,
                            updatedAt: new Date().toISOString(),
                            size: new Blob([newContent]).size
                        };
                    }
                    return file;
                })
            }
        }
        return repo;
    }));
  };

  const handleDeleteFile = (repoId: string, fileId: string) => {
      if (!isAuthenticated) return;
      setRepos(prevRepos => prevRepos.map(repo => {
          if (repo.id === repoId) {
              return {
                  ...repo,
                  updatedAt: new Date().toISOString(),
                  files: repo.files.filter(f => f.id !== fileId)
              };
          }
          return repo;
      }));
  }

  const handleDeleteRepo = (repoId: string) => {
      if (!isAuthenticated) return;
      setRepos(prevRepos => prevRepos.filter(r => r.id !== repoId));
  }

  const handleImportData = (newRepos: Repository[]) => {
      setRepos(newRepos);
  }

  if (loading) {
      return <div className="h-screen bg-zenith-bg text-zenith-text flex items-center justify-center font-mono tracking-widest text-xs">INITIALIZING SYSTEM...</div>;
  }

  return (
    <Router>
      <div className="min-h-screen bg-zenith-bg text-zenith-text font-sans selection:bg-zenith-orange selection:text-black">
        <Header 
            isAuthenticated={isAuthenticated} 
            onLoginClick={() => setIsLoginModalOpen(true)}
            onLogoutClick={() => setIsAuthenticated(false)}
        />

        <Routes>
          <Route 
            path="/" 
            element={
                <Dashboard 
                    repos={repos} 
                    onCreateRepo={handleCreateRepo} 
                    isAuthenticated={isAuthenticated}
                />
            } 
          />
          <Route 
            path="/:repoId" 
            element={
                <RepositoryView 
                    repos={repos} 
                    onAddFile={handleAddFile}
                    onDeleteRepo={handleDeleteRepo}
                    onUpdateRepo={handleUpdateRepo}
                    isAuthenticated={isAuthenticated}
                />
            } 
          />
          <Route 
            path="/:repoId/:fileId" 
            element={
                <FileEditor 
                    repos={repos} 
                    onUpdateFile={handleUpdateFile} 
                    onDeleteFile={handleDeleteFile}
                    isAuthenticated={isAuthenticated}
                />
            } 
          />
        </Routes>

        <footer className="mt-20 py-12 border-t border-zenith-border flex flex-col items-center gap-8 bg-zenith-bg/50">
            <SocialBar />

            <div className="text-[10px] tracking-widest text-zenith-muted font-mono uppercase flex items-center gap-4 opacity-60 hover:opacity-100 transition-opacity">
                <span className="">System Status: <span className={isAuthenticated ? "text-zenith-orange" : "text-white"}>{isAuthenticated ? 'Admin' : 'Guest'}</span></span>
                <span className="w-px h-3 bg-zenith-muted"></span>
                <button onClick={() => setIsSearchOpen(true)} className="hover:text-white flex items-center gap-1"><Icons.Command size={10}/> CMD+K</button>
                {isAuthenticated && (
                   <>
                     <span className="w-px h-3 bg-zenith-muted"></span>
                     <button onClick={() => setIsSettingsOpen(true)} className="hover:text-white flex items-center gap-1"><Icons.Database size={10}/> MAINTENANCE</button>
                   </>
                )}
                <span className="w-px h-3 bg-zenith-muted"></span>
                <span className="">Ver: 2.6.0</span>
            </div>
        </footer>

        <LoginModal 
            isOpen={isLoginModalOpen} 
            onClose={() => setIsLoginModalOpen(false)}
            onLogin={handleLogin}
        />

        <GlobalSearch 
            isOpen={isSearchOpen}
            onClose={() => setIsSearchOpen(false)}
            repos={repos}
        />

        <SystemSettingsModal 
            isOpen={isSettingsOpen}
            onClose={() => setIsSettingsOpen(false)}
            repos={repos}
            onImport={handleImportData}
        />
      </div>
    </Router>
  );
}

export default App;

import { createClient } from '@supabase/supabase-js';

const supabaseUrl = import.meta.env.VITE_SUPABASE_URL;
const supabaseAnonKey = import.meta.env.VITE_SUPABASE_ANON_KEY;

if (!supabaseUrl || !supabaseAnonKey) {
  console.error('Missing Supabase Environment Variables');
}

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

import { supabase } from '../lib/supabase';
import { Repository, FileItem } from '../types';

// Helper to map DB snake_case to App camelCase
const mapRepo = (r: any): Repository => ({
  id: r.id,
  name: r.name,
  description: r.description,
  isPrivate: r.is_private,
  updatedAt: r.updated_at,
  stars: r.stars,
  language: r.language,
  files: r.files ? r.files.map(mapFile) : []
});

const mapFile = (f: any): FileItem => ({
  id: f.id,
  name: f.name,
  content: f.content,
  language: f.language,
  size: f.size,
  updatedAt: f.updated_at
});

export const api = {
  // Fetch all data for a specific owner (Secret Key)
  getRepos: async (ownerId: string): Promise<Repository[]> => {
    const { data, error } = await supabase
      .from('repositories')
      .select('*, files(*)')
      .eq('owner_id', ownerId)
      .order('updated_at', { ascending: false });

    if (error) {
      console.error('Error fetching repos:', error);
      throw error;
    }

    // Sort files within repos by update time
    const repos = data.map(mapRepo);
    repos.forEach(r => {
        r.files.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime());
    });

    return repos;
  },

  createRepo: async (ownerId: string, name: string, description: string, isPrivate: boolean): Promise<Repository | null> => {
    const { data, error } = await supabase
      .from('repositories')
      .insert([{ owner_id: ownerId, name, description, is_private: isPrivate }])
      .select()
      .single();

    if (error) throw error;
    return { ...mapRepo(data), files: [] };
  },

  updateRepo: async (repoId: string, name: string, description: string) => {
    const { error } = await supabase
      .from('repositories')
      .update({ name, description, updated_at: new Date().toISOString() })
      .eq('id', repoId);
    if (error) throw error;
  },

  deleteRepo: async (repoId: string) => {
    const { error } = await supabase.from('repositories').delete().eq('id', repoId);
    if (error) throw error;
  },

  addFile: async (ownerId: string, repoId: string, name: string, content: string): Promise<FileItem | null> => {
    const size = new Blob([content]).size;
    const { data, error } = await supabase
      .from('files')
      .insert([{ 
        repo_id: repoId, 
        owner_id: ownerId,
        name, 
        content, 
        size 
      }])
      .select()
      .single();

    if (error) throw error;

    // Also touch the repo updated_at
    await supabase.from('repositories').update({ updated_at: new Date().toISOString() }).eq('id', repoId);

    return mapFile(data);
  },

  updateFile: async (fileId: string, content: string) => {
    const size = new Blob([content]).size;
    const { error } = await supabase
      .from('files')
      .update({ content, size, updated_at: new Date().toISOString() })
      .eq('id', fileId);
    if (error) throw error;
  },

  deleteFile: async (fileId: string) => {
    const { error } = await supabase.from('files').delete().eq('id', fileId);
    if (error) throw error;
  }
};

import React, { useState } from 'react';
import { Icons } from './Icon';
import { Repository } from '../types';

interface QuickCaptureProps {
  repos: Repository[];
  onQuickSave: (repoId: string, title: string, content: string) => Promise<void>;
  onCreateRepo: (name: string) => Promise<string | null>;
}

const QuickCapture: React.FC<QuickCaptureProps> = ({ repos, onQuickSave, onCreateRepo }) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [content, setContent] = useState('');
  const [title, setTitle] = useState('');
  const [selectedRepoId, setSelectedRepoId] = useState('');
  const [isCreatingRepo, setIsCreatingRepo] = useState(false);
  const [newRepoName, setNewRepoName] = useState('');
  const [isSaving, setIsSaving] = useState(false);

  const handleSave = async () => {
    if (!content.trim()) return;
    setIsSaving(true);

    try {
      let targetRepoId = selectedRepoId;

      // Logic: If no repo selected, default to the first one, or create a 'General' one
      if (!targetRepoId && !isCreatingRepo) {
        if (repos.length > 0) {
          targetRepoId = repos[0].id;
        } else {
            // Auto create general if absolutely no repos exist
            const id = await onCreateRepo('general-notes');
            if (id) targetRepoId = id;
        }
      }

      // Logic: If user opted to create new repo
      if (isCreatingRepo && newRepoName.trim()) {
        const id = await onCreateRepo(newRepoName);
        if (id) targetRepoId = id;
      }

      // Generate Title if empty
      let finalTitle = title.trim();
      if (!finalTitle) {
         const dateStr = new Date().toISOString().split('T')[0];
         const snippet = content.slice(0, 15).replace(/\n/g, ' ').trim();
         finalTitle = snippet ? `${snippet}... (${dateStr}).md` : `note-${dateStr}.md`;
      }
      if (!finalTitle.endsWith('.md')) finalTitle += '.md';

      if (targetRepoId) {
          await onQuickSave(targetRepoId, finalTitle, content);
          // Reset
          setContent('');
          setTitle('');
          setIsExpanded(false);
          setIsCreatingRepo(false);
          setNewRepoName('');
      }
    } catch (e) {
        console.error("Capture failed", e);
        alert("Transmission failed. Check network.");
    } finally {
        setIsSaving(false);
    }
  };

  return (
    <div className={`mb-12 border transition-all duration-300 ${isExpanded ? 'bg-zenith-surface border-zenith-orange shadow-[0_0_20px_rgba(255,77,0,0.15)]' : 'bg-black border-zenith-border hover:border-zenith-light'}`}>

      {/* Collapsed View (Input Trigger) */}
      {!isExpanded && (
        <div 
            onClick={() => setIsExpanded(true)}
            className="p-4 flex items-center gap-4 cursor-text"
        >
            <div className="text-zenith-orange animate-pulse">
                <Icons.Edit size={18} />
            </div>
            <span className="font-mono text-zenith-muted text-sm tracking-wide">
                INITIATE QUICK CAPTURE PROTOCOL...
            </span>
        </div>
      )}

      {/* Expanded View */}
      {isExpanded && (
        <div className="p-6">
            <div className="flex items-center justify-between mb-4 border-b border-zenith-border pb-2">
                <span className="font-mono text-xs text-zenith-orange tracking-widest uppercase flex items-center gap-2">
                    <Icons.Zap size={12} /> Live Uplink
                </span>
                <button onClick={() => setIsExpanded(false)} className="text-zenith-muted hover:text-white">
                    <Icons.Close size={16} />
                </button>
            </div>

            <div className="space-y-4">
                <textarea 
                    autoFocus
                    value={content}
                    onChange={e => setContent(e.target.value)}
                    placeholder="Enter raw data stream..."
                    className="w-full bg-black border border-zenith-border p-4 text-white font-mono text-sm focus:border-zenith-orange focus:outline-none min-h-[120px] resize-y"
                />

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <input 
                        type="text"
                        value={title}
                        onChange={e => setTitle(e.target.value)}
                        placeholder="Filename (Optional)"
                        className="bg-black border border-zenith-border p-2 text-white font-mono text-xs focus:border-zenith-orange focus:outline-none"
                    />

                    <div className="relative">
                        {!isCreatingRepo ? (
                            <div className="flex gap-2">
                                <select 
                                    value={selectedRepoId}
                                    onChange={e => {
                                        if(e.target.value === 'NEW') {
                                            setIsCreatingRepo(true);
                                        } else {
                                            setSelectedRepoId(e.target.value);
                                        }
                                    }}
                                    className="flex-1 bg-black border border-zenith-border p-2 text-white font-mono text-xs focus:border-zenith-orange focus:outline-none appearance-none"
                                >
                                    <option value="" disabled>Select Target Module</option>
                                    {repos.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                                    <option value="NEW" className="text-zenith-orange">[+ CREATE NEW MODULE]</option>
                                </select>
                                <div className="absolute right-2 top-2.5 pointer-events-none text-zenith-muted">
                                    <Icons.ChevronRight size={12} className="rotate-90" />
                                </div>
                            </div>
                        ) : (
                            <div className="flex gap-2">
                                <input 
                                    type="text"
                                    value={newRepoName}
                                    onChange={e => setNewRepoName(e.target.value)}
                                    placeholder="New Module Name"
                                    className="flex-1 bg-black border border-zenith-orange p-2 text-zenith-orange font-mono text-xs focus:outline-none placeholder:text-zenith-orange/50"
                                />
                                <button 
                                    onClick={() => setIsCreatingRepo(false)}
                                    className="p-2 border border-zenith-border text-zenith-muted hover:text-white"
                                >
                                    <Icons.Close size={14} />
                                </button>
                            </div>
                        )}
                    </div>
                </div>

                <div className="flex justify-end pt-2">
                    <button 
                        onClick={handleSave}
                        disabled={isSaving || !content.trim()}
                        className={`bg-zenith-orange text-black px-6 py-2 text-xs font-bold font-mono tracking-widest uppercase hover:bg-white transition-colors flex items-center gap-2 ${isSaving ? 'opacity-50 cursor-wait' : ''}`}
                    >
                        {isSaving ? 'Transmitting...' : (
                            <>
                                <Icons.Upload size={14} /> Commit Data
                            </>
                        )}
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default QuickCapture;

