import React, { useState, useEffect, useRef } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { Repository } from '../types';
import { Icons } from '../components/Icon';
import MarkdownPreview from '../components/MarkdownPreview';
import DeleteConfirmModal from '../components/DeleteConfirmModal';
import EditorToolbar from '../components/EditorToolbar';
// Use default import for Turndown, but handle 'default' property at runtime if needed
// @ts-ignore
import TurndownService from 'turndown';
// Use named import for gfm plugin
// @ts-ignore
import { gfm } from 'turndown-plugin-gfm';

interface FileEditorProps {
  repos: Repository[];
  onUpdateFile: (repoId: string, fileId: string, newContent: string) => void;
  onDeleteFile: (repoId: string, fileId: string) => void;
  isAuthenticated: boolean;
}

type ViewMode = 'write' | 'preview' | 'split';

const FileEditor: React.FC<FileEditorProps> = ({ repos, onUpdateFile, onDeleteFile, isAuthenticated }) => {
  const { repoId, fileId } = useParams<{ repoId: string; fileId: string }>();
  const navigate = useNavigate();
  const textAreaRef = useRef<HTMLTextAreaElement>(null);

  const repo = repos.find(r => r.id === repoId);
  const file = repo?.files.find(f => f.id === fileId);

  const [viewMode, setViewMode] = useState<ViewMode>('preview');
  const [content, setContent] = useState('');
  const [hasChanges, setHasChanges] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [conversionStatus, setConversionStatus] = useState<string | null>(null);

  useEffect(() => {
    if (file) {
      setContent(file.content);
    }
  }, [file]);

  if (!repo || !file) {
    return <div className="h-screen flex items-center justify-center font-mono text-zenith-orange">ERROR: FILE DATA CORRUPTED OR MISSING</div>;
  }

  const handleSave = () => {
    if (!isAuthenticated) return;
    onUpdateFile(repoId!, fileId!, content);
    setHasChanges(false);
  };

  const handleContentChange = (val: string) => {
      setContent(val);
      setHasChanges(val !== file.content);
  }

  const handleDeleteConfirm = () => {
      if (!isAuthenticated) return;
      onDeleteFile(repoId!, fileId!);
      navigate(`/${repoId}`);
  }

  const handleInsert = (prefix: string, suffix: string = '') => {
    if (!textAreaRef.current) return;
    const start = textAreaRef.current.selectionStart;
    const end = textAreaRef.current.selectionEnd;
    const text = textAreaRef.current.value;
    const before = text.substring(0, start);
    const selection = text.substring(start, end);
    const after = text.substring(end);

    const newText = before + prefix + selection + suffix + after;
    handleContentChange(newText);

    // Defer focus to allow React render
    setTimeout(() => {
      if(textAreaRef.current) {
        textAreaRef.current.focus();
        textAreaRef.current.selectionStart = start + prefix.length;
        textAreaRef.current.selectionEnd = end + prefix.length;
      }
    }, 0);
  };

  const insertTextAtCursor = (textToInsert: string) => {
      if (!textAreaRef.current) return;
      const start = textAreaRef.current.selectionStart;
      const end = textAreaRef.current.selectionEnd;
      const currentText = textAreaRef.current.value;
      const before = currentText.substring(0, start);
      const after = currentText.substring(end);

      const newText = before + textToInsert + after;
      handleContentChange(newText);

      setTimeout(() => {
          if (textAreaRef.current) {
              textAreaRef.current.focus();
              const newCursorPos = start + textToInsert.length;
              textAreaRef.current.selectionStart = newCursorPos;
              textAreaRef.current.selectionEnd = newCursorPos;
          }
      }, 0);
  };

  const handlePaste = (e: React.ClipboardEvent<HTMLTextAreaElement>) => {
    if (!isAuthenticated) return;

    const clipboardData = e.clipboardData;
    const types = clipboardData.types;

    // console.log("GitNotes Paste Debug: Available Types ->", types);

    // Check for HTML content
    if (types.includes('text/html')) {
        const html = clipboardData.getData('text/html');
        // console.log("GitNotes Paste Debug: Found HTML content, length:", html.length);

        try {
            e.preventDefault(); // Prevent default plain text paste immediately

            // 1. Robust Constructor Resolution
            // In Vite prod builds, sometimes CJS modules are wrapped in { default: ... }
            let ServiceClass = TurndownService;
            // @ts-ignore
            if (typeof ServiceClass !== 'function' && ServiceClass.default) {
                // @ts-ignore
                ServiceClass = ServiceClass.default;
            }

            if (typeof ServiceClass !== 'function') {
                throw new Error("Could not find TurndownService constructor.");
            }

            // 2. Initialize Service
            // @ts-ignore
            const turndownService = new ServiceClass({
                headingStyle: 'atx',
                codeBlockStyle: 'fenced',
                bulletListMarker: '-',
                emDelimiter: '*'
            });

            // 3. Robust Plugin Loading (Fail-safe)
            try {
                if (typeof gfm === 'function') {
                    turndownService.use(gfm);
                    // console.log("GitNotes Debug: GFM Plugin applied.");
                } else {
                    console.warn("GitNotes Warning: GFM plugin not available, skipping tables support.");
                }
            } catch (pluginErr) {
                console.warn("GitNotes Warning: Error applying GFM plugin, continuing with basic markdown.", pluginErr);
            }

            // Pure Text Mode: Remove images
            turndownService.remove('img');
            turndownService.remove('picture');

            // 4. Custom Rules
            turndownService.addRule('pre', {
                filter: ['pre'],
                replacement: function (content: string, node: any) {
                     return '\n```\n' + node.textContent + '\n```\n';
                }
            });

            // 5. Execute Conversion
            const markdown = turndownService.turndown(html);

            // Visual Feedback
            setConversionStatus("SMART PASTE: TEXT ONLY");
            setTimeout(() => setConversionStatus(null), 3000);

            insertTextAtCursor(markdown);

        } catch (err) {
            console.error("GitNotes Paste Error:", err);

            // Fallback: manually insert the plain text since we prevented default
            const plainText = clipboardData.getData('text/plain');
            insertTextAtCursor(plainText);

            setConversionStatus("PASTE FALLBACK: PLAIN TEXT");
            setTimeout(() => setConversionStatus(null), 3000);
        }
        return;
    }

    // console.log("GitNotes Paste: Plain text mode");
  };

  const lineCount = content.split('\n').length;

  return (
    <div className="h-[calc(100vh-56px)] flex flex-col bg-zenith-bg relative">

      {/* Toast Notification (Fixed Position) */}
      {conversionStatus && (
          <div className="fixed bottom-12 right-6 z-50 animate-in slide-in-from-bottom-5 duration-300">
              <div className="bg-zenith-surface border border-zenith-orange px-4 py-3 shadow-[0_0_15px_rgba(255,77,0,0.2)] flex items-center gap-3">
                  <div className="bg-zenith-orange text-black p-1">
                      <Icons.Zap size={14} />
                  </div>
                  <span className="font-mono text-white font-bold text-xs tracking-widest uppercase">
                      {conversionStatus}
                  </span>
              </div>
          </div>
      )}

      {/* File Toolbar */}
      <div className="h-14 border-b border-zenith-border bg-zenith-bg flex items-center justify-between px-6 shrink-0 relative z-10">
          <div className="flex items-center gap-4">
              <Link to={`/${repoId}`} className="text-zenith-muted hover:text-white transition-colors">
                  <Icons.ChevronRight className="rotate-180" size={18} />
              </Link>
              <div className="h-6 w-px bg-zenith-border"></div>
              <span className="font-mono text-sm text-white font-bold tracking-wide">{file.name}</span>
              {hasChanges && <span className="text-[10px] bg-zenith-orange text-black px-2 py-0.5 font-bold font-mono">UNSAVED</span>}
              {!isAuthenticated && <span className="text-[10px] border border-zenith-border text-zenith-muted px-2 py-0.5 font-mono uppercase">Read Only</span>}
          </div>

          <div className="flex items-center gap-3">
             {/* Mode Switcher */}
             <div className="flex border border-zenith-border p-0.5 bg-zenith-surface">
                 <button 
                    onClick={() => setViewMode('write')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'write' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Write Mode"
                 >
                    <Icons.Edit size={12} /> <span className="hidden sm:inline">Write</span>
                 </button>
                 <button 
                    onClick={() => setViewMode('split')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 border-l border-r border-zenith-border ${viewMode === 'split' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Split View"
                 >
                    <Icons.Layout size={12} /> <span className="hidden sm:inline">Split</span>
                 </button>
                 <button 
                    onClick={() => setViewMode('preview')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'preview' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Preview Mode"
                 >
                    <Icons.File size={12} /> <span className="hidden sm:inline">Render</span>
                 </button>
             </div>

             {isAuthenticated && (
                <>
                 <button 
                    onClick={handleSave}
                    disabled={!hasChanges}
                    className={`flex items-center gap-2 px-4 py-2 border text-xs font-mono tracking-widest uppercase transition-colors ${hasChanges ? 'border-zenith-orange text-zenith-orange hover:bg-zenith-orange hover:text-black' : 'border-zenith-border text-zenith-muted cursor-not-allowed'}`}
                 >
                    <Icons.Save size={14} /> Save
                 </button>

                 <button onClick={() => setIsDeleteModalOpen(true)} className="p-2 text-zenith-muted hover:text-red-600 transition-colors">
                     <Icons.Trash size={16} />
                 </button>
                </>
             )}
          </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-hidden relative flex z-0">

         {/* Write Panel */}
         {(viewMode === 'write' || viewMode === 'split') && (
           <div className={`flex flex-col border-r border-zenith-border ${viewMode === 'split' ? 'w-1/2' : 'w-full'}`}>
             {isAuthenticated && <EditorToolbar onInsert={handleInsert} />}
             <div className="flex flex-1 overflow-hidden">
                {/* Line Numbers */}
                <div className="hidden sm:block w-10 bg-zenith-surface border-r border-zenith-border text-right py-4 pr-2 font-mono text-xs text-zenith-border select-none overflow-hidden shrink-0">
                    {Array.from({length: Math.max(lineCount, 20)}).map((_, i) => <div key={i}>{i+1}</div>)}
                </div>

                <textarea
                    ref={textAreaRef}
                    readOnly={!isAuthenticated}
                    value={content}
                    onChange={(e) => handleContentChange(e.target.value)}
                    onPaste={handlePaste}
                    className={`w-full h-full bg-zenith-bg text-zenith-text font-mono text-sm p-4 resize-none outline-none transition-colors leading-relaxed ${!isAuthenticated ? 'cursor-not-allowed text-zenith-muted' : 'focus:bg-[#050505]'}`}
                    spellCheck={false}
                    placeholder={!isAuthenticated ? "Editing is disabled in visitor mode." : "Start typing... (Rich text pasted here will be auto-converted to Markdown)"}
                />
             </div>
           </div>
         )}

         {/* Preview Panel */}
         {(viewMode === 'preview' || viewMode === 'split') && (
           <div className={`flex-1 overflow-auto bg-zenith-bg ${viewMode === 'split' ? 'bg-[#080808]' : ''}`}>
               <div className={`p-8 mx-auto ${viewMode === 'split' ? 'max-w-none' : 'max-w-4xl'}`}>
                   <MarkdownPreview content={content} />
               </div>
           </div>
         )}

      </div>

      {/* Footer Info */}
      <div className="h-8 border-t border-zenith-border bg-zenith-surface flex items-center justify-between px-4 font-mono text-[10px] text-zenith-muted uppercase tracking-widest shrink-0">
         <div>Ln {lineCount}, Col {content.length}</div>
         <div>{isAuthenticated ? 'Markdown Environment' : 'Visitor View'}</div>
      </div>

      <DeleteConfirmModal 
        isOpen={isDeleteModalOpen}
        onClose={() => setIsDeleteModalOpen(false)}
        onConfirm={handleDeleteConfirm}
        title="Delete File"
        itemName={file.name}
      />
    </div>
  );
};

export default FileEditor;

import React from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus } from 'react-syntax-highlighter/dist/esm/styles/prism';

interface MarkdownPreviewProps {
  content: string;
}

// Utility to generate IDs from heading text
export const generateSlug = (text: string): string => {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9\u4e00-\u9fa5]+/g, '-') // Support Chinese characters & alphanumeric
    .replace(/(^-|-$)+/g, '');
};

// Utility to extract text from React children (recursively if needed)
const getNodeText = (node: any): string => {
  if (['string', 'number'].includes(typeof node)) return node;
  if (node instanceof Array) return node.map(getNodeText).join('');
  if (typeof node === 'object' && node?.props?.children) return getNodeText(node.props.children);
  return '';
};

const MarkdownPreview: React.FC<MarkdownPreviewProps> = ({ content }) => {
  // Simple Frontmatter Parser
  let displayContent = content;
  let frontmatter: Record<string, string> | null = null;

  if (content.startsWith('---')) {
    const endMatch = content.indexOf('---', 3);
    if (endMatch !== -1) {
      const fmBlock = content.slice(3, endMatch);
      displayContent = content.slice(endMatch + 3).trim();

      frontmatter = {};
      fmBlock.split('\n').forEach(line => {
        const [key, ...values] = line.split(':');
        if (key && values.length) {
          frontmatter![key.trim()] = values.join(':').trim();
        }
      });
    }
  }

  const HeaderRenderer = ({ level, children, ...props }: any) => {
    const text = getNodeText(children);
    const slug = generateSlug(text);
    const Tag = `h${level}` as keyof JSX.IntrinsicElements;

    // Tailwind classes based on level
    let classes = "font-bold tracking-tight text-white scroll-mt-20"; // scroll-mt handles sticky header offset
    if (level === 1) classes += " text-3xl border-b border-zenith-border pb-4 mb-6 mt-8 first:mt-0";
    if (level === 2) classes += " text-2xl mt-8 mb-4 flex items-center gap-2 before:content-['#'] before:text-zenith-orange/50 before:font-mono before:text-lg";
    if (level === 3) classes += " text-xl font-semibold mt-6 mb-3";
    if (level === 4) classes += " text-lg font-semibold mt-6 mb-2";

    return React.createElement(Tag, { ...props, id: slug, className: classes }, children);
  };

  return (
    <div className="flex flex-col gap-6">
      {frontmatter && Object.keys(frontmatter).length > 0 && (
        <div className="bg-zenith-surface border border-zenith-border p-4 mb-4 font-mono text-xs">
          <div className="text-zenith-muted uppercase tracking-widest mb-2 border-b border-zenith-border pb-1">Metadata</div>
          <div className="grid grid-cols-[100px_1fr] gap-y-1">
            {Object.entries(frontmatter).map(([k, v]) => (
              <React.Fragment key={k}>
                <span className="text-zenith-orange">{k}</span>
                <span className="text-zenith-text break-all">{v}</span>
              </React.Fragment>
            ))}
          </div>
        </div>
      )}

      <div className="prose prose-invert prose-sm max-w-none font-sans">
        <ReactMarkdown 
          remarkPlugins={[remarkGfm]}
          components={{
            code({node, inline, className, children, ...props}: any) {
              const match = /language-(\w+)/.exec(className || '')
              return !inline && match ? (
                <div className="bg-zenith-surface border border-zenith-border my-4 group relative">
                  <div className="bg-zenith-border/30 px-3 py-1 text-[10px] font-mono text-zenith-muted uppercase border-b border-zenith-border flex justify-between items-center">
                    <span>{match[1]}</span>
                  </div>
                  <SyntaxHighlighter
                    {...props}
                    style={vscDarkPlus}
                    language={match[1]}
                    PreTag="div"
                    customStyle={{ background: 'transparent', padding: '1rem', fontSize: '0.875rem' }}
                  >
                    {String(children).replace(/\n$/, '')}
                  </SyntaxHighlighter>
                </div>
              ) : (
                <code className="bg-zenith-surface border border-zenith-border px-1.5 py-0.5 rounded-none text-xs font-mono text-zenith-orange break-words" {...props}>
                  {children}
                </code>
              )
            },
            h1: ({node, children, ...props}) => <HeaderRenderer level={1} children={children} {...props} />,
            h2: ({node, children, ...props}) => <HeaderRenderer level={2} children={children} {...props} />,
            h3: ({node, children, ...props}) => <HeaderRenderer level={3} children={children} {...props} />,
            h4: ({node, children, ...props}) => <HeaderRenderer level={4} children={children} {...props} />,
            p: ({node, ...props}) => <p className="text-zenith-text leading-7 mb-4" {...props} />,
            blockquote: ({node, ...props}) => <blockquote className="border-l-2 border-zenith-orange pl-4 bg-zenith-surface/30 py-2 pr-2 text-zenith-muted italic my-6" {...props} />,

            // Lists
            ul: ({node, ...props}) => <ul className="list-disc list-outside ml-5 my-4 space-y-2 marker:text-zenith-orange text-zenith-text" {...props} />,
            ol: ({node, ...props}) => <ol className="list-decimal list-outside ml-5 my-4 space-y-2 marker:text-zenith-orange text-zenith-text" {...props} />,
            li: ({node, ...props}) => <li className="pl-1" {...props} />,

            // Links & Formatting
            a: ({node, ...props}) => <a className="text-zenith-orange hover:text-white underline decoration-zenith-orange/50 hover:decoration-white underline-offset-4 transition-colors cursor-pointer" {...props} />,
            hr: ({node, ...props}) => <hr className="border-zenith-border my-8" {...props} />,
            img: ({node, ...props}) => <img className="max-w-full border border-zenith-border my-6 bg-black/50" {...props} />,
            strong: ({node, ...props}) => <strong className="font-bold text-white" {...props} />,
            em: ({node, ...props}) => <em className="italic text-zenith-text/80" {...props} />,
            del: ({node, ...props}) => <del className="line-through text-zenith-muted" {...props} />,

            // Tables (GFM)
            table: ({node, ...props}) => (
              <div className="overflow-x-auto my-8 border border-zenith-border">
                <table className="w-full text-left border-collapse text-sm" {...props} />
              </div>
            ),
            thead: ({node, ...props}) => <thead className="bg-zenith-surface border-b border-zenith-border" {...props} />,
            tbody: ({node, ...props}) => <tbody className="divide-y divide-zenith-border bg-black/20" {...props} />,
            tr: ({node, ...props}) => <tr className="hover:bg-white/5 transition-colors" {...props} />,
            th: ({node, ...props}) => <th className="p-3 font-mono text-xs font-bold uppercase tracking-wider text-zenith-muted select-none" {...props} />,
            td: ({node, ...props}) => <td className="p-3 text-zenith-text border-r border-zenith-border last:border-r-0 whitespace-nowrap md:whitespace-normal" {...props} />,
          }}
        >
          {displayContent}
        </ReactMarkdown>
      </div>
    </div>
  );
};

export default MarkdownPreview;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { Repository } from '../types';
import { Icons } from '../components/Icon';
import MarkdownPreview, { generateSlug } from '../components/MarkdownPreview';
import DeleteConfirmModal from '../components/DeleteConfirmModal';
import EditorToolbar from '../components/EditorToolbar';
// Use default import for Turndown, but handle 'default' property at runtime if needed
// @ts-ignore
import TurndownService from 'turndown';
// Use named import for gfm plugin
// @ts-ignore
import { gfm } from 'turndown-plugin-gfm';

interface FileEditorProps {
  repos: Repository[];
  onUpdateFile: (repoId: string, fileId: string, newContent: string) => void;
  onDeleteFile: (repoId: string, fileId: string) => void;
  isAuthenticated: boolean;
}

type ViewMode = 'write' | 'preview' | 'split';

interface TocItem {
  id: string;
  text: string;
  level: number;
}

const FileEditor: React.FC<FileEditorProps> = ({ repos, onUpdateFile, onDeleteFile, isAuthenticated }) => {
  const { repoId, fileId } = useParams<{ repoId: string; fileId: string }>();
  const navigate = useNavigate();
  const textAreaRef = useRef<HTMLTextAreaElement>(null);

  const repo = repos.find(r => r.id === repoId);
  const file = repo?.files.find(f => f.id === fileId);

  const [viewMode, setViewMode] = useState<ViewMode>('preview');
  const [content, setContent] = useState('');
  const [hasChanges, setHasChanges] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [conversionStatus, setConversionStatus] = useState<string | null>(null);

  useEffect(() => {
    if (file) {
      setContent(file.content);
    }
  }, [file]);

  // --- Table of Contents Logic ---
  const toc = useMemo(() => {
    if (!content) return [];

    // Regex to match # Heading, ## Heading etc.
    // Handles simple markdown headers
    const headingRegex = /^(#{1,3})\s+(.+)$/gm;
    const items: TocItem[] = [];
    let match;

    // We need to work on a version without code blocks to avoid false positives in code
    // This is a simplified parser; for perfect accuracy one would need AST, but regex is usually fast/enough for basic usage
    // To respect code blocks, we simple strip lines starting with ``` for the search context, but keeping it simple for now:

    const lines = content.split('\n');
    let inCodeBlock = false;

    lines.forEach(line => {
        if (line.trim().startsWith('```')) {
            inCodeBlock = !inCodeBlock;
            return;
        }
        if (inCodeBlock) return;

        const headingMatch = line.match(/^(#{1,3})\s+(.+)$/);
        if (headingMatch) {
            const level = headingMatch[1].length;
            const text = headingMatch[2].trim();
            // Remove markdown links or bold from TOC text if present
            const cleanText = text.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1').replace(/(\*\*|__)(.*?)\1/g, '$2');

            items.push({
                id: generateSlug(cleanText),
                text: cleanText,
                level
            });
        }
    });

    return items;
  }, [content]);

  if (!repo || !file) {
    return <div className="h-screen flex items-center justify-center font-mono text-zenith-orange">ERROR: FILE DATA CORRUPTED OR MISSING</div>;
  }

  const handleSave = () => {
    if (!isAuthenticated) return;
    onUpdateFile(repoId!, fileId!, content);
    setHasChanges(false);
  };

  const handleContentChange = (val: string) => {
      setContent(val);
      setHasChanges(val !== file.content);
  }

  const handleDeleteConfirm = () => {
      if (!isAuthenticated) return;
      onDeleteFile(repoId!, fileId!);
      navigate(`/${repoId}`);
  }

  const handleInsert = (prefix: string, suffix: string = '') => {
    if (!textAreaRef.current) return;
    const start = textAreaRef.current.selectionStart;
    const end = textAreaRef.current.selectionEnd;
    const text = textAreaRef.current.value;
    const before = text.substring(0, start);
    const selection = text.substring(start, end);
    const after = text.substring(end);

    const newText = before + prefix + selection + suffix + after;
    handleContentChange(newText);

    // Defer focus to allow React render
    setTimeout(() => {
      if(textAreaRef.current) {
        textAreaRef.current.focus();
        textAreaRef.current.selectionStart = start + prefix.length;
        textAreaRef.current.selectionEnd = end + prefix.length;
      }
    }, 0);
  };

  const insertTextAtCursor = (textToInsert: string) => {
      if (!textAreaRef.current) return;
      const start = textAreaRef.current.selectionStart;
      const end = textAreaRef.current.selectionEnd;
      const currentText = textAreaRef.current.value;
      const before = currentText.substring(0, start);
      const after = currentText.substring(end);

      const newText = before + textToInsert + after;
      handleContentChange(newText);

      setTimeout(() => {
          if (textAreaRef.current) {
              textAreaRef.current.focus();
              const newCursorPos = start + textToInsert.length;
              textAreaRef.current.selectionStart = newCursorPos;
              textAreaRef.current.selectionEnd = newCursorPos;
          }
      }, 0);
  };

  const handlePaste = (e: React.ClipboardEvent<HTMLTextAreaElement>) => {
    if (!isAuthenticated) return;

    const clipboardData = e.clipboardData;
    const types = clipboardData.types;

    // Check for HTML content
    if (types.includes('text/html')) {
        const html = clipboardData.getData('text/html');

        try {
            e.preventDefault(); 

            // 1. Robust Constructor Resolution
            let ServiceClass = TurndownService;
            // @ts-ignore
            if (typeof ServiceClass !== 'function' && ServiceClass.default) {
                // @ts-ignore
                ServiceClass = ServiceClass.default;
            }

            if (typeof ServiceClass !== 'function') {
                throw new Error("Could not find TurndownService constructor.");
            }

            // 2. Initialize Service
            // @ts-ignore
            const turndownService = new ServiceClass({
                headingStyle: 'atx',
                codeBlockStyle: 'fenced',
                bulletListMarker: '-',
                emDelimiter: '*'
            });

            // 3. Robust Plugin Loading (Fail-safe)
            try {
                if (typeof gfm === 'function') {
                    turndownService.use(gfm);
                } else {
                    console.warn("GitNotes Warning: GFM plugin not available, skipping tables support.");
                }
            } catch (pluginErr) {
                console.warn("GitNotes Warning: Error applying GFM plugin, continuing with basic markdown.", pluginErr);
            }

            // Pure Text Mode: Remove images
            turndownService.remove('img');
            turndownService.remove('picture');

            // 4. Custom Rules
            turndownService.addRule('pre', {
                filter: ['pre'],
                replacement: function (content: string, node: any) {
                     return '\n```\n' + node.textContent + '\n```\n';
                }
            });

            // 5. Execute Conversion
            const markdown = turndownService.turndown(html);

            // Visual Feedback
            setConversionStatus("SMART PASTE: TEXT ONLY");
            setTimeout(() => setConversionStatus(null), 3000);

            insertTextAtCursor(markdown);

        } catch (err) {
            console.error("GitNotes Paste Error:", err);

            // Fallback: manually insert the plain text since we prevented default
            const plainText = clipboardData.getData('text/plain');
            insertTextAtCursor(plainText);

            setConversionStatus("PASTE FALLBACK: PLAIN TEXT");
            setTimeout(() => setConversionStatus(null), 3000);
        }
        return;
    }
  };

  const lineCount = content.split('\n').length;

  return (
    <div className="h-[calc(100vh-56px)] flex flex-col bg-zenith-bg relative">

      {/* Toast Notification (Fixed Position) */}
      {conversionStatus && (
          <div className="fixed bottom-12 right-6 z-50 animate-in slide-in-from-bottom-5 duration-300">
              <div className="bg-zenith-surface border border-zenith-orange px-4 py-3 shadow-[0_0_15px_rgba(255,77,0,0.2)] flex items-center gap-3">
                  <div className="bg-zenith-orange text-black p-1">
                      <Icons.Zap size={14} />
                  </div>
                  <span className="font-mono text-white font-bold text-xs tracking-widest uppercase">
                      {conversionStatus}
                  </span>
              </div>
          </div>
      )}

      {/* File Toolbar */}
      <div className="h-14 border-b border-zenith-border bg-zenith-bg flex items-center justify-between px-6 shrink-0 relative z-10">
          <div className="flex items-center gap-4">
              <Link to={`/${repoId}`} className="text-zenith-muted hover:text-white transition-colors">
                  <Icons.ChevronRight className="rotate-180" size={18} />
              </Link>
              <div className="h-6 w-px bg-zenith-border"></div>
              <span className="font-mono text-sm text-white font-bold tracking-wide">{file.name}</span>
              {hasChanges && <span className="text-[10px] bg-zenith-orange text-black px-2 py-0.5 font-bold font-mono">UNSAVED</span>}
              {!isAuthenticated && <span className="text-[10px] border border-zenith-border text-zenith-muted px-2 py-0.5 font-mono uppercase">Read Only</span>}
          </div>

          <div className="flex items-center gap-3">
             {/* Mode Switcher */}
             <div className="flex border border-zenith-border p-0.5 bg-zenith-surface">
                 <button 
                    onClick={() => setViewMode('write')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'write' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Write Mode"
                 >
                    <Icons.Edit size={12} /> <span className="hidden sm:inline">Write</span>
                 </button>
                 <button 
                    onClick={() => setViewMode('split')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 border-l border-r border-zenith-border ${viewMode === 'split' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Split View"
                 >
                    <Icons.Layout size={12} /> <span className="hidden sm:inline">Split</span>
                 </button>
                 <button 
                    onClick={() => setViewMode('preview')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'preview' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Preview Mode"
                 >
                    <Icons.File size={12} /> <span className="hidden sm:inline">Render</span>
                 </button>
             </div>

             {isAuthenticated && (
                <>
                 <button 
                    onClick={handleSave}
                    disabled={!hasChanges}
                    className={`flex items-center gap-2 px-4 py-2 border text-xs font-mono tracking-widest uppercase transition-colors ${hasChanges ? 'border-zenith-orange text-zenith-orange hover:bg-zenith-orange hover:text-black' : 'border-zenith-border text-zenith-muted cursor-not-allowed'}`}
                 >
                    <Icons.Save size={14} /> Save
                 </button>

                 <button onClick={() => setIsDeleteModalOpen(true)} className="p-2 text-zenith-muted hover:text-red-600 transition-colors">
                     <Icons.Trash size={16} />
                 </button>
                </>
             )}
          </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-hidden relative flex z-0">

         {/* Write Panel */}
         {(viewMode === 'write' || viewMode === 'split') && (
           <div className={`flex flex-col border-r border-zenith-border ${viewMode === 'split' ? 'w-1/2' : 'w-full'}`}>
             {isAuthenticated && <EditorToolbar onInsert={handleInsert} />}
             <div className="flex flex-1 overflow-hidden">
                {/* Line Numbers */}
                <div className="hidden sm:block w-10 bg-zenith-surface border-r border-zenith-border text-right py-4 pr-2 font-mono text-xs text-zenith-border select-none overflow-hidden shrink-0">
                    {Array.from({length: Math.max(lineCount, 20)}).map((_, i) => <div key={i}>{i+1}</div>)}
                </div>

                <textarea
                    ref={textAreaRef}
                    readOnly={!isAuthenticated}
                    value={content}
                    onChange={(e) => handleContentChange(e.target.value)}
                    onPaste={handlePaste}
                    className={`w-full h-full bg-zenith-bg text-zenith-text font-mono text-sm p-4 resize-none outline-none transition-colors leading-relaxed ${!isAuthenticated ? 'cursor-not-allowed text-zenith-muted' : 'focus:bg-[#050505]'}`}
                    spellCheck={false}
                    placeholder={!isAuthenticated ? "Editing is disabled in visitor mode." : "Start typing... (Rich text pasted here will be auto-converted to Markdown)"}
                />
             </div>
           </div>
         )}

         {/* Preview Panel Wrapper (Now Flex for Sidebar) */}
         {(viewMode === 'preview' || viewMode === 'split') && (
           <div className={`flex flex-1 overflow-hidden bg-zenith-bg ${viewMode === 'split' ? 'bg-[#080808]' : ''}`}>

               {/* Actual Preview Content */}
               <div className="flex-1 overflow-y-auto overflow-x-hidden">
                   <div className={`p-8 mx-auto ${viewMode === 'split' ? 'max-w-none' : 'max-w-4xl'}`}>
                       <MarkdownPreview content={content} />
                   </div>
                   {/* Bottom Spacer for comfortable reading */}
                   <div className="h-32"></div>
               </div>

                {/* Outline Sidebar (Visible in Preview Mode mainly, or Split if room permits) */}
                {viewMode === 'preview' && toc.length > 0 && (
                    <div className="hidden xl:flex w-72 flex-col border-l border-zenith-border bg-zenith-bg/50 backdrop-blur-sm">
                        <div className="p-4 border-b border-zenith-border font-mono text-[10px] tracking-widest text-zenith-muted uppercase flex items-center gap-2">
                            <Icons.List size={12} />
                            <span>Document Outline</span>
                        </div>
                        <div className="flex-1 overflow-y-auto p-4 space-y-1">
                            {toc.map((item, idx) => (
                                <a 
                                    key={`${item.id}-${idx}`}
                                    href={`#${item.id}`}
                                    onClick={(e) => {
                                        e.preventDefault();
                                        document.getElementById(item.id)?.scrollIntoView({ behavior: 'smooth' });
                                    }}
                                    className={`
                                        block text-xs font-mono py-1.5 transition-colors duration-200 border-l-2 border-transparent hover:border-zenith-orange pl-3
                                        ${item.level === 1 ? 'text-white font-bold' : 'text-zenith-muted hover:text-zenith-text'}
                                        ${item.level === 2 ? 'ml-2' : ''}
                                        ${item.level === 3 ? 'ml-4' : ''}
                                    `}
                                >
                                    {item.text}
                                </a>
                            ))}
                        </div>
                    </div>
                )}
           </div>
         )}

      </div>

      {/* Footer Info */}
      <div className="h-8 border-t border-zenith-border bg-zenith-surface flex items-center justify-between px-4 font-mono text-[10px] text-zenith-muted uppercase tracking-widest shrink-0">
         <div>Ln {lineCount}, Col {content.length}</div>
         <div>{isAuthenticated ? 'Markdown Environment' : 'Visitor View'}</div>
      </div>

      <DeleteConfirmModal 
        isOpen={isDeleteModalOpen}
        onClose={() => setIsDeleteModalOpen(false)}
        onConfirm={handleDeleteConfirm}
        title="Delete File"
        itemName={file.name}
      />
    </div>
  );
};

export default FileEditor;

import React from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus } from 'react-syntax-highlighter/dist/esm/styles/prism';

interface MarkdownPreviewProps {
  content: string;
}

// Utility to generate IDs from heading text
export const generateSlug = (text: string): string => {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9\u4e00-\u9fa5]+/g, '-') // Support Chinese characters & alphanumeric
    .replace(/(^-|-$)+/g, '');
};

// Utility to extract text from React children (recursively if needed)
const getNodeText = (node: any): string => {
  if (['string', 'number'].includes(typeof node)) return node;
  if (node instanceof Array) return node.map(getNodeText).join('');
  if (typeof node === 'object' && node?.props?.children) return getNodeText(node.props.children);
  return '';
};

const MarkdownPreview: React.FC<MarkdownPreviewProps> = ({ content }) => {
  // Simple Frontmatter Parser
  let displayContent = content;
  let frontmatter: Record<string, string> | null = null;

  if (content.startsWith('---')) {
    const endMatch = content.indexOf('---', 3);
    if (endMatch !== -1) {
      const fmBlock = content.slice(3, endMatch);
      displayContent = content.slice(endMatch + 3).trim();

      frontmatter = {};
      fmBlock.split('\n').forEach(line => {
        const [key, ...values] = line.split(':');
        if (key && values.length) {
          frontmatter![key.trim()] = values.join(':').trim();
        }
      });
    }
  }

  const HeaderRenderer = ({ level, children, ...props }: any) => {
    const text = getNodeText(children);
    const slug = generateSlug(text);
    const Tag = `h${level}` as React.ElementType;

    // Tailwind classes based on level
    let classes = "font-bold tracking-tight text-white scroll-mt-20"; // scroll-mt handles sticky header offset
    if (level === 1) classes += " text-3xl border-b border-zenith-border pb-4 mb-6 mt-8 first:mt-0";
    if (level === 2) classes += " text-2xl mt-8 mb-4 flex items-center gap-2 before:content-['#'] before:text-zenith-orange/50 before:font-mono before:text-lg";
    if (level === 3) classes += " text-xl font-semibold mt-6 mb-3";
    if (level === 4) classes += " text-lg font-semibold mt-6 mb-2";

    return React.createElement(Tag, { ...props, id: slug, className: classes }, children);
  };

  return (
    <div className="flex flex-col gap-6">
      {frontmatter && Object.keys(frontmatter).length > 0 && (
        <div className="bg-zenith-surface border border-zenith-border p-4 mb-4 font-mono text-xs">
          <div className="text-zenith-muted uppercase tracking-widest mb-2 border-b border-zenith-border pb-1">Metadata</div>
          <div className="grid grid-cols-[100px_1fr] gap-y-1">
            {Object.entries(frontmatter).map(([k, v]) => (
              <React.Fragment key={k}>
                <span className="text-zenith-orange">{k}</span>
                <span className="text-zenith-text break-all">{v}</span>
              </React.Fragment>
            ))}
          </div>
        </div>
      )}

      <div className="prose prose-invert prose-sm max-w-none font-sans">
        <ReactMarkdown 
          remarkPlugins={[remarkGfm]}
          components={{
            code({node, inline, className, children, ...props}: any) {
              const match = /language-(\w+)/.exec(className || '')
              return !inline && match ? (
                <div className="bg-zenith-surface border border-zenith-border my-4 group relative">
                  <div className="bg-zenith-border/30 px-3 py-1 text-[10px] font-mono text-zenith-muted uppercase border-b border-zenith-border flex justify-between items-center">
                    <span>{match[1]}</span>
                  </div>
                  <SyntaxHighlighter
                    {...props}
                    style={vscDarkPlus}
                    language={match[1]}
                    PreTag="div"
                    customStyle={{ background: 'transparent', padding: '1rem', fontSize: '0.875rem' }}
                  >
                    {String(children).replace(/\n$/, '')}
                  </SyntaxHighlighter>
                </div>
              ) : (
                <code className="bg-zenith-surface border border-zenith-border px-1.5 py-0.5 rounded-none text-xs font-mono text-zenith-orange break-words" {...props}>
                  {children}
                </code>
              )
            },
            h1: ({node, children, ...props}) => <HeaderRenderer level={1} children={children} {...props} />,
            h2: ({node, children, ...props}) => <HeaderRenderer level={2} children={children} {...props} />,
            h3: ({node, children, ...props}) => <HeaderRenderer level={3} children={children} {...props} />,
            h4: ({node, children, ...props}) => <HeaderRenderer level={4} children={children} {...props} />,
            p: ({node, ...props}) => <p className="text-zenith-text leading-7 mb-4" {...props} />,
            blockquote: ({node, ...props}) => <blockquote className="border-l-2 border-zenith-orange pl-4 bg-zenith-surface/30 py-2 pr-2 text-zenith-muted italic my-6" {...props} />,

            // Lists
            ul: ({node, ...props}) => <ul className="list-disc list-outside ml-5 my-4 space-y-2 marker:text-zenith-orange text-zenith-text" {...props} />,
            ol: ({node, ...props}) => <ol className="list-decimal list-outside ml-5 my-4 space-y-2 marker:text-zenith-orange text-zenith-text" {...props} />,
            li: ({node, ...props}) => <li className="pl-1" {...props} />,

            // Links & Formatting
            a: ({node, ...props}) => <a className="text-zenith-orange hover:text-white underline decoration-zenith-orange/50 hover:decoration-white underline-offset-4 transition-colors cursor-pointer" {...props} />,
            hr: ({node, ...props}) => <hr className="border-zenith-border my-8" {...props} />,
            img: ({node, ...props}) => <img className="max-w-full border border-zenith-border my-6 bg-black/50" {...props} />,
            strong: ({node, ...props}) => <strong className="font-bold text-white" {...props} />,
            em: ({node, ...props}) => <em className="italic text-zenith-text/80" {...props} />,
            del: ({node, ...props}) => <del className="line-through text-zenith-muted" {...props} />,

            // Tables (GFM)
            table: ({node, ...props}) => (
              <div className="overflow-x-auto my-8 border border-zenith-border">
                <table className="w-full text-left border-collapse text-sm" {...props} />
              </div>
            ),
            thead: ({node, ...props}) => <thead className="bg-zenith-surface border-b border-zenith-border" {...props} />,
            tbody: ({node, ...props}) => <tbody className="divide-y divide-zenith-border bg-black/20" {...props} />,
            tr: ({node, ...props}) => <tr className="hover:bg-white/5 transition-colors" {...props} />,
            th: ({node, ...props}) => <th className="p-3 font-mono text-xs font-bold uppercase tracking-wider text-zenith-muted select-none" {...props} />,
            td: ({node, ...props}) => <td className="p-3 text-zenith-text border-r border-zenith-border last:border-r-0 whitespace-nowrap md:whitespace-normal" {...props} />,
          }}
        >
          {displayContent}
        </ReactMarkdown>
      </div>
    </div>
  );
};

export default MarkdownPreview;

import React, { useState, useRef, useEffect } from 'react';
import { Icons } from './Icon';
import { Repository } from '../types';
// @ts-ignore
import TurndownService from 'turndown';
// @ts-ignore
import { gfm } from 'turndown-plugin-gfm';

interface QuickCaptureProps {
  repos: Repository[];
  onQuickSave: (repoId: string, title: string, content: string) => Promise<void>;
  onCreateRepo: (name: string) => Promise<string | null>;
}

const QuickCapture: React.FC<QuickCaptureProps> = ({ repos, onQuickSave, onCreateRepo }) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [content, setContent] = useState('');
  const [title, setTitle] = useState('');
  const [selectedRepoId, setSelectedRepoId] = useState('');
  const [isCreatingRepo, setIsCreatingRepo] = useState(false);
  const [newRepoName, setNewRepoName] = useState('');
  const [isSaving, setIsSaving] = useState(false);
  const [conversionStatus, setConversionStatus] = useState<string | null>(null);

  const textAreaRef = useRef<HTMLTextAreaElement>(null);

  // Auto-resize logic
  useEffect(() => {
    if (textAreaRef.current && isExpanded) {
        // Reset height to auto to correctly calculate shrink
        textAreaRef.current.style.height = 'auto';
        // Set to scrollHeight
        textAreaRef.current.style.height = `${textAreaRef.current.scrollHeight}px`;
    }
  }, [content, isExpanded]);

  const handleSave = async () => {
    if (!content.trim()) return;
    setIsSaving(true);

    try {
      let targetRepoId = selectedRepoId;

      // Logic: If no repo selected, default to the first one, or create a 'General' one
      if (!targetRepoId && !isCreatingRepo) {
        if (repos.length > 0) {
          targetRepoId = repos[0].id;
        } else {
            // Auto create general if absolutely no repos exist
            const id = await onCreateRepo('general-notes');
            if (id) targetRepoId = id;
        }
      }

      // Logic: If user opted to create new repo
      if (isCreatingRepo && newRepoName.trim()) {
        const id = await onCreateRepo(newRepoName);
        if (id) targetRepoId = id;
      }

      // Generate Title if empty
      let finalTitle = title.trim();
      if (!finalTitle) {
         const dateStr = new Date().toISOString().split('T')[0];
         const snippet = content.slice(0, 15).replace(/\n/g, ' ').trim();
         finalTitle = snippet ? `${snippet}... (${dateStr}).md` : `note-${dateStr}.md`;
      }
      if (!finalTitle.endsWith('.md')) finalTitle += '.md';

      if (targetRepoId) {
          await onQuickSave(targetRepoId, finalTitle, content);
          // Reset
          setContent('');
          setTitle('');
          setIsExpanded(false);
          setIsCreatingRepo(false);
          setNewRepoName('');
      }
    } catch (e) {
        console.error("Capture failed", e);
        alert("Transmission failed. Check network.");
    } finally {
        setIsSaving(false);
    }
  };

  const insertTextAtCursor = (textToInsert: string) => {
      if (!textAreaRef.current) return;
      const start = textAreaRef.current.selectionStart;
      const end = textAreaRef.current.selectionEnd;
      const currentText = textAreaRef.current.value;
      const before = currentText.substring(0, start);
      const after = currentText.substring(end);

      const newText = before + textToInsert + after;
      setContent(newText);

      setTimeout(() => {
          if (textAreaRef.current) {
              textAreaRef.current.focus();
              const newCursorPos = start + textToInsert.length;
              textAreaRef.current.selectionStart = newCursorPos;
              textAreaRef.current.selectionEnd = newCursorPos;
          }
      }, 0);
  };

  const handlePaste = (e: React.ClipboardEvent<HTMLTextAreaElement>) => {
    const clipboardData = e.clipboardData;
    const types = clipboardData.types;

    if (types.includes('text/html')) {
        const html = clipboardData.getData('text/html');

        try {
            e.preventDefault(); 

            // Robust Constructor Resolution for Vite/Rollup compatibility
            let ServiceClass = TurndownService;
            // @ts-ignore
            if (typeof ServiceClass !== 'function' && ServiceClass.default) {
                // @ts-ignore
                ServiceClass = ServiceClass.default;
            }

            if (typeof ServiceClass !== 'function') {
                // Fallback if library fails to load, just let default paste happen or insert plain text
                throw new Error("TurndownService constructor not found");
            }

            // @ts-ignore
            const turndownService = new ServiceClass({
                headingStyle: 'atx',
                codeBlockStyle: 'fenced',
                bulletListMarker: '-',
                emDelimiter: '*',
                hr: '***' // Use asterisks for HR to avoid conflict with Frontmatter '---'
            });

            // Try to use GFM plugin
            try {
                if (typeof gfm === 'function') {
                    turndownService.use(gfm);
                }
            } catch (e) {
                console.warn("GFM plugin failed", e);
            }

            // Pure Text Mode: Remove images
            turndownService.remove('img');
            turndownService.remove('picture'); 

            // Custom rule for pre tags
            turndownService.addRule('pre', {
                filter: ['pre'],
                replacement: function (content: string, node: any) {
                     return '\n```\n' + node.textContent + '\n```\n';
                }
            });

            // Force HR rule to be asterisks
            turndownService.addRule('horizontalRule', {
                filter: 'hr',
                replacement: function () {
                    return '\n\n***\n\n';
                }
            });

            const markdown = turndownService.turndown(html);

            setConversionStatus("SMART PASTE: TEXT ONLY");
            setTimeout(() => setConversionStatus(null), 3000);

            insertTextAtCursor(markdown);

        } catch (err) {
            console.error("Paste Error:", err);
            const plainText = clipboardData.getData('text/plain');
            insertTextAtCursor(plainText);

            setConversionStatus("PASTE: PLAIN TEXT");
            setTimeout(() => setConversionStatus(null), 3000);
        }
    }
  };

  return (
    <div className={`mb-12 border transition-all duration-300 relative ${isExpanded ? 'bg-zenith-surface border-zenith-orange shadow-[0_0_20px_rgba(255,77,0,0.15)]' : 'bg-black border-zenith-border hover:border-zenith-light'}`}>

      {/* Toast Notification (Scoped to this component) */}
      {conversionStatus && (
          <div className="absolute -top-10 right-0 z-50 animate-in slide-in-from-bottom-2 duration-300">
              <div className="bg-zenith-surface border border-zenith-orange px-3 py-1.5 shadow-lg flex items-center gap-2">
                  <div className="bg-zenith-orange text-black p-0.5">
                      <Icons.Zap size={10} />
                  </div>
                  <span className="font-mono text-white font-bold text-[10px] tracking-widest uppercase">
                      {conversionStatus}
                  </span>
              </div>
          </div>
      )}

      {/* Collapsed View (Input Trigger) */}
      {!isExpanded && (
        <div 
            onClick={() => setIsExpanded(true)}
            className="p-4 flex items-center gap-4 cursor-text"
        >
            <div className="text-zenith-orange animate-pulse">
                <Icons.Edit size={18} />
            </div>
            <span className="font-mono text-zenith-muted text-sm tracking-wide">
                INITIATE QUICK CAPTURE PROTOCOL...
            </span>
        </div>
      )}

      {/* Expanded View */}
      {isExpanded && (
        <div className="p-6">
            <div className="flex items-center justify-between mb-4 border-b border-zenith-border pb-2">
                <span className="font-mono text-xs text-zenith-orange tracking-widest uppercase flex items-center gap-2">
                    <Icons.Zap size={12} /> Live Uplink
                </span>
                <button onClick={() => setIsExpanded(false)} className="text-zenith-muted hover:text-white">
                    <Icons.Close size={16} />
                </button>
            </div>

            <div className="space-y-4">
                <textarea 
                    ref={textAreaRef}
                    autoFocus
                    value={content}
                    onChange={e => setContent(e.target.value)}
                    onPaste={handlePaste}
                    placeholder="Enter raw data stream... (Auto-converts to clean Markdown, images removed)"
                    className="w-full bg-black border border-zenith-border p-4 text-white font-mono text-sm focus:border-zenith-orange focus:outline-none min-h-[120px] max-h-[60vh] overflow-hidden resize-none"
                    style={{ height: 'auto' }}
                />

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <input 
                        type="text"
                        value={title}
                        onChange={e => setTitle(e.target.value)}
                        placeholder="Filename (Optional)"
                        className="bg-black border border-zenith-border p-2 text-white font-mono text-xs focus:border-zenith-orange focus:outline-none"
                    />

                    <div className="relative">
                        {!isCreatingRepo ? (
                            <div className="flex gap-2">
                                <select 
                                    value={selectedRepoId}
                                    onChange={e => {
                                        if(e.target.value === 'NEW') {
                                            setIsCreatingRepo(true);
                                        } else {
                                            setSelectedRepoId(e.target.value);
                                        }
                                    }}
                                    className="flex-1 bg-black border border-zenith-border p-2 text-white font-mono text-xs focus:border-zenith-orange focus:outline-none appearance-none"
                                >
                                    <option value="" disabled>Select Target Module</option>
                                    {repos.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                                    <option value="NEW" className="text-zenith-orange">[+ CREATE NEW MODULE]</option>
                                </select>
                                <div className="absolute right-2 top-2.5 pointer-events-none text-zenith-muted">
                                    <Icons.ChevronRight size={12} className="rotate-90" />
                                </div>
                            </div>
                        ) : (
                            <div className="flex gap-2">
                                <input 
                                    type="text"
                                    value={newRepoName}
                                    onChange={e => setNewRepoName(e.target.value)}
                                    placeholder="New Module Name"
                                    className="flex-1 bg-black border border-zenith-orange p-2 text-zenith-orange font-mono text-xs focus:outline-none placeholder:text-zenith-orange/50"
                                />
                                <button 
                                    onClick={() => setIsCreatingRepo(false)}
                                    className="p-2 border border-zenith-border text-zenith-muted hover:text-white"
                                >
                                    <Icons.Close size={14} />
                                </button>
                            </div>
                        )}
                    </div>
                </div>

                <div className="flex justify-end pt-2">
                    <button 
                        onClick={handleSave}
                        disabled={isSaving || !content.trim()}
                        className={`bg-zenith-orange text-black px-6 py-2 text-xs font-bold font-mono tracking-widest uppercase hover:bg-white transition-colors flex items-center gap-2 ${isSaving ? 'opacity-50 cursor-wait' : ''}`}
                    >
                        {isSaving ? 'Transmitting...' : (
                            <>
                                <Icons.Upload size={14} /> Commit Data
                            </>
                        )}
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default QuickCapture;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { Repository } from '../types';
import { Icons } from '../components/Icon';
import MarkdownPreview, { generateSlug } from '../components/MarkdownPreview';
import DeleteConfirmModal from '../components/DeleteConfirmModal';
import EditorToolbar from '../components/EditorToolbar';
// Use default import for Turndown, but handle 'default' property at runtime if needed
// @ts-ignore
import TurndownService from 'turndown';
// Use named import for gfm plugin
// @ts-ignore
import { gfm } from 'turndown-plugin-gfm';

interface FileEditorProps {
  repos: Repository[];
  onUpdateFile: (repoId: string, fileId: string, newContent: string) => void;
  onDeleteFile: (repoId: string, fileId: string) => void;
  isAuthenticated: boolean;
}

type ViewMode = 'write' | 'preview' | 'split';

interface TocItem {
  id: string;
  text: string;
  level: number;
}

const FileEditor: React.FC<FileEditorProps> = ({ repos, onUpdateFile, onDeleteFile, isAuthenticated }) => {
  const { repoId, fileId } = useParams<{ repoId: string; fileId: string }>();
  const navigate = useNavigate();
  const textAreaRef = useRef<HTMLTextAreaElement>(null);

  const repo = repos.find(r => r.id === repoId);
  const file = repo?.files.find(f => f.id === fileId);

  const [viewMode, setViewMode] = useState<ViewMode>('preview');
  const [content, setContent] = useState('');
  const [hasChanges, setHasChanges] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [conversionStatus, setConversionStatus] = useState<string | null>(null);

  useEffect(() => {
    if (file) {
      setContent(file.content);
    }
  }, [file]);

  // --- Table of Contents Logic ---
  const toc = useMemo(() => {
    if (!content) return [];

    // Regex to match # Heading, ## Heading etc.
    const headingRegex = /^(#{1,3})\s+(.+)$/gm;
    const items: TocItem[] = [];

    const lines = content.split('\n');
    let inCodeBlock = false;

    lines.forEach(line => {
        if (line.trim().startsWith('```')) {
            inCodeBlock = !inCodeBlock;
            return;
        }
        if (inCodeBlock) return;

        const headingMatch = line.match(/^(#{1,3})\s+(.+)$/);
        if (headingMatch) {
            const level = headingMatch[1].length;
            const text = headingMatch[2].trim();
            // Remove markdown links or bold from TOC text if present
            const cleanText = text.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1').replace(/(\*\*|__)(.*?)\1/g, '$2');

            items.push({
                id: generateSlug(cleanText),
                text: cleanText,
                level
            });
        }
    });

    return items;
  }, [content]);

  if (!repo || !file) {
    return <div className="h-screen flex items-center justify-center font-mono text-zenith-orange">ERROR: FILE DATA CORRUPTED OR MISSING</div>;
  }

  const handleSave = () => {
    if (!isAuthenticated) return;
    onUpdateFile(repoId!, fileId!, content);
    setHasChanges(false);
  };

  const handleContentChange = (val: string) => {
      setContent(val);
      setHasChanges(val !== file.content);
  }

  const handleDeleteConfirm = () => {
      if (!isAuthenticated) return;
      onDeleteFile(repoId!, fileId!);
      navigate(`/${repoId}`);
  }

  const handleInsert = (prefix: string, suffix: string = '') => {
    if (!textAreaRef.current) return;
    const start = textAreaRef.current.selectionStart;
    const end = textAreaRef.current.selectionEnd;
    const text = textAreaRef.current.value;
    const before = text.substring(0, start);
    const selection = text.substring(start, end);
    const after = text.substring(end);

    const newText = before + prefix + selection + suffix + after;
    handleContentChange(newText);

    // Defer focus to allow React render
    setTimeout(() => {
      if(textAreaRef.current) {
        textAreaRef.current.focus();
        textAreaRef.current.selectionStart = start + prefix.length;
        textAreaRef.current.selectionEnd = end + prefix.length;
      }
    }, 0);
  };

  const insertTextAtCursor = (textToInsert: string) => {
      if (!textAreaRef.current) return;
      const start = textAreaRef.current.selectionStart;
      const end = textAreaRef.current.selectionEnd;
      const currentText = textAreaRef.current.value;
      const before = currentText.substring(0, start);
      const after = currentText.substring(end);

      const newText = before + textToInsert + after;
      handleContentChange(newText);

      setTimeout(() => {
          if (textAreaRef.current) {
              textAreaRef.current.focus();
              const newCursorPos = start + textToInsert.length;
              textAreaRef.current.selectionStart = newCursorPos;
              textAreaRef.current.selectionEnd = newCursorPos;
          }
      }, 0);
  };

  const handlePaste = (e: React.ClipboardEvent<HTMLTextAreaElement>) => {
    if (!isAuthenticated) return;

    const clipboardData = e.clipboardData;
    const types = clipboardData.types;

    // Check for HTML content
    if (types.includes('text/html')) {
        const html = clipboardData.getData('text/html');

        try {
            e.preventDefault(); 

            // 1. Robust Constructor Resolution
            let ServiceClass = TurndownService;
            // @ts-ignore
            if (typeof ServiceClass !== 'function' && ServiceClass.default) {
                // @ts-ignore
                ServiceClass = ServiceClass.default;
            }

            if (typeof ServiceClass !== 'function') {
                throw new Error("Could not find TurndownService constructor.");
            }

            // 2. Initialize Service
            // @ts-ignore
            const turndownService = new ServiceClass({
                headingStyle: 'atx',
                codeBlockStyle: 'fenced',
                bulletListMarker: '-',
                emDelimiter: '*',
                hr: '***' // Use asterisks to avoid Frontmatter conflicts
            });

            // 3. Robust Plugin Loading (Fail-safe)
            try {
                if (typeof gfm === 'function') {
                    turndownService.use(gfm);
                } else {
                    console.warn("GitNotes Warning: GFM plugin not available, skipping tables support.");
                }
            } catch (pluginErr) {
                console.warn("GitNotes Warning: Error applying GFM plugin, continuing with basic markdown.", pluginErr);
            }

            // Pure Text Mode: Remove images
            turndownService.remove('img');
            turndownService.remove('picture');

            // 4. Custom Rules
            turndownService.addRule('pre', {
                filter: ['pre'],
                replacement: function (content: string, node: any) {
                     return '\n```\n' + node.textContent + '\n```\n';
                }
            });

             // Force HR rule to be asterisks here too
             turndownService.addRule('horizontalRule', {
                filter: 'hr',
                replacement: function () {
                    return '\n\n***\n\n';
                }
            });

            // 5. Execute Conversion
            const markdown = turndownService.turndown(html);

            // Visual Feedback
            setConversionStatus("SMART PASTE: TEXT ONLY");
            setTimeout(() => setConversionStatus(null), 3000);

            insertTextAtCursor(markdown);

        } catch (err) {
            console.error("GitNotes Paste Error:", err);

            // Fallback: manually insert the plain text since we prevented default
            const plainText = clipboardData.getData('text/plain');
            insertTextAtCursor(plainText);

            setConversionStatus("PASTE FALLBACK: PLAIN TEXT");
            setTimeout(() => setConversionStatus(null), 3000);
        }
        return;
    }
  };

  const lineCount = content.split('\n').length;

  return (
    <div className="h-[calc(100vh-56px)] flex flex-col bg-zenith-bg relative">

      {/* Toast Notification (Fixed Position) */}
      {conversionStatus && (
          <div className="fixed bottom-12 right-6 z-50 animate-in slide-in-from-bottom-5 duration-300">
              <div className="bg-zenith-surface border border-zenith-orange px-4 py-3 shadow-[0_0_15px_rgba(255,77,0,0.2)] flex items-center gap-3">
                  <div className="bg-zenith-orange text-black p-1">
                      <Icons.Zap size={14} />
                  </div>
                  <span className="font-mono text-white font-bold text-xs tracking-widest uppercase">
                      {conversionStatus}
                  </span>
              </div>
          </div>
      )}

      {/* File Toolbar */}
      <div className="h-14 border-b border-zenith-border bg-zenith-bg flex items-center justify-between px-6 shrink-0 relative z-10">
          <div className="flex items-center gap-4">
              <Link to={`/${repoId}`} className="text-zenith-muted hover:text-white transition-colors">
                  <Icons.ChevronRight className="rotate-180" size={18} />
              </Link>
              <div className="h-6 w-px bg-zenith-border"></div>
              <span className="font-mono text-sm text-white font-bold tracking-wide">{file.name}</span>
              {hasChanges && <span className="text-[10px] bg-zenith-orange text-black px-2 py-0.5 font-bold font-mono">UNSAVED</span>}
              {!isAuthenticated && <span className="text-[10px] border border-zenith-border text-zenith-muted px-2 py-0.5 font-mono uppercase">Read Only</span>}
          </div>

          <div className="flex items-center gap-3">
             {/* Mode Switcher */}
             <div className="flex border border-zenith-border p-0.5 bg-zenith-surface">
                 <button 
                    onClick={() => setViewMode('write')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'write' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Write Mode"
                 >
                    <Icons.Edit size={12} /> <span className="hidden sm:inline">Write</span>
                 </button>
                 <button 
                    onClick={() => setViewMode('split')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 border-l border-r border-zenith-border ${viewMode === 'split' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Split View"
                 >
                    <Icons.Layout size={12} /> <span className="hidden sm:inline">Split</span>
                 </button>
                 <button 
                    onClick={() => setViewMode('preview')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'preview' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Preview Mode"
                 >
                    <Icons.File size={12} /> <span className="hidden sm:inline">Render</span>
                 </button>
             </div>

             {isAuthenticated && (
                <>
                 <button 
                    onClick={handleSave}
                    disabled={!hasChanges}
                    className={`flex items-center gap-2 px-4 py-2 border text-xs font-mono tracking-widest uppercase transition-colors ${hasChanges ? 'border-zenith-orange text-zenith-orange hover:bg-zenith-orange hover:text-black' : 'border-zenith-border text-zenith-muted cursor-not-allowed'}`}
                 >
                    <Icons.Save size={14} /> Save
                 </button>

                 <button onClick={() => setIsDeleteModalOpen(true)} className="p-2 text-zenith-muted hover:text-red-600 transition-colors">
                     <Icons.Trash size={16} />
                 </button>
                </>
             )}
          </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-hidden relative flex z-0">

         {/* Write Panel */}
         {(viewMode === 'write' || viewMode === 'split') && (
           <div className={`flex flex-col border-r border-zenith-border ${viewMode === 'split' ? 'w-1/2' : 'w-full'}`}>
             {isAuthenticated && <EditorToolbar onInsert={handleInsert} />}
             <div className="flex flex-1 overflow-hidden">
                {/* Line Numbers */}
                <div className="hidden sm:block w-10 bg-zenith-surface border-r border-zenith-border text-right py-4 pr-2 font-mono text-xs text-zenith-border select-none overflow-hidden shrink-0">
                    {Array.from({length: Math.max(lineCount, 20)}).map((_, i) => <div key={i}>{i+1}</div>)}
                </div>

                <textarea
                    ref={textAreaRef}
                    readOnly={!isAuthenticated}
                    value={content}
                    onChange={(e) => handleContentChange(e.target.value)}
                    onPaste={handlePaste}
                    className={`w-full h-full bg-zenith-bg text-zenith-text font-mono text-sm p-4 resize-none outline-none transition-colors leading-relaxed ${!isAuthenticated ? 'cursor-not-allowed text-zenith-muted' : 'focus:bg-[#050505]'}`}
                    spellCheck={false}
