  createRepo: async (name: string, description: string, isPrivate: boolean): Promise<Repository> => {
    const repos = localProvider.getData();
    const newRepo: Repository = {
      id: uuidv4(),
      name,
      description,
      isPrivate,
      updatedAt: new Date().toISOString(),
      stars: 0,
