export default RepositoryView;

import { supabase, getAuthenticatedClient, isSupabaseConfigured } from '../lib/supabase';
import { Repository, FileItem } from '../types';
import { INITIAL_REPOS } from '../constants';
import { v4 as uuidv4 } from 'uuid';

// --- Types & Mappers ---

const mapRepo = (r: any): Repository => ({
  id: r.id,
  name: r.name,
  description: r.description,
  isPrivate: r.is_private,
  updatedAt: r.updated_at,
  stars: r.stars,
  language: r.language,
  files: r.files ? r.files.map(mapFile) : []
});

const mapFile = (f: any): FileItem => ({
  id: f.id,
  name: f.name,
  content: f.content,
  language: f.language,
  size: f.size,
  updatedAt: f.updated_at
});

// --- LocalStorage Fallback Implementation ---
const LOCAL_KEY = 'gitnotes_offline_v2';

const localProvider = {
  getData: (): Repository[] => {
    try {
      const stored = localStorage.getItem(LOCAL_KEY);
      if (!stored) {
        localStorage.setItem(LOCAL_KEY, JSON.stringify(INITIAL_REPOS));
        return INITIAL_REPOS;
      }
      return JSON.parse(stored);
    } catch {
      return INITIAL_REPOS;
    }
  },

  saveData: (data: Repository[]) => {
    localStorage.setItem(LOCAL_KEY, JSON.stringify(data));
  },

  getRepos: async (): Promise<Repository[]> => {
    await new Promise(r => setTimeout(r, 300));
    return localProvider.getData();
  },

  createRepo: async (name: string, description: string, isPrivate: boolean): Promise<Repository> => {
    const repos = localProvider.getData();
    const newRepo: Repository = {
      id: uuidv4(),
      name,
      description,
      isPrivate,
      updatedAt: new Date().toISOString(),
      stars: 0,
      language: 'Markdown',
      files: []
    };
    localProvider.saveData([newRepo, ...repos]);
    return newRepo;
  },

  updateRepo: async (repoId: string, name: string, description: string) => {
    const repos = localProvider.getData();
    const updated = repos.map(r => r.id === repoId ? { ...r, name, description, updatedAt: new Date().toISOString() } : r);
    localProvider.saveData(updated);
  },

  deleteRepo: async (repoId: string) => {
    const repos = localProvider.getData();
    localProvider.saveData(repos.filter(r => r.id !== repoId));
  },

  addFile: async (repoId: string, name: string, content: string, customDate?: string): Promise<FileItem | null> => {
    const repos = localProvider.getData();
    const repoIndex = repos.findIndex(r => r.id === repoId);
    if (repoIndex === -1) return null;

    const timestamp = customDate ? new Date(customDate).toISOString() : new Date().toISOString();

    const newFile: FileItem = {
      id: uuidv4(),
      name,
      content,
      language: 'markdown',
      size: new Blob([content]).size,
      updatedAt: timestamp
    };

    repos[repoIndex].files.unshift(newFile);

    if (!customDate) {
        repos[repoIndex].updatedAt = timestamp;
    }

    localProvider.saveData(repos);
    return newFile;
  },

  renameFile: async (repoId: string, fileId: string, newName: string) => {
      const repos = localProvider.getData();
      let found = false;
      const updatedRepos = repos.map(repo => {
          if (repo.id === repoId) {
              const fileIndex = repo.files.findIndex(f => f.id === fileId);
              if (fileIndex !== -1) {
                  repo.files[fileIndex] = {
                      ...repo.files[fileIndex],
                      name: newName,
                      updatedAt: new Date().toISOString()
                  };
                  repo.updatedAt = new Date().toISOString();
                  found = true;
              }
          }
          return repo;
      });
      if (found) localProvider.saveData(updatedRepos);
  },

  updateFile: async (fileId: string, content: string) => {
    const repos = localProvider.getData();
    let found = false;

    const updatedRepos = repos.map(repo => {
      const fileIndex = repo.files.findIndex(f => f.id === fileId);
      if (fileIndex !== -1) {
        repo.files[fileIndex] = {
          ...repo.files[fileIndex],
          content,
          size: new Blob([content]).size,
          updatedAt: new Date().toISOString()
        };
        repo.updatedAt = new Date().toISOString();
        found = true;
      }
      return repo;
    });

    if (found) localProvider.saveData(updatedRepos);
  },

  deleteFile: async (fileId: string) => {
    const repos = localProvider.getData();
    const updatedRepos = repos.map(repo => ({
      ...repo,
      files: repo.files.filter(f => f.id !== fileId)
    }));
    localProvider.saveData(updatedRepos);
  }
};


// --- Public API ---

export const api = {
  getRepos: async (secretKey: string): Promise<Repository[]> => {
    const client = getAuthenticatedClient(secretKey);
    if (!client) return localProvider.getRepos();

    // Use secretKey as ownerId
    const { data, error } = await client
      .from('repositories')
      .select('*, files(*)')
      .eq('owner_id', secretKey)
      .order('updated_at', { ascending: false });

    if (error) {
      console.error('Error fetching repos:', error);
      throw error;
    }

    const repos = data.map(mapRepo);
    repos.forEach(r => {
        r.files.sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime());
    });

    return repos;
  },

  createRepo: async (secretKey: string, name: string, description: string, isPrivate: boolean): Promise<Repository | null> => {
    const client = getAuthenticatedClient(secretKey);
    if (!client) return localProvider.createRepo(name, description, isPrivate);

    const { data, error } = await client
      .from('repositories')
      .insert([{ owner_id: secretKey, name, description, is_private: isPrivate }])
      .select()
      .single();

    if (error) throw error;
    return { ...mapRepo(data), files: [] };
  },

  updateRepo: async (secretKey: string, repoId: string, name: string, description: string) => {
    const client = getAuthenticatedClient(secretKey);
    if (!client) return localProvider.updateRepo(repoId, name, description);

    const { error } = await client
      .from('repositories')
      .update({ name, description, updated_at: new Date().toISOString() })
      .eq('id', repoId);
    if (error) throw error;
  },

  deleteRepo: async (secretKey: string, repoId: string) => {
    const client = getAuthenticatedClient(secretKey);
    if (!client) return localProvider.deleteRepo(repoId);

    const { error } = await client.from('repositories').delete().eq('id', repoId);
    if (error) throw error;
  },

  addFile: async (secretKey: string, repoId: string, name: string, content: string, customDate?: string): Promise<FileItem | null> => {
    const client = getAuthenticatedClient(secretKey);
    if (!client) return localProvider.addFile(repoId, name, content, customDate);

    const size = new Blob([content]).size;
    const timestamp = customDate ? new Date(customDate).toISOString() : new Date().toISOString();

    const { data, error } = await client
      .from('files')
      .insert([{ 
        repo_id: repoId, 
        owner_id: secretKey,
        name, 
        content, 
        size,
        updated_at: timestamp 
      }])
      .select()
      .single();

    if (error) throw error;

    if (!customDate) {
        await client.from('repositories').update({ updated_at: new Date().toISOString() }).eq('id', repoId);
    }

    return mapFile(data);
  },

  renameFile: async (secretKey: string, repoId: string, fileId: string, newName: string) => {
      const client = getAuthenticatedClient(secretKey);
      if (!client) return localProvider.renameFile(repoId, fileId, newName);

      const { error } = await client
        .from('files')
        .update({ name: newName, updated_at: new Date().toISOString() })
        .eq('id', fileId);

      if (error) throw error;
  },

  updateFile: async (secretKey: string, fileId: string, content: string) => {
    const client = getAuthenticatedClient(secretKey);
    if (!client) return localProvider.updateFile(fileId, content);

    const size = new Blob([content]).size;
    const { error } = await client
      .from('files')
      .update({ content, size, updated_at: new Date().toISOString() })
      .eq('id', fileId);
    if (error) throw error;
  },

  deleteFile: async (secretKey: string, fileId: string) => {
    const client = getAuthenticatedClient(secretKey);
    if (!client) return localProvider.deleteFile(fileId);

    const { error } = await client.from('files').delete().eq('id', fileId);
    if (error) throw error;
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { HashRouter as Router, Routes, Route } from 'react-router-dom';
import Header from './components/Header';
import Dashboard from './pages/Dashboard';
import RepositoryView from './pages/RepositoryView';
import FileEditor from './pages/FileEditor';
import AccessGate from './components/AccessGate';
import SocialBar from './components/SocialBar';
import GlobalSearch from './components/GlobalSearch';
import { api } from './services/dataService';
import { Repository } from './types';
import { Icons } from './components/Icon';

type Theme = 'orange' | 'green' | 'blue';

function App() {
  const [repos, setRepos] = useState<Repository[]>([]);
  const [loading, setLoading] = useState(false);
  const [secretKey, setSecretKey] = useState<string | null>(null);

  // Ref to track the art repo ID across async calls/stale closures
  const artRepoIdRef = useRef<string | null>(null);

  // Theme State
  const [theme, setTheme] = useState<Theme>(() => {
      return (localStorage.getItem('gitnotes_theme') as Theme) || 'orange';
  });

  // Apply Theme
  useEffect(() => {
      document.documentElement.setAttribute('data-theme', theme);
      localStorage.setItem('gitnotes_theme', theme);
  }, [theme]);

  // New Modals
  const [isSearchOpen, setIsSearchOpen] = useState(false);

  // Load Data function
  const loadData = useCallback(async (key: string) => {
      setLoading(true);
      try {
          const data = await api.getRepos(key);
          setRepos(data);
      } catch (e) {
          console.error("Sync failed", e);
      } finally {
          setLoading(false);
      }
  }, []);

  // Sync ref with state when data loads
  useEffect(() => {
      const artRepo = repos.find(r => r.name === 'contribution-art');
      if (artRepo) {
          artRepoIdRef.current = artRepo.id;
      }
  }, [repos]);

  // Initial Auth Check is handled by AccessGate, which calls handleUnlock
  const handleUnlock = (key: string) => {
      setSecretKey(key);
      loadData(key);
  };

  const handleLogout = () => {
      localStorage.removeItem('gitnotes_secret_key');
      setSecretKey(null);
      setRepos([]);
      artRepoIdRef.current = null;
  };

  // Explicit Sync Action for Button
  const handleSync = () => {
      if (secretKey) loadData(secretKey);
  };

  // Global Key Listener for Search
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        if (secretKey) setIsSearchOpen(true);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [secretKey]);

  // Actions wrapped for Supabase
  const handleCreateRepo = async (name: string, description: string, isPrivate: boolean) => {
    if (!secretKey) return null;
    const newRepo = await api.createRepo(secretKey, name, description, isPrivate);
    if (newRepo) {
        setRepos(prev => [newRepo, ...prev]);
        return newRepo.id;
    }
    return null;
  };

  const handleUpdateRepo = async (repoId: string, name: string, description: string) => {
    if (!secretKey) return;
    await api.updateRepo(secretKey, repoId, name, description);
    setRepos(prev => prev.map(r => r.id === repoId ? { ...r, name, description, updatedAt: new Date().toISOString() } : r));
  };

  const handleDeleteRepo = async (repoId: string) => {
      if (!secretKey) return;
      await api.deleteRepo(secretKey, repoId);
      setRepos(prev => prev.filter(r => r.id !== repoId));
      // Clear ref if we deleted the art repo
      if (repoId === artRepoIdRef.current) {
          artRepoIdRef.current = null;
      }
  }

  const handleAddFile = async (repoId: string, filename: string) => {
    if (!secretKey) return;
    const initialContent = `# ${filename.replace('.md', '')}\n\nFile created via Terminal.`;
    const newFile = await api.addFile(secretKey, repoId, filename, initialContent);

    if (newFile) {
        setRepos(prev => prev.map(repo => {
            if (repo.id === repoId) {
                return { ...repo, files: [...repo.files, newFile] };
            }
            return repo;
        }));
    }
  };

  const handleQuickSave = async (repoId: string, title: string, content: string) => {
      if (!secretKey) return;
      const newFile = await api.addFile(secretKey, repoId, title, content);
      if (newFile) {
          setRepos(prev => prev.map(repo => {
            if (repo.id === repoId) {
                return { ...repo, files: [newFile, ...repo.files], updatedAt: new Date().toISOString() }; // Add to top
            }
            return repo;
          }));
      }
  }

  const handleUpdateFile = async (repoId: string, fileId: string, newContent: string) => {
    if (!secretKey) return;
    await api.updateFile(secretKey, fileId, newContent);
    setRepos(prev => prev.map(repo => {
        if (repo.id === repoId) {
            return {
                ...repo,
                files: repo.files.map(f => f.id === fileId ? { ...f, content: newContent, updatedAt: new Date().toISOString() } : f)
            }
        }
        return repo;
    }));
  };

  const handleRenameFile = async (repoId: string, fileId: string, newName: string) => {
      if (!secretKey) return;

      const repo = repos.find(r => r.id === repoId);
      const file = repo?.files.find(f => f.id === fileId);

      if (!repo || !file) return;

      const oldName = file.name;
      const oldLinkName = oldName.replace('.md', '');
      const newLinkName = newName.replace('.md', '');

      // 1. Rename the file itself
      await api.renameFile(secretKey, repoId, fileId, newName);

      // 2. REFACTORING PROTOCOL: Update all other files in the same repo
      // Regex to find [[OldName]] or [[OldName.md]]
      // We escape the old name to prevent regex errors
      const escapeRegExp = (string: string) => string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); 
      const linkRegex = new RegExp(`\\[\\[${escapeRegExp(oldLinkName)}(?:\\.md)?\\]\\]`, 'g');

      // Optimistically update state
      setRepos(prev => prev.map(r => {
          if (r.id === repoId) {
             const updatedFiles = r.files.map(f => {
                 // Rename the target file
                 if (f.id === fileId) {
                     return { ...f, name: newName, updatedAt: new Date().toISOString() };
                 }

                 // Refactor links in other files
                 if (linkRegex.test(f.content)) {
                     const newContent = f.content.replace(linkRegex, `[[${newLinkName}]]`);
                     // Fire and forget update for these files to backend
                     api.updateFile(secretKey, f.id, newContent); 
                     return { ...f, content: newContent, updatedAt: new Date().toISOString() };
                 }

                 return f;
             });
             return { ...r, files: updatedFiles, updatedAt: new Date().toISOString() };
          }
          return r;
      }));
  };

  const handleDeleteFile = async (repoId: string, fileId: string) => {
      if (!secretKey) return;
      await api.deleteFile(secretKey, fileId);
      setRepos(prev => prev.map(repo => {
          if (repo.id === repoId) {
              return { ...repo, files: repo.files.filter(f => f.id !== fileId) };
          }
          return repo;
      }));
  }

  // --- Pixel Art Logic ---
  const handlePixelArt = async (date: string) => {
      if (!secretKey) return;

      // 1. Resolve Target Repo ID
      // We use a Ref here because this function is called in a loop (stamp mode)
      // inside ContributionGraph. The closure of this function might have a stale 'repos' state
      // if it was captured before the first repo creation finished.
      // The Ref ensures we always see the ID created in the previous iteration of the loop.
      let targetRepoId = artRepoIdRef.current || repos.find(r => r.name === 'contribution-art')?.id;

      if (!targetRepoId) {
          try {
              // Create hidden repo for art
              const newRepo = await api.createRepo(secretKey, 'contribution-art', 'Automated repository for contribution graph pixel art.', true);
              if (newRepo) {
                  targetRepoId = newRepo.id;
                  artRepoIdRef.current = newRepo.id; // CRITICAL: Update Ref immediately
                  setRepos(prev => [newRepo, ...prev]);
              } else {
                  console.error("Failed to initialize Pixel Art Module.");
                  return;
              }
          } catch (e) {
              console.error("Repo creation failed", e);
              return;
          }
      }

      // 2. Add Dummy File with specific date
      // We append a random ID to allow multiple commits per day (darker colors)
      const dummyName = `pixel-${date}-${Math.floor(Math.random() * 1000)}.md`;
      const dummyContent = `# Pixel Art Entry\n\nAutomated entry for visual data manipulation.\nDate: ${date}`;

      const newFile = await api.addFile(secretKey, targetRepoId, dummyName, dummyContent, date);

      if (newFile) {
          // Update local state to reflect change immediately in the graph
          setRepos(prev => prev.map(repo => {
              if (repo.id === targetRepoId) {
                  return { ...repo, files: [newFile, ...repo.files] };
              }
              return repo;
          }));
      }
  };

  // If not authenticated, show the Access Gate
  if (!secretKey) {
      return <AccessGate onUnlock={handleUnlock} />;
  }

  return (
    <Router>
      <div className="min-h-screen bg-zenith-bg text-zenith-text font-sans selection:bg-zenith-orange selection:text-black">
        <Header 
            secretKey={secretKey}
            onLogoutClick={handleLogout}
        />

        <Routes>
          <Route 
            path="/" 
            element={
                <Dashboard 
                    repos={repos} 
                    onCreateRepo={handleCreateRepo} 
                    onQuickSave={handleQuickSave}
                    onSync={handleSync}
                    isLoading={loading}
                    onPixelArt={handlePixelArt}
                />
            } 
          />
          <Route 
            path="/:repoId" 
            element={
                <RepositoryView 
                    repos={repos} 
                    onAddFile={handleAddFile}
                    onDeleteRepo={handleDeleteRepo}
                    onUpdateRepo={handleUpdateRepo}
                    onUpdateFile={handleUpdateFile}
                    isAuthenticated={true} 
                />
            } 
          />
          <Route 
            path="/:repoId/:fileId" 
            element={
                <FileEditor 
                    repos={repos} 
                    onUpdateFile={handleUpdateFile}
                    onRenameFile={handleRenameFile} 
                    onDeleteFile={handleDeleteFile}
                    isAuthenticated={true}
                />
            } 
          />
        </Routes>

        <footer className="mt-20 py-12 border-t border-zenith-border flex flex-col items-center gap-6 bg-zenith-bg/50">
            <SocialBar />

            {/* Theme Switcher */}
            <div className="flex items-center gap-4 bg-zenith-surface border border-zenith-border rounded-full px-4 py-2">
                <button 
                    onClick={() => setTheme('orange')} 
                    className={`w-3 h-3 rounded-full bg-[#FF4D00] transition-all duration-300 ${theme === 'orange' ? 'ring-2 ring-white scale-110 shadow-[0_0_10px_#FF4D00]' : 'opacity-40 hover:opacity-100 hover:scale-110'}`}
                    title="Zenith Orange"
                ></button>
                <button 
                    onClick={() => setTheme('green')} 
                    className={`w-3 h-3 rounded-full bg-[#00FF94] transition-all duration-300 ${theme === 'green' ? 'ring-2 ring-white scale-110 shadow-[0_0_10px_#00FF94]' : 'opacity-40 hover:opacity-100 hover:scale-110'}`}
                    title="Matrix Green"
                ></button>
                <button 
                    onClick={() => setTheme('blue')} 
                    className={`w-3 h-3 rounded-full bg-[#38BDF8] transition-all duration-300 ${theme === 'blue' ? 'ring-2 ring-white scale-110 shadow-[0_0_10px_#38BDF8]' : 'opacity-40 hover:opacity-100 hover:scale-110'}`}
                    title="Holo Blue"
                ></button>
            </div>

            <div className="text-[10px] tracking-widest text-zenith-muted font-mono uppercase flex items-center gap-4 opacity-60 hover:opacity-100 transition-opacity">
                <span className="text-zenith-green">WildSalt.Lab</span>
                <span className="w-px h-3 bg-zenith-muted"></span>
                <button onClick={() => setIsSearchOpen(true)} className="hover:text-white flex items-center gap-1"><Icons.Command size={10}/> CMD+K</button>
                <span className="w-px h-3 bg-zenith-muted"></span>
                <span className="">Ver: 3.1.0</span>
            </div>
        </footer>

        <GlobalSearch 
            isOpen={isSearchOpen}
            onClose={() => setIsSearchOpen(false)}
            repos={repos}
        />
      </div>
    </Router>
  );
}

export default App;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { Repository } from '../types';
import { Icons } from '../components/Icon';
import MarkdownPreview, { generateSlug } from '../components/MarkdownPreview';
import DeleteConfirmModal from '../components/DeleteConfirmModal';
import EditorToolbar from '../components/EditorToolbar';
import LinkSelectorModal from '../components/LinkSelectorModal';
// Use default import for Turndown, but handle 'default' property at runtime if needed
// @ts-ignore
import TurndownService from 'turndown';
// Use named import for gfm plugin
// @ts-ignore
import { gfm } from 'turndown-plugin-gfm';

interface FileEditorProps {
  repos: Repository[];
  onUpdateFile: (repoId: string, fileId: string, newContent: string) => void;
  onRenameFile: (repoId: string, fileId: string, newName: string) => void;
  onDeleteFile: (repoId: string, fileId: string) => void;
  isAuthenticated: boolean;
}

type ViewMode = 'write' | 'preview' | 'split';

interface TocItem {
  id: string;
  text: string;
  level: number;
}

interface Backlink {
  fileId: string;
  fileName: string;
  repoId: string;
  repoName: string;
  context: string;
}

const FileEditor: React.FC<FileEditorProps> = ({ repos, onUpdateFile, onRenameFile, onDeleteFile, isAuthenticated }) => {
  const { repoId, fileId } = useParams<{ repoId: string; fileId: string }>();
  const navigate = useNavigate();
  const textAreaRef = useRef<HTMLTextAreaElement>(null);

  const repo = repos.find(r => r.id === repoId);
  const file = repo?.files.find(f => f.id === fileId);

  const [viewMode, setViewMode] = useState<ViewMode>('preview');
  const [content, setContent] = useState('');
  const [hasChanges, setHasChanges] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [conversionStatus, setConversionStatus] = useState<string | null>(null);
  const [isLinkSelectorOpen, setIsLinkSelectorOpen] = useState(false);

  // Renaming State
  const [isRenaming, setIsRenaming] = useState(false);
  const [renameValue, setRenameValue] = useState('');

  useEffect(() => {
    if (file) {
      setContent(file.content);
      setRenameValue(file.name);
    }
  }, [file]);

  // --- Backlinks Logic ---
  const backlinks = useMemo(() => {
    if (!repoId || !fileId) return [];
    const links: Backlink[] = [];
    const targetLink = `/${repoId}/${fileId}`;

    repos.forEach(r => {
        r.files.forEach(f => {
            // Don't link to self
            if (f.id === fileId) return;

            if (f.content.includes(targetLink)) {
                // Try to find context (line containing the link)
                const lines = f.content.split('\n');
                const matchLine = lines.find(l => l.includes(targetLink)) || "Link found in document";
                // Clean link syntax for display
                const cleanContext = matchLine.replace(/\[(.*?)\]\(.*?\)/g, '$1').trim();

                links.push({
                    fileId: f.id,
                    fileName: f.name,
                    repoId: r.id,
                    repoName: r.name,
                    context: cleanContext.length > 60 ? cleanContext.substring(0, 60) + "..." : cleanContext
                });
            }
        })
    });
    return links;
  }, [repos, repoId, fileId]);

  // --- Table of Contents Logic ---
  const toc = useMemo(() => {
    if (!content) return [];

    // Regex to match # Heading, ## Heading etc.
    const headingRegex = /^(#{1,3})\s+(.+)$/gm;
    const items: TocItem[] = [];

    const lines = content.split('\n');
    let inCodeBlock = false;

    lines.forEach(line => {
        if (line.trim().startsWith('```')) {
            inCodeBlock = !inCodeBlock;
            return;
        }
        if (inCodeBlock) return;

        const headingMatch = line.match(/^(#{1,3})\s+(.+)$/);
        if (headingMatch) {
            const level = headingMatch[1].length;
            const text = headingMatch[2].trim();
            // Remove markdown links or bold from TOC text if present
            const cleanText = text.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1').replace(/(\*\*|__)(.*?)\1/g, '$2');

            items.push({
                id: generateSlug(cleanText),
                text: cleanText,
                level
            });
        }
    });

    return items;
  }, [content]);

  if (!repo || !file) {
    return <div className="h-screen flex items-center justify-center font-mono text-zenith-orange">ERROR: FILE DATA CORRUPTED OR MISSING</div>;
  }

  const handleSave = () => {
    if (!isAuthenticated) return;
    onUpdateFile(repoId!, fileId!, content);
    setHasChanges(false);
  };

  const handleRenameSubmit = () => {
    if (!isAuthenticated) return;
    if (renameValue.trim() && renameValue.trim() !== file.name) {
        let name = renameValue.trim();
        if (!name.endsWith('.md')) name += '.md';
        onRenameFile(repoId!, fileId!, name);
        // Show Feedback
        setConversionStatus("REFACTORING LINKS...");
        setTimeout(() => setConversionStatus(null), 2000);
    }
    setIsRenaming(false);
  };

  const handleContentChange = (val: string) => {
      setContent(val);
      setHasChanges(val !== file.content);

      // Trigger Link Selector on '[['
      if (val.endsWith('[[')) {
          setIsLinkSelectorOpen(true);
      }
  }

  const handleDeleteConfirm = () => {
      if (!isAuthenticated) return;
      onDeleteFile(repoId!, fileId!);
      navigate(`/${repoId}`);
  }

  const handleInsert = (prefix: string, suffix: string = '') => {
    if (!textAreaRef.current) return;
    const start = textAreaRef.current.selectionStart;
    const end = textAreaRef.current.selectionEnd;
    const text = textAreaRef.current.value;
    const before = text.substring(0, start);
    const selection = text.substring(start, end);
    const after = text.substring(end);

    const newText = before + prefix + selection + suffix + after;
    // Don't call handleContentChange directly to avoid double triggering logic if we used it, but here we just set state
    setContent(newText);
    setHasChanges(true);

    setTimeout(() => {
      if(textAreaRef.current) {
        textAreaRef.current.focus();
        textAreaRef.current.selectionStart = start + prefix.length;
        textAreaRef.current.selectionEnd = end + prefix.length;
      }
    }, 0);
  };

  const insertTextAtCursor = (textToInsert: string) => {
      if (!textAreaRef.current) return;
      const start = textAreaRef.current.selectionStart;
      const end = textAreaRef.current.selectionEnd;
      const currentText = textAreaRef.current.value;
      const before = currentText.substring(0, start);
      const after = currentText.substring(end);

      const newText = before + textToInsert + after;
      setContent(newText);
      setHasChanges(true);

      setTimeout(() => {
          if (textAreaRef.current) {
              textAreaRef.current.focus();
              const newCursorPos = start + textToInsert.length;
              textAreaRef.current.selectionStart = newCursorPos;
              textAreaRef.current.selectionEnd = newCursorPos;
          }
      }, 0);
  };

  const handleLinkSelect = (targetRepoId: string, targetFileId: string, targetName: string) => {
      // Remove the '[[' trigger if it exists at the end
      if (textAreaRef.current) {
         const val = textAreaRef.current.value;
         const end = textAreaRef.current.selectionEnd;
         // Check if cursor is right after '[['
         if (val.substring(end - 2, end) === '[[') {
             // Remove '[[' and insert link
             const before = val.substring(0, end - 2);
             const after = val.substring(end);
             const linkMd = `[[${targetName.replace('.md', '')}]]`; // Using WikiLink Style preference based on user behavior
             const newText = before + linkMd + after;
             setContent(newText);
             setHasChanges(true);
             setTimeout(() => {
                 if(textAreaRef.current) {
                     textAreaRef.current.focus();
                     textAreaRef.current.selectionStart = before.length + linkMd.length;
                     textAreaRef.current.selectionEnd = before.length + linkMd.length;
                 }
             }, 0);
             return;
         }
      }

      // Normal insertion via button
      const linkMd = `[[${targetName.replace('.md', '')}]]`;
      insertTextAtCursor(linkMd);
  };

  const handlePaste = (e: React.ClipboardEvent<HTMLTextAreaElement>) => {
    if (!isAuthenticated) return;

    const clipboardData = e.clipboardData;
    const types = clipboardData.types;

    // Check for HTML content
    if (types.includes('text/html')) {
        const html = clipboardData.getData('text/html');

        try {
            e.preventDefault(); 

            // 1. Robust Constructor Resolution
            let ServiceClass = TurndownService;
            // @ts-ignore
            if (typeof ServiceClass !== 'function' && ServiceClass.default) {
                // @ts-ignore
                ServiceClass = ServiceClass.default;
            }

            if (typeof ServiceClass !== 'function') {
                throw new Error("Could not find TurndownService constructor.");
            }

            // 2. Initialize Service
            // @ts-ignore
            const turndownService = new ServiceClass({
                headingStyle: 'atx',
                codeBlockStyle: 'fenced',
                bulletListMarker: '-',
                emDelimiter: '*',
                hr: '***' // Use asterisks to avoid Frontmatter conflicts
            });

            // 3. Robust Plugin Loading (Fail-safe)
            try {
                if (typeof gfm === 'function') {
                    turndownService.use(gfm);
                } else {
                    console.warn("GitNotes Warning: GFM plugin not available, skipping tables support.");
                }
            } catch (pluginErr) {
                console.warn("GitNotes Warning: Error applying GFM plugin, continuing with basic markdown.", pluginErr);
            }

            // Pure Text Mode: Remove images
            turndownService.remove('img');
            turndownService.remove('picture');

            // 4. Custom Rules
            turndownService.addRule('pre', {
                filter: ['pre'],
                replacement: function (content: string, node: any) {
                     return '\n```\n' + node.textContent + '\n```\n';
                }
            });

             // Force HR rule to be asterisks here too
             turndownService.addRule('horizontalRule', {
                filter: 'hr',
                replacement: function () {
                    return '\n\n***\n\n';
                }
            });

            // 5. Execute Conversion
            let markdown = turndownService.turndown(html);

            // --- DATA CLEANUP PIPELINE ---
            // 1. Unescape common markdown structures at start of line
            markdown = markdown.replace(/^\\(#+)/gm, '$1'); // \# -> #
            markdown = markdown.replace(/^\\>/gm, '>');     // \> -> >
            markdown = markdown.replace(/^\\([-*+])/gm, '$1'); // \- -> -

            // 2. Unescape specific patterns
            markdown = markdown.replace(/^(\\\*){3,}$/gm, '***'); // \*\*\* -> ***
            markdown = markdown.replace(/\\([\[\]])/g, '$1');     // \[Link\] -> [Link]

            // 3. Remove artifacts
            markdown = markdown.replace(/↩︎/g, ''); // Remove footnote returns

            // 4. Normalize Whitespace (Collapse 3+ newlines to 2)
            markdown = markdown.replace(/\n{3,}/g, '\n\n');

            // Visual Feedback
            setConversionStatus("SMART PASTE: CLEANED");
            setTimeout(() => setConversionStatus(null), 3000);

            insertTextAtCursor(markdown);

        } catch (err) {
            console.error("GitNotes Paste Error:", err);

            // Fallback: manually insert the plain text since we prevented default
            const plainText = clipboardData.getData('text/plain');
            insertTextAtCursor(plainText);

            setConversionStatus("PASTE FALLBACK: PLAIN TEXT");
            setTimeout(() => setConversionStatus(null), 3000);
        }
        return;
    }
  };

  const lineCount = content.split('\n').length;

  return (
    <div className="h-[calc(100vh-56px)] flex flex-col bg-zenith-bg relative">

      {/* Toast Notification (Fixed Position) */}
      {conversionStatus && (
          <div className="fixed bottom-12 right-6 z-50 animate-in slide-in-from-bottom-5 duration-300">
              <div className="bg-zenith-surface border border-zenith-orange px-4 py-3 shadow-[0_0_15px_rgba(255,77,0,0.2)] flex items-center gap-3">
                  <div className="bg-zenith-orange text-black p-1">
                      <Icons.Zap size={14} />
                  </div>
                  <span className="font-mono text-white font-bold text-xs tracking-widest uppercase">
                      {conversionStatus}
                  </span>
              </div>
          </div>
      )}

      {/* File Toolbar */}
      <div className="h-14 border-b border-zenith-border bg-zenith-bg flex items-center justify-between px-4 sm:px-6 shrink-0 relative z-10 gap-2">
          <div className="flex items-center gap-3 sm:gap-4 min-w-0 flex-1">
              <Link to={`/${repoId}`} className="text-zenith-muted hover:text-white transition-colors shrink-0">
                  <Icons.ChevronRight className="rotate-180" size={18} />
              </Link>
              <div className="h-6 w-px bg-zenith-border shrink-0"></div>

              {/* Renaming Interface */}
              {isRenaming && isAuthenticated ? (
                  <input 
                    autoFocus
                    type="text"
                    value={renameValue}
                    onChange={(e) => setRenameValue(e.target.value)}
                    onBlur={handleRenameSubmit}
                    onKeyDown={(e) => e.key === 'Enter' && handleRenameSubmit()}
                    className="bg-black border border-zenith-orange text-white font-mono text-sm font-bold tracking-wide px-2 py-1 outline-none min-w-[200px]"
                  />
              ) : (
                  <div className="flex items-center gap-2 group cursor-pointer" onClick={() => isAuthenticated && setIsRenaming(true)}>
                    <span className="font-mono text-sm text-white font-bold tracking-wide truncate group-hover:text-zenith-orange transition-colors" title={file.name}>
                        {file.name}
                    </span>
                    {isAuthenticated && <Icons.Edit size={12} className="text-zenith-border group-hover:text-zenith-orange opacity-0 group-hover:opacity-100 transition-all"/>}
                  </div>
              )}

              {hasChanges && <span className="text-[10px] bg-zenith-orange text-black px-2 py-0.5 font-bold font-mono shrink-0">UNSAVED</span>}
              {!isAuthenticated && <span className="text-[10px] border border-zenith-border text-zenith-muted px-2 py-0.5 font-mono uppercase shrink-0 hidden sm:block">Read Only</span>}
          </div>

          <div className="flex items-center gap-2 sm:gap-3 shrink-0">
             {/* Mode Switcher */}
             <div className="flex border border-zenith-border p-0.5 bg-zenith-surface">
                 <button 
                    onClick={() => setViewMode('write')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'write' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Write Mode"
                 >
                    <Icons.Edit size={12} /> <span className="hidden sm:inline">Write</span>
                 </button>
                 <button 
                    onClick={() => setViewMode('split')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 border-l border-r border-zenith-border ${viewMode === 'split' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Split View"
                 >
                    <Icons.Layout size={12} /> <span className="hidden sm:inline">Split</span>
                 </button>
                 <button 
                    onClick={() => setViewMode('preview')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'preview' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Preview Mode"
                 >
                    <Icons.File size={12} /> <span className="hidden sm:inline">Render</span>
                 </button>
             </div>

             {isAuthenticated && (
                <>
                 <button 
                    onClick={handleSave}
                    disabled={!hasChanges}
                    className={`flex items-center gap-2 px-4 py-2 border text-xs font-mono tracking-widest uppercase transition-colors ${hasChanges ? 'border-zenith-orange text-zenith-orange hover:bg-zenith-orange hover:text-black' : 'border-zenith-border text-zenith-muted cursor-not-allowed'}`}
                 >
                    <Icons.Save size={14} /> <span className="hidden sm:inline">Save</span>
                 </button>

                 <button onClick={() => setIsDeleteModalOpen(true)} className="p-2 text-zenith-muted hover:text-red-600 transition-colors">
                     <Icons.Trash size={16} />
                 </button>
                </>
             )}
          </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-hidden relative flex z-0">

         {/* Write Panel */}
         {(viewMode === 'write' || viewMode === 'split') && (
           <div className={`flex flex-col border-r border-zenith-border ${viewMode === 'split' ? 'w-1/2' : 'w-full'}`}>
             {isAuthenticated && (
                 <EditorToolbar 
                    onInsert={handleInsert} 
                    onLinkNote={() => setIsLinkSelectorOpen(true)} 
                 />
             )}
             <div className="flex flex-1 overflow-hidden">
                {/* Line Numbers */}
                <div className="hidden sm:block w-10 bg-zenith-surface border-r border-zenith-border text-right py-4 pr-2 font-mono text-xs text-zenith-border select-none overflow-hidden shrink-0">
                    {Array.from({length: Math.max(lineCount, 20)}).map((_, i) => <div key={i}>{i+1}</div>)}
                </div>

                <textarea
                    ref={textAreaRef}
                    readOnly={!isAuthenticated}
                    value={content}
                    onChange={(e) => handleContentChange(e.target.value)}
                    onPaste={handlePaste}
                    className={`w-full h-full bg-zenith-bg text-zenith-text font-mono text-sm p-4 resize-none outline-none transition-colors leading-relaxed ${!isAuthenticated ? 'cursor-not-allowed text-zenith-muted' : 'focus:bg-[#050505]'}`}
                    spellCheck={false}
                    placeholder={!isAuthenticated ? "Editing is disabled in visitor mode." : "Start typing... Tip: Type '[[' to link another note."}
                />
             </div>
           </div>
         )}

         {/* Preview Panel Wrapper (Now Flex for Sidebar) */}
         {(viewMode === 'preview' || viewMode === 'split') && (
           <div className={`flex flex-1 overflow-hidden bg-zenith-bg ${viewMode === 'split' ? 'bg-[#080808]' : ''}`}>

               {/* Actual Preview Content */}
               <div className="flex-1 overflow-y-auto overflow-x-hidden">
                   <div className={`p-8 mx-auto ${viewMode === 'split' ? 'max-w-none' : 'max-w-4xl'}`}>
                       <MarkdownPreview content={content} />

                       {/* Linked Mentions (Backlinks) Section */}
                       {backlinks.length > 0 && (
                           <div className="mt-16 pt-8 border-t border-zenith-border">
                               <h3 className="text-sm font-mono font-bold text-zenith-muted uppercase tracking-widest mb-4 flex items-center gap-2">
                                   <Icons.GitBranch size={14} /> Linked Mentions
                               </h3>
                               <div className="grid grid-cols-1 gap-3">
                                   {backlinks.map((link, idx) => (
                                       <div 
                                            key={idx}
                                            onClick={() => navigate(`/${link.repoId}/${link.fileId}`)}
                                            className="group bg-zenith-surface border border-zenith-border p-4 cursor-pointer hover:border-zenith-orange transition-colors"
                                       >
                                           <div className="flex items-center justify-between mb-2">
                                               <span className="text-white font-bold text-sm group-hover:text-zenith-orange transition-colors">
                                                   {link.fileName}
                                               </span>
                                               <span className="text-[10px] text-zenith-muted font-mono bg-zenith-bg px-2 py-0.5 border border-zenith-border">
                                                   {link.repoName}
                                               </span>
                                           </div>
                                           <div className="text-zenith-muted text-xs font-mono line-clamp-2 border-l-2 border-zenith-border pl-2 group-hover:border-zenith-orange">
                                               "...{link.context}..."
                                           </div>
                                       </div>
                                   ))}
                               </div>
                           </div>
                       )}
                   </div>
                   {/* Bottom Spacer for comfortable reading */}
                   <div className="h-32"></div>
               </div>

                {/* Outline Sidebar (Visible in Preview Mode mainly, or Split if room permits) */}
                {viewMode === 'preview' && toc.length > 0 && (
                    <div className="hidden xl:flex w-72 flex-col border-l border-zenith-border bg-zenith-bg/50 backdrop-blur-sm">
                        <div className="p-4 border-b border-zenith-border font-mono text-[10px] tracking-widest text-zenith-muted uppercase flex items-center gap-2">
                            <Icons.List size={12} />
                            <span>Document Outline</span>
                        </div>
                        <div className="flex-1 overflow-y-auto p-4 space-y-1">
                            {toc.map((item, idx) => (
                                <a 
                                    key={`${item.id}-${idx}`}
                                    href={`#${item.id}`}
                                    onClick={(e) => {
                                        e.preventDefault();
                                        document.getElementById(item.id)?.scrollIntoView({ behavior: 'smooth' });
                                    }}
                                    className={`
                                        block text-xs font-mono py-1.5 transition-colors duration-200 border-l-2 border-transparent hover:border-zenith-orange pl-3
                                        ${item.level === 1 ? 'text-white font-bold' : 'text-zenith-muted hover:text-zenith-text'}
                                        ${item.level === 2 ? 'ml-2' : ''}
                                        ${item.level === 3 ? 'ml-4' : ''}
                                    `}
                                >
                                    {item.text}
                                </a>
                            ))}
                        </div>
                    </div>
                )}
           </div>
         )}

      </div>

      {/* Footer Info */}
      <div className="h-8 border-t border-zenith-border bg-zenith-surface flex items-center justify-between px-4 font-mono text-[10px] text-zenith-muted uppercase tracking-widest shrink-0">
         <div>Ln {lineCount}, Col {content.length}</div>
         <div>{isAuthenticated ? 'Markdown Environment' : 'Visitor View'}</div>
      </div>

      <DeleteConfirmModal 
        isOpen={isDeleteModalOpen}
        onClose={() => setIsDeleteModalOpen(false)}
        onConfirm={handleDeleteConfirm}
        title="Delete File"
        itemName={file.name}
      />

      <LinkSelectorModal
        isOpen={isLinkSelectorOpen}
        onClose={() => setIsLinkSelectorOpen(false)}
        repos={repos}
        onSelect={handleLinkSelect}
      />
    </div>
  );
};

export default FileEditor;

import React, { useCallback, useEffect } from 'react';
import { 
  ReactFlow, 
  useNodesState, 
  useEdgesState, 
  addEdge, 
  Background, 
  Controls,
  MiniMap,
  Node,
  Edge,
  MarkerType,
  ConnectionLineType,
  useReactFlow,
  Connection
} from '@xyflow/react';
