                </span>
             </div>
             <div className="text-[9px] text-red-500 uppercase tracking-wider font-bold">
                Click × to Unlink
             </div>
          </div>
        </div>
      </EdgeLabelRenderer>
    </>
  );
};

const GraphView: React.FC<GraphViewProps> = ({ repo, onAddFile, onLinkNodes, onDisconnectNodes }) => {
  const navigate = useNavigate();
  const [nodes, setNodes, onNodesChange] = useNodesState([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);
  const { fitView } = useReactFlow();

  // Define edge types outside of render or useMemo
  const edgeTypes = useMemo(() => ({
    'custom-delete': CustomDeleteEdge,
  }), []);

  // --- 1. Graph Construction Logic ---
  const getLayoutedElements = useCallback((nodes: Node[], edges: Edge[]) => {
    const dagreGraph = new dagre.graphlib.Graph();
    dagreGraph.setDefaultEdgeLabel(() => ({}));

    // Dynamic Rank Separation based on complexity
    const rankSep = edges.length > 20 ? 100 : 70;

    dagreGraph.setGraph({ 
        rankdir: 'LR', // Left to Right
        align: 'UL',   // Align Upper Left
        nodesep: 50,
        ranksep: rankSep
    });

    nodes.forEach((node) => {
      // Use dimensions stored in data or default
      const w = node.style?.width ? parseInt(node.style.width.toString()) : 180;
      const h = 60; 
      dagreGraph.setNode(node.id, { width: w, height: h });
    });

    edges.forEach((edge) => {
      dagreGraph.setEdge(edge.source, edge.target);
    });

    dagre.layout(dagreGraph);

    const layoutedNodes = nodes.map((node) => {
      const nodeWithPosition = dagreGraph.node(node.id);

      // Safety check if dagre failed to position (e.g. strict orphaned node)
      const x = nodeWithPosition ? nodeWithPosition.x : 0;
      const y = nodeWithPosition ? nodeWithPosition.y : 0;
      const w = node.style?.width ? parseInt(node.style.width.toString()) : 180;

      return {
        ...node,
        position: {
          x: x - w / 2,
          y: y - 30, // half height
        },
      };
    });

    return { nodes: layoutedNodes, edges };
  }, []);

  // --- 2. Data Parsing Effect ---
  useEffect(() => {
    if (!repo) return;

    const rawNodes: Node[] = [];
    const rawEdges: Edge[] = [];

    // Map filename to ID for easy edge creation
    const fileMap = new Map<string, string>();
    repo.files.forEach(f => fileMap.set(f.name, f.id));
    repo.files.forEach(f => fileMap.set(f.name.replace('.md', ''), f.id)); 

    // Helper to get name from ID for labels
    const idToName = new Map<string, string>();
    repo.files.forEach(f => idToName.set(f.id, f.name.replace('.md', '')));

    // Connection Counter (Weight)
    const connectionCounts = new Map<string, number>();

    // 1. First Pass: Create Edges (Parse Links)
    repo.files.forEach(sourceFile => {
        // Regex for [[Link]]
        const linkRegex = /\[\[(.*?)\]\]/g;
        let match;
        while ((match = linkRegex.exec(sourceFile.content)) !== null) {
            const targetName = match[1];
            // Try to find exact match or partial match
            let targetId = fileMap.get(targetName);
            if (!targetId) targetId = fileMap.get(targetName + '.md');

            if (targetId && targetId !== sourceFile.id) {
                // Increment weights
                connectionCounts.set(sourceFile.id, (connectionCounts.get(sourceFile.id) || 0) + 1);
                connectionCounts.set(targetId, (connectionCounts.get(targetId) || 0) + 1);

                rawEdges.push({
                    id: `${sourceFile.id}-${targetId}`,
                    source: sourceFile.id,
                    target: targetId,
                    type: 'custom-delete', 
                    animated: true,
                    style: { stroke: '#52525B' },
                    markerEnd: {
                        type: MarkerType.ArrowClosed,
                        color: '#52525B',
                    },
                    data: {
                        sourceName: sourceFile.name.replace('.md', ''),
                        targetName: idToName.get(targetId) || targetName,
                        onDelete: () => {
                            if (onDisconnectNodes) {
                                onDisconnectNodes(sourceFile.id, targetId!);
                            }
                        }
                    },
                    selected: false, 
                    focusable: true,
                });
            }
        }
    });

    // 2. Identify Orphans (Nodes with 0 edges)
    const connectedNodeIds = new Set<string>();
    rawEdges.forEach(e => {
        connectedNodeIds.add(e.source);
        connectedNodeIds.add(e.target);
    });

    // 3. Second Pass: Create Nodes with HIERARCHICAL STYLING
    repo.files.forEach(file => {
        const isOrphan = !connectedNodeIds.has(file.id) && repo.files.length > 1; 
        const isReadme = file.name.toLowerCase() === 'readme.md';
        const weight = connectionCounts.get(file.id) || 0;
        const isHub = weight >= 3; // Defines a "Parent Theme" candidate if not Readme

        // Base Sizes
        let width = 150;
        let fontSize = 12;

        // --- HIERARCHY STYLES ---

        // 1. README (The Sun/Root)
        const readmeStyle = {
            background: 'linear-gradient(135deg, #18181B 0%, #000 100%)',
            color: '#FFD700', // Gold
            border: '2px solid #FFD700',
            fontWeight: '900',
            boxShadow: '0 0 25px rgba(255, 215, 0, 0.3)',
            zIndex: 10,
            textTransform: 'uppercase' as const,
            letterSpacing: '0.1em'
        };
        if (isReadme) {
            width = 220; // Larger
            fontSize = 14;
        }

        // 2. HUBS (High Connectivity Nodes - "Parent Themes")
        const hubStyle = {
            background: '#0F0F11',
            color: '#fff',
            border: '1px solid #FF4D00', // Zenith Orange
            fontWeight: 'bold',
            boxShadow: '0 0 15px rgba(255, 77, 0, 0.25)',
            zIndex: 5
        };
        if (isHub && !isReadme) {
            width = 190;
            fontSize = 13;
        }

        // 3. ORPHANS (Disconnected)
        const orphanStyle = {
            background: '#1a0505',
            color: '#ff4d4d',
            border: '1px dashed #ff4d4d',
            boxShadow: 'none',
            opacity: 0.8
        };

        // 4. LEAF NODES (Standard)
        const defaultStyle = {
            background: '#030303',
            color: '#A1A1AA', // Muted text
            border: '1px solid #27272A',
            boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.5)',
        };

        // Determine final style
        let finalStyle = defaultStyle;
        if (isReadme) finalStyle = { ...defaultStyle, ...readmeStyle };
        else if (isOrphan) finalStyle = { ...defaultStyle, ...orphanStyle };
        else if (isHub) finalStyle = { ...defaultStyle, ...hubStyle };

        rawNodes.push({
            id: file.id,
            data: { 
                label: isOrphan ? `⚠ ${file.name.replace('.md', '')}` : file.name.replace('.md', '') 
            },
            position: { x: 0, y: 0 }, 
            connectable: true,
            style: { 
                borderRadius: '2px', // Sharper corners for industrial look
                padding: '12px',
                fontFamily: 'monospace',
                textAlign: 'center',
                width: width,
                fontSize: `${fontSize}px`,
                transition: 'all 0.3s ease',
                ...finalStyle
            },
        });
    });

    // Apply Layout
    const { nodes: layoutedNodes, edges: layoutedEdges } = getLayoutedElements(rawNodes, rawEdges);
    setNodes(layoutedNodes);
    setEdges(layoutedEdges);

    // Fit view after a brief delay to allow rendering
    setTimeout(() => {
        window.requestAnimationFrame(() => fitView({ padding: 0.2 }));
    }, 100);

  }, [repo, getLayoutedElements, setNodes, setEdges, fitView, onDisconnectNodes]);

  const onNodeClick = (_: React.MouseEvent, node: Node) => {
      navigate(`/${repo.id}/${node.id}`);
  };

  const onConnect = useCallback((params: Connection) => {
    if (params.source && params.target && onLinkNodes) {
        onLinkNodes(params.source, params.target);
    }
  }, [onLinkNodes]);

  const onEdgesDelete = useCallback((deletedEdges: Edge[]) => {
      if (onDisconnectNodes) {
          deletedEdges.forEach((edge) => {
              onDisconnectNodes(edge.source, edge.target);
          });
      }
  }, [onDisconnectNodes]);

  const orphanCount = nodes.filter(n => n.style && n.style.border && (n.style.border as string).includes('dashed')).length;

  return (
    <div className="w-full h-[calc(100vh-180px)] border border-zenith-border bg-zenith-bg relative group">

        {/* Graph Toolbar */}
        <div className="absolute top-4 right-4 z-10 flex gap-2">
            <button 
                onClick={onAddFile}
                className="bg-zenith-orange text-black px-4 py-2 font-mono text-xs font-bold uppercase tracking-widest hover:bg-white transition-colors shadow-lg flex items-center gap-2"
            >
                <Icons.Plus size={14} /> Add Node
            </button>
        </div>

        {/* Empty State */}
        {nodes.length === 0 && (
             <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
                 <div className="text-center">
                     <div className="text-zenith-muted font-mono text-xs uppercase tracking-widest mb-2">No Data Points Detected</div>
                     <div className="text-zenith-orange/50 font-mono text-[10px]">Add a file to initialize graph</div>
                 </div>
             </div>
        )}

        <ReactFlow
            nodes={nodes}
            edges={edges}
            onNodesChange={onNodesChange}
            onEdgesChange={onEdgesChange}
            onNodeClick={onNodeClick}
            onConnect={onConnect}
            onEdgesDelete={onEdgesDelete} // Bind the delete handler
            deleteKeyCode={['Backspace', 'Delete']} // Explicitly allow deletion
            edgeTypes={edgeTypes}
            connectionLineType={ConnectionLineType.SmoothStep}
            fitView
            style={flowStyles}
            minZoom={0.2}
            maxZoom={4}
            // Style handles to be visible
            defaultEdgeOptions={{ 
                style: { stroke: '#52525B' }, 
                markerEnd: { type: MarkerType.ArrowClosed, color: '#52525B' } 
            }}
        >
            <Background color="#27272A" gap={20} size={1} />
            <Controls 
                className="bg-zenith-surface border border-zenith-border fill-white text-white" 
                style={{ borderRadius: 0, padding: 2 }} 
            />
            <MiniMap 
                nodeStrokeColor="#27272A"
                nodeColor="#18181B"
                maskColor="rgba(0,0,0, 0.7)"
                style={{ backgroundColor: '#030303', border: '1px solid #27272A' }}
            />
        </ReactFlow>

        {/* HUD Overlay */}
        <div className="absolute bottom-4 left-4 pointer-events-none">
            <div className="font-mono text-[10px] text-zenith-orange uppercase tracking-widest flex items-center gap-2">
