import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { 
  ReactFlow, 
  useNodesState, 
  useEdgesState, 
  Background, 
  Controls,
  MiniMap,
  Node,
  Edge,
  MarkerType,
  ConnectionLineType,
  useReactFlow,
  Connection,
  ReactFlowProvider,
  BaseEdge,
  EdgeLabelRenderer,
  EdgeProps,
  getSmoothStepPath
} from '@xyflow/react';
import dagre from 'dagre';
import { Repository } from '../types';
import { useNavigate } from 'react-router-dom';
import { Icons } from './Icon';

interface GraphViewProps {
  repo: Repository;
  onAddFile: () => void;
  onLinkNodes?: (sourceId: string, targetId: string) => void;
  onDisconnectNodes?: (sourceId: string, targetId: string) => void;
}

// Custom Dark Theme styles for React Flow
const flowStyles = {
    background: '#030303',
};

// --- COLOR PALETTES FOR CLUSTERS ---
// Distinct colors to separate different "projects" visually
const CLUSTER_PALETTES = [
    { main: '#FF4D00', glow: 'rgba(255, 77, 0, 0.4)' },   // Zenith Orange
    { main: '#00E676', glow: 'rgba(0, 230, 118, 0.4)' },  // Matrix Green
    { main: '#2979FF', glow: 'rgba(41, 121, 255, 0.4)' }, // Electric Blue
    { main: '#D500F9', glow: 'rgba(213, 0, 249, 0.4)' },  // Neon Purple
    { main: '#FF1744', glow: 'rgba(255, 23, 68, 0.4)' },  // Crimson Red
    { main: '#FFEA00', glow: 'rgba(255, 234, 0, 0.4)' },  // Cyber Yellow
];

// --- Custom Edge Component with Delete Button & Hover Feedback ---
const CustomDeleteEdge = ({
  id,
  sourceX,
  sourceY,
  targetX,
  targetY,
  sourcePosition,
  targetPosition,
  style = {},
  markerEnd,
  data,
}: EdgeProps) => {
  const [isHovered, setIsHovered] = useState(false);
  const color = (data?.color as string) || '#52525B'; // Use cluster color

  const [edgePath, labelX, labelY] = getSmoothStepPath({
    sourceX,
    sourceY,
    sourcePosition,
    targetX,
    targetY,
    targetPosition,
  });

  const onEdgeClick = (evt: React.MouseEvent, id: string) => {
    evt.stopPropagation();
    if (data && typeof data.onDelete === 'function') {
        (data.onDelete as () => void)();
    }
  };

  // Dynamic Edge Style
  const activeStyle = {
      ...style,
      stroke: '#ef4444', // Red Warning on delete hover
      strokeWidth: 2,
      filter: 'drop-shadow(0 0 3px rgba(239, 68, 68, 0.6))',
      transition: 'all 0.3s ease',
      zIndex: 100
  };

  const defaultStyle = {
      ...style,
      stroke: color, 
      opacity: 0.6,
      strokeWidth: 1,
      transition: 'all 0.3s ease',
  };

  return (
    <>
      <BaseEdge path={edgePath} markerEnd={{...markerEnd, color: isHovered ? '#ef4444' : color} as any} style={isHovered ? activeStyle : defaultStyle} />
      <EdgeLabelRenderer>
        <div
          style={{
            position: 'absolute',
            transform: `translate(-50%, -50%) translate(${labelX}px,${labelY}px)`,
            fontSize: 12,
            pointerEvents: 'all',
          }}
          className="nodrag nopan group flex flex-col items-center justify-center"
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
        >
          {/* Delete Button */}
          <button
            className={`w-5 h-5 rounded-full flex items-center justify-center transition-all duration-200 border shadow-lg ${
                isHovered 
                ? 'bg-red-600 text-white border-red-500 scale-110' 
                : 'bg-black border-zenith-border opacity-0 group-hover:opacity-100 scale-90 hover:scale-100'
            }`}
            style={{ color: isHovered ? 'white' : color }}
            onClick={(event) => onEdgeClick(event, id)}
            title="Sever Connection"
          >
            <span className="leading-none mb-[1px] font-bold">×</span>
          </button>

          {/* Context Tooltip */}
          <div className={`
            absolute top-7 whitespace-nowrap bg-black/90 border border-red-500/30 px-3 py-2 rounded-sm 
            text-[10px] font-mono shadow-[0_4px_20px_rgba(0,0,0,0.8)] backdrop-blur-md transition-all duration-200 z-50
            flex flex-col items-center gap-1 pointer-events-none
            ${isHovered ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 -translate-y-2 scale-95'}
          `}>
             <div className="flex items-center gap-2 text-zenith-muted">
                <span className="text-white font-bold truncate max-w-[120px]">
                    {data?.sourceName as string || 'Unknown'}
                </span>
                <Icons.ChevronRight size={10} className="text-red-500" />
                <span className="text-white font-bold truncate max-w-[120px]">
                    {data?.targetName as string || 'Unknown'}
                </span>
             </div>
             <div className="text-[9px] text-red-500 uppercase tracking-wider font-bold">
                Click × to Unlink
             </div>
          </div>
        </div>
      </EdgeLabelRenderer>
    </>
  );
};

const GraphView: React.FC<GraphViewProps> = ({ repo, onAddFile, onLinkNodes, onDisconnectNodes }) => {
  const navigate = useNavigate();
  const [nodes, setNodes, onNodesChange] = useNodesState([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);
  const { fitView } = useReactFlow();

  const edgeTypes = useMemo(() => ({
    'custom-delete': CustomDeleteEdge,
  }), []);

  // --- 1. Layout Engine ---
  const getLayoutedElements = useCallback((nodes: Node[], edges: Edge[]) => {
    const dagreGraph = new dagre.graphlib.Graph();
    dagreGraph.setDefaultEdgeLabel(() => ({}));

    dagreGraph.setGraph({ 
        rankdir: 'LR', 
        align: 'DL',
        nodesep: 60, // Increased spacing between nodes
        ranksep: 120 // Increased spacing between ranks
    });

    nodes.forEach((node) => {
      const w = node.style?.width ? parseInt(node.style.width.toString()) : 180;
      const h = 60; 
      dagreGraph.setNode(node.id, { width: w, height: h });
    });

    edges.forEach((edge) => {
      dagreGraph.setEdge(edge.source, edge.target);
    });

    dagre.layout(dagreGraph);

    const layoutedNodes = nodes.map((node) => {
      const nodeWithPosition = dagreGraph.node(node.id);
      const x = nodeWithPosition ? nodeWithPosition.x : 0;
      const y = nodeWithPosition ? nodeWithPosition.y : 0;
      const w = node.style?.width ? parseInt(node.style.width.toString()) : 180;

      return {
        ...node,
        position: {
          x: x - w / 2,
          y: y - 30,
        },
      };
    });

    return { nodes: layoutedNodes, edges };
  }, []);

  // --- 2. Data Processing ---
  useEffect(() => {
    if (!repo) return;

    // --- A. Build Maps ---
    const fileMap = new Map<string, string>();
    repo.files.forEach(f => fileMap.set(f.name, f.id));
    repo.files.forEach(f => fileMap.set(f.name.replace('.md', ''), f.id)); 
    const idToName = new Map<string, string>();
    repo.files.forEach(f => idToName.set(f.id, f.name.replace('.md', '')));

    // --- B. Build Adjacency Graph (Undirected) for Clustering ---
    // We need to know who is connected to whom regardless of direction to identify "Galaxies"
    const adj = new Map<string, string[]>();
    repo.files.forEach(f => adj.set(f.id, []));

    const rawEdges: Edge[] = [];
    const connectionCounts = new Map<string, number>(); // Count total connections (degree) per node

    repo.files.forEach(sourceFile => {
        const linkRegex = /\[\[(.*?)\]\]/g;
        let match;
        while ((match = linkRegex.exec(sourceFile.content)) !== null) {
            const targetName = match[1];
            let targetId = fileMap.get(targetName);
            if (!targetId) targetId = fileMap.get(targetName + '.md');

            if (targetId && targetId !== sourceFile.id) {
                // Update Adjacency for Clustering
                adj.get(sourceFile.id)?.push(targetId);
                adj.get(targetId)?.push(sourceFile.id);

                // Update Degree Counts
                connectionCounts.set(sourceFile.id, (connectionCounts.get(sourceFile.id) || 0) + 1);
                connectionCounts.set(targetId, (connectionCounts.get(targetId) || 0) + 1);

                rawEdges.push({
                    id: `${sourceFile.id}-${targetId}`,
                    source: sourceFile.id,
                    target: targetId,
                    type: 'custom-delete', 
                    animated: true,
                    style: { strokeWidth: 1 }, // Color will be set later based on cluster
                    markerEnd: { type: MarkerType.ArrowClosed },
                    data: {
                        sourceName: sourceFile.name.replace('.md', ''),
                        targetName: idToName.get(targetId) || targetName,
                        onDelete: () => {
                            if (onDisconnectNodes) onDisconnectNodes(sourceFile.id, targetId!);
                        }
                    },
                });
            }
        }
    });

    // --- C. Identify Connected Components (Clusters) ---
    const visited = new Set<string>();
    const clusters: string[][] = []; // Array of arrays of nodeIDs

    repo.files.forEach(file => {
        if (!visited.has(file.id)) {
            const componentNodes: string[] = [];
            const queue = [file.id];
            visited.add(file.id);

            while(queue.length > 0) {
                const curr = queue.shift()!;
                componentNodes.push(curr);

                // Check neighbors
                const neighbors = adj.get(curr) || [];
                neighbors.forEach(neighbor => {
                    if (!visited.has(neighbor)) {
                        visited.add(neighbor);
                        queue.push(neighbor);
                    }
                });
            }
            // Only consider it a cluster if it has connections OR if it's the only node in repo
            if (componentNodes.length > 1 || repo.files.length === 1) {
                clusters.push(componentNodes);
            } else {
                // It's a true orphan
                clusters.push([file.id]);
            }
        }
    });

    // Sort clusters by size (largest first)
    clusters.sort((a, b) => b.length - a.length);

    // --- D. Build Nodes with Styles ---
    const rawNodes: Node[] = [];

    // Process each cluster
    clusters.forEach((clusterNodes, clusterIndex) => {
        // Determine Palette for this cluster
        const palette = CLUSTER_PALETTES[clusterIndex % CLUSTER_PALETTES.length];

        // Find the "Mother Theme" (Max Degree) in this cluster
        let maxDegree = -1;
        let motherNodeId = '';

        clusterNodes.forEach(nodeId => {
            const degree = connectionCounts.get(nodeId) || 0;
            // Prefer README as mother if present, else max degree
            const isReadme = idToName.get(nodeId)?.toLowerCase() === 'readme';
            const weightedDegree = isReadme ? 9999 : degree;

            if (weightedDegree > maxDegree) {
                maxDegree = weightedDegree;
                motherNodeId = nodeId;
            }
        });

        // Create Nodes
        clusterNodes.forEach(nodeId => {
            const file = repo.files.find(f => f.id === nodeId);
            if (!file) return;

            const isMother = nodeId === motherNodeId && (connectionCounts.get(nodeId) || 0) > 0;
            const isOrphan = clusterNodes.length === 1 && repo.files.length > 1;
            const isReadme = file.name.toLowerCase() === 'readme.md';

            // --- Styling Logic ---
            let width = 160;
            let fontSize = 12;
            let style: React.CSSProperties = {
                background: '#030303',
                color: palette.main,
                border: `1px solid ${palette.main}`,
                boxShadow: `0 4px 6px -1px rgba(0, 0, 0, 0.5)`,
            };

            if (isReadme) {
                // Readme is always special (White/Gold)
                style = {
                    background: 'linear-gradient(135deg, #18181B 0%, #000 100%)',
                    color: '#FFD700',
                    border: '2px solid #FFD700',
                    fontWeight: '900',
                    boxShadow: '0 0 25px rgba(255, 215, 0, 0.3)',
                    textTransform: 'uppercase',
                    zIndex: 10
                };
                width = 220;
                fontSize = 14;
            } else if (isMother) {
                // Mother Theme of a Cluster (Cluster Color)
                style = {
                    background: '#0F0F11',
                    color: '#fff', // White text on cluster border
                    border: `2px solid ${palette.main}`,
                    fontWeight: 'bold',
                    boxShadow: `0 0 20px ${palette.glow}`,
                    zIndex: 5
                };
                width = 200;
                fontSize = 13;
            } else if (isOrphan) {
                 style = {
                    background: '#1a0505',
                    color: '#ff4d4d',
                    border: '1px dashed #ff4d4d',
                    opacity: 0.8
                };
            } else {
                // Child Node
                 style = {
                    background: '#030303',
                    color: '#A1A1AA',
                    border: '1px solid #27272A',
                    borderLeft: `3px solid ${palette.main}`, // Subtle color indicator
                };
            }

            rawNodes.push({
                id: file.id,
                data: { label: file.name.replace('.md', '') },
                position: { x: 0, y: 0 },
                connectable: true,
                style: {
                    borderRadius: '2px',
                    padding: '12px',
                    fontFamily: 'monospace',
                    textAlign: 'center',
                    width: width,
                    fontSize: `${fontSize}px`,
                    transition: 'all 0.3s ease',
                    ...style
                }
            });
        });
    });

    // --- E. Update Edge Colors based on Source Cluster ---
    // If Source is in Cluster X, Edge is Color X
    const coloredEdges = rawEdges.map(edge => {
        // Find which cluster the source belongs to
        const clusterIndex = clusters.findIndex(c => c.includes(edge.source));
        const palette = CLUSTER_PALETTES[clusterIndex % CLUSTER_PALETTES.length];

        return {
            ...edge,
            data: { ...edge.data, color: palette.main }, // Pass color to custom edge
            style: { ...edge.style, stroke: palette.main, opacity: 0.6 },
            markerEnd: { ...edge.markerEnd, color: palette.main }
        } as Edge;
    });

    // Apply Layout
    const { nodes: layoutedNodes, edges: layoutedEdges } = getLayoutedElements(rawNodes, coloredEdges);
    setNodes(layoutedNodes);
    setEdges(layoutedEdges);

    setTimeout(() => {
        window.requestAnimationFrame(() => fitView({ padding: 0.2 }));
    }, 100);

  }, [repo, getLayoutedElements, setNodes, setEdges, fitView, onDisconnectNodes]);

  const onNodeClick = (_: React.MouseEvent, node: Node) => {
      navigate(`/${repo.id}/${node.id}`);
  };

  const onConnect = useCallback((params: Connection) => {
    if (params.source && params.target && onLinkNodes) {
        onLinkNodes(params.source, params.target);
    }
  }, [onLinkNodes]);

  const onEdgesDelete = useCallback((deletedEdges: Edge[]) => {
      if (onDisconnectNodes) {
          deletedEdges.forEach((edge) => {
              onDisconnectNodes(edge.source, edge.target);
          });
      }
  }, [onDisconnectNodes]);

  const clusterCount = nodes.length > 0 ? new Set(nodes.map(n => n.style?.borderColor || n.style?.border)).size : 0;
  // Estimate unique colors to guess cluster count roughly for UI

  return (
    <div className="w-full h-[calc(100vh-180px)] border border-zenith-border bg-zenith-bg relative group">

        {/* Graph Toolbar */}
        <div className="absolute top-4 right-4 z-10 flex gap-2">
            <button 
                onClick={onAddFile}
                className="bg-zenith-orange text-black px-4 py-2 font-mono text-xs font-bold uppercase tracking-widest hover:bg-white transition-colors shadow-lg flex items-center gap-2"
            >
                <Icons.Plus size={14} /> Add Node
            </button>
        </div>

        {/* Empty State */}
        {nodes.length === 0 && (
             <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
                 <div className="text-center">
                     <div className="text-zenith-muted font-mono text-xs uppercase tracking-widest mb-2">No Data Points Detected</div>
                     <div className="text-zenith-orange/50 font-mono text-[10px]">Add a file to initialize graph</div>
                 </div>
             </div>
        )}

        <ReactFlow
            nodes={nodes}
            edges={edges}
            onNodesChange={onNodesChange}
            onEdgesChange={onEdgesChange}
            onNodeClick={onNodeClick}
            onConnect={onConnect}
            onEdgesDelete={onEdgesDelete} 
            deleteKeyCode={['Backspace', 'Delete']} 
            edgeTypes={edgeTypes}
            connectionLineType={ConnectionLineType.SmoothStep}
            fitView
            style={flowStyles}
            minZoom={0.2}
            maxZoom={4}
            defaultEdgeOptions={{ 
                type: 'custom-delete',
                markerEnd: { type: MarkerType.ArrowClosed } 
            }}
        >
            <Background color="#27272A" gap={20} size={1} />
            <Controls 
                className="bg-zenith-surface border border-zenith-border fill-white text-white" 
                style={{ borderRadius: 0, padding: 2 }} 
            />
            <MiniMap 
                nodeStrokeColor="#27272A"
                nodeColor="#18181B"
                maskColor="rgba(0,0,0, 0.7)"
                style={{ backgroundColor: '#030303', border: '1px solid #27272A' }}
            />
        </ReactFlow>

        {/* HUD Overlay */}
        <div className="absolute bottom-4 left-4 pointer-events-none">
            <div className="font-mono text-[10px] text-zenith-orange uppercase tracking-widest flex items-center gap-2">
                <Icons.Zap size={10} className="animate-pulse"/>
                Visualizing {nodes.length} Nodes via Multi-Cluster Protocol
            </div>
            <div className="font-mono text-[10px] text-zenith-muted mt-1">
                Drag handles to link nodes | Click '×' on line to unlink
            </div>
        </div>
    </div>
  );
};

