  const [nodes, setNodes, onNodesChange] = useNodesState([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);
  const { fitView } = useReactFlow();

  const edgeTypes = useMemo(() => ({
    'custom-delete': CustomDeleteEdge,
  }), []);

  // --- 1. Layout Engine ---
  const getLayoutedElements = useCallback((nodes: Node[], edges: Edge[]) => {
    const dagreGraph = new dagre.graphlib.Graph();
    dagreGraph.setDefaultEdgeLabel(() => ({}));

    dagreGraph.setGraph({ 
        rankdir: 'LR', 
        align: 'DL',
        nodesep: 60, // Increased spacing between nodes
        ranksep: 120 // Increased spacing between ranks
    });

    nodes.forEach((node) => {
      const w = node.style?.width ? parseInt(node.style.width.toString()) : 180;
      const h = 60; 
      dagreGraph.setNode(node.id, { width: w, height: h });
    });

    edges.forEach((edge) => {
      dagreGraph.setEdge(edge.source, edge.target);
    });

    dagre.layout(dagreGraph);

    const layoutedNodes = nodes.map((node) => {
      const nodeWithPosition = dagreGraph.node(node.id);
      const x = nodeWithPosition ? nodeWithPosition.x : 0;
      const y = nodeWithPosition ? nodeWithPosition.y : 0;
      const w = node.style?.width ? parseInt(node.style.width.toString()) : 180;

      return {
        ...node,
        position: {
          x: x - w / 2,
          y: y - 30,
        },
      };
    });

    return { nodes: layoutedNodes, edges };
  }, []);

  // --- 2. Data Processing ---
  useEffect(() => {
    if (!repo) return;

    // --- A. Build Maps ---
    const fileMap = new Map<string, string>();
    repo.files.forEach(f => fileMap.set(f.name, f.id));
    repo.files.forEach(f => fileMap.set(f.name.replace('.md', ''), f.id)); 
    const idToName = new Map<string, string>();
    repo.files.forEach(f => idToName.set(f.id, f.name.replace('.md', '')));

    // --- B. Build Adjacency Graph (Undirected) for Clustering ---
    // We need to know who is connected to whom regardless of direction to identify "Galaxies"
    const adj = new Map<string, string[]>();
    repo.files.forEach(f => adj.set(f.id, []));

    const rawEdges: Edge[] = [];
    const connectionCounts = new Map<string, number>(); // Count total connections (degree) per node

    repo.files.forEach(sourceFile => {
        const linkRegex = /\[\[(.*?)\]\]/g;
        let match;
        while ((match = linkRegex.exec(sourceFile.content)) !== null) {
            const targetName = match[1];
            let targetId = fileMap.get(targetName);
            if (!targetId) targetId = fileMap.get(targetName + '.md');

            if (targetId && targetId !== sourceFile.id) {
                // Update Adjacency for Clustering
                adj.get(sourceFile.id)?.push(targetId);
                adj.get(targetId)?.push(sourceFile.id);

                // Update Degree Counts
                connectionCounts.set(sourceFile.id, (connectionCounts.get(sourceFile.id) || 0) + 1);
                connectionCounts.set(targetId, (connectionCounts.get(targetId) || 0) + 1);

                rawEdges.push({
                    id: `${sourceFile.id}-${targetId}`,
                    source: sourceFile.id,
                    target: targetId,
                    type: 'custom-delete', 
                    animated: true,
                    style: { strokeWidth: 1 }, // Color will be set later based on cluster
                    markerEnd: { type: MarkerType.ArrowClosed },
                    data: {
                        sourceName: sourceFile.name.replace('.md', ''),
                        targetName: idToName.get(targetId) || targetName,
                        onDelete: () => {
                            if (onDisconnectNodes) onDisconnectNodes(sourceFile.id, targetId!);
                        }
                    },
                });
            }
        }
    });

    // --- C. Identify Connected Components (Clusters) ---
    const visited = new Set<string>();
    const clusters: string[][] = []; // Array of arrays of nodeIDs

    repo.files.forEach(file => {
        if (!visited.has(file.id)) {
            const componentNodes: string[] = [];
            const queue = [file.id];
            visited.add(file.id);

            while(queue.length > 0) {
                const curr = queue.shift()!;
                componentNodes.push(curr);

                // Check neighbors
                const neighbors = adj.get(curr) || [];
                neighbors.forEach(neighbor => {
                    if (!visited.has(neighbor)) {
                        visited.add(neighbor);
                        queue.push(neighbor);
                    }
                });
            }
            // Only consider it a cluster if it has connections OR if it's the only node in repo
            if (componentNodes.length > 1 || repo.files.length === 1) {
                clusters.push(componentNodes);
            } else {
                // It's a true orphan
                clusters.push([file.id]);
            }
        }
    });

    // Sort clusters by size (largest first)
    clusters.sort((a, b) => b.length - a.length);

    // --- D. Build Nodes with Styles ---
    const rawNodes: Node[] = [];

    // Process each cluster
    clusters.forEach((clusterNodes, clusterIndex) => {
        // Determine Palette for this cluster
        const palette = CLUSTER_PALETTES[clusterIndex % CLUSTER_PALETTES.length];

        // Find the "Mother Theme" (Max Degree) in this cluster
        let maxDegree = -1;
        let motherNodeId = '';

        clusterNodes.forEach(nodeId => {
            const degree = connectionCounts.get(nodeId) || 0;
            // Prefer README as mother if present, else max degree
            const isReadme = idToName.get(nodeId)?.toLowerCase() === 'readme';
            const weightedDegree = isReadme ? 9999 : degree;

            if (weightedDegree > maxDegree) {
                maxDegree = weightedDegree;
                motherNodeId = nodeId;
            }
        });

        // Create Nodes
        clusterNodes.forEach(nodeId => {
            const file = repo.files.find(f => f.id === nodeId);
            if (!file) return;

            const isMother = nodeId === motherNodeId && (connectionCounts.get(nodeId) || 0) > 0;
            const isOrphan = clusterNodes.length === 1 && repo.files.length > 1;
            const isReadme = file.name.toLowerCase() === 'readme.md';

            // --- Styling Logic ---
            let width = 160;
            let fontSize = 12;
            let style: React.CSSProperties = {
                background: '#030303',
                color: palette.main,
                border: `1px solid ${palette.main}`,
                boxShadow: `0 4px 6px -1px rgba(0, 0, 0, 0.5)`,
            };

            if (isReadme) {
                // Readme is always special (White/Gold)
                style = {
                    background: 'linear-gradient(135deg, #18181B 0%, #000 100%)',
                    color: '#FFD700',
                    border: '2px solid #FFD700',
                    fontWeight: '900',
                    boxShadow: '0 0 25px rgba(255, 215, 0, 0.3)',
                    textTransform: 'uppercase',
                    zIndex: 10
                };
                width = 220;
                fontSize = 14;
            } else if (isMother) {
                // Mother Theme of a Cluster (Cluster Color)
                style = {
                    background: '#0F0F11',
                    color: '#fff', // White text on cluster border
                    border: `2px solid ${palette.main}`,
                    fontWeight: 'bold',
                    boxShadow: `0 0 20px ${palette.glow}`,
                    zIndex: 5
                };
                width = 200;
                fontSize = 13;
            } else if (isOrphan) {
                 style = {
                    background: '#1a0505',
                    color: '#ff4d4d',
                    border: '1px dashed #ff4d4d',
                    opacity: 0.8
                };
            } else {
                // Child Node
                 style = {
                    background: '#030303',
                    color: '#A1A1AA',
                    border: '1px solid #27272A',
                    borderLeft: `3px solid ${palette.main}`, // Subtle color indicator
                };
            }

            rawNodes.push({
                id: file.id,
                data: { label: file.name.replace('.md', '') },
                position: { x: 0, y: 0 },
                connectable: true,
                style: {
                    borderRadius: '2px',
                    padding: '12px',
                    fontFamily: 'monospace',
                    textAlign: 'center',
                    width: width,
                    fontSize: `${fontSize}px`,
                    transition: 'all 0.3s ease',
                    ...style
                }
            });
        });
    });

    // --- E. Update Edge Colors based on Source Cluster ---
    // If Source is in Cluster X, Edge is Color X
    const coloredEdges = rawEdges.map(edge => {
        // Find which cluster the source belongs to
        const clusterIndex = clusters.findIndex(c => c.includes(edge.source));
        const palette = CLUSTER_PALETTES[clusterIndex % CLUSTER_PALETTES.length];

        // Safe spread for markerEnd
        const markerEndSafe = typeof edge.markerEnd === 'object' ? edge.markerEnd : {};

        return {
            ...edge,
            data: { ...edge.data, color: palette.main }, // Pass color to custom edge
            style: { ...edge.style, stroke: palette.main, opacity: 0.6 },
            markerEnd: { ...markerEndSafe, color: palette.main }
        } as Edge;
    });

    // Apply Layout
    const { nodes: layoutedNodes, edges: layoutedEdges } = getLayoutedElements(rawNodes, coloredEdges);
    setNodes(layoutedNodes);
    setEdges(layoutedEdges);

    setTimeout(() => {
        window.requestAnimationFrame(() => fitView({ padding: 0.2 }));
    }, 100);

  }, [repo, getLayoutedElements, setNodes, setEdges, fitView, onDisconnectNodes]);

  const onNodeClick = (_: React.MouseEvent, node: Node) => {
      navigate(`/${repo.id}/${node.id}`);
  };

  const onConnect = useCallback((params: Connection) => {
    if (params.source && params.target && onLinkNodes) {
        onLinkNodes(params.source, params.target);
    }
  }, [onLinkNodes]);

