interface GraphViewProps {
  repo: Repository;
  onAddFile: () => void;
  onLinkNodes?: (sourceId: string, targetId: string) => void;
  onDisconnectNodes?: (sourceId: string, targetId: string) => void;
}

const flowStyles = {
    background: '#030303',
};

// --- COLOR PALETTES FOR TERRITORIES ---
const CLUSTER_PALETTES = [
    { main: '#FF4D00', glow: 'rgba(255, 77, 0, 0.4)' },   // Zenith Orange
    { main: '#00E676', glow: 'rgba(0, 230, 118, 0.4)' },  // Matrix Green
    { main: '#2979FF', glow: 'rgba(41, 121, 255, 0.4)' }, // Electric Blue
    { main: '#D500F9', glow: 'rgba(213, 0, 249, 0.4)' },  // Neon Purple
    { main: '#FF1744', glow: 'rgba(255, 23, 68, 0.4)' },  // Crimson Red
    { main: '#FFEA00', glow: 'rgba(255, 234, 0, 0.4)' },  // Cyber Yellow
];

// --- Custom Edge Component ---
const CustomDeleteEdge = ({
  id,
  sourceX,
  sourceY,
  targetX,
  targetY,
  sourcePosition,
  targetPosition,
  style = {},
  markerEnd,
  data,
}: EdgeProps) => {
  const [isHovered, setIsHovered] = useState(false);
  const color = (data?.color as string) || '#52525B'; 

  const [edgePath, labelX, labelY] = getSmoothStepPath({
    sourceX,
    sourceY,
    sourcePosition,
    targetX,
    targetY,
    targetPosition,
  });

  const onEdgeClick = (evt: React.MouseEvent, id: string) => {
    evt.stopPropagation();
    if (data && typeof data.onDelete === 'function') {
        (data.onDelete as () => void)();
    }
  };

  // Safe spread for markerEnd
  const markerEndSafe = typeof markerEnd === 'object' ? markerEnd : {};

  // Dynamic Edge Style
  const activeStyle = {
      ...style,
      stroke: '#ef4444', 
      strokeWidth: 2,
      filter: 'drop-shadow(0 0 3px rgba(239, 68, 68, 0.6))',
      transition: 'all 0.3s ease',
      zIndex: 100
  };

  const defaultStyle = {
      ...style,
      stroke: color, 
      opacity: 0.5,
      strokeWidth: 1,
      transition: 'all 0.3s ease',
  };

  return (
    <>
      <BaseEdge path={edgePath} markerEnd={{...markerEndSafe, color: isHovered ? '#ef4444' : color} as any} style={isHovered ? activeStyle : defaultStyle} />
      <EdgeLabelRenderer>
        <div
          style={{
            position: 'absolute',
            transform: `translate(-50%, -50%) translate(${labelX}px,${labelY}px)`,
            fontSize: 12,
            pointerEvents: 'all',
          }}
          className="nodrag nopan group flex flex-col items-center justify-center"
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
        >
          <button
            className={`w-5 h-5 rounded-full flex items-center justify-center transition-all duration-200 border shadow-lg ${
                isHovered 
                ? 'bg-red-600 text-white border-red-500 scale-110' 
                : 'bg-black border-zenith-border opacity-0 group-hover:opacity-100 scale-90 hover:scale-100'
            }`}
            style={{ color: isHovered ? 'white' : color }}
            onClick={(event) => onEdgeClick(event, id)}
            title="Sever Connection"
          >
            <span className="leading-none mb-[1px] font-bold">×</span>
          </button>
        </div>
      </EdgeLabelRenderer>
    </>
  );
};

const GraphView: React.FC<GraphViewProps> = ({ repo, onAddFile, onLinkNodes, onDisconnectNodes }) => {
  const navigate = useNavigate();
  const [nodes, setNodes, onNodesChange] = useNodesState([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);
  const { fitView } = useReactFlow();

  const edgeTypes = useMemo(() => ({
    'custom-delete': CustomDeleteEdge,
  }), []);

  // --- 1. Layout Engine ---
  const getLayoutedElements = useCallback((nodes: Node[], edges: Edge[]) => {
    const dagreGraph = new dagre.graphlib.Graph();
    dagreGraph.setDefaultEdgeLabel(() => ({}));

    dagreGraph.setGraph({ 
        rankdir: 'LR', 
        align: 'DL',
        nodesep: 60,
        ranksep: 120 
    });

    nodes.forEach((node) => {
      const w = node.style?.width ? parseInt(node.style.width.toString()) : 180;
      const h = 60; 
      dagreGraph.setNode(node.id, { width: w, height: h });
    });

    edges.forEach((edge) => {
      dagreGraph.setEdge(edge.source, edge.target);
    });

    dagre.layout(dagreGraph);

    const layoutedNodes = nodes.map((node) => {
      const nodeWithPosition = dagreGraph.node(node.id);
      const x = nodeWithPosition ? nodeWithPosition.x : 0;
      const y = nodeWithPosition ? nodeWithPosition.y : 0;
      const w = node.style?.width ? parseInt(node.style.width.toString()) : 180;

      return {
        ...node,
        position: {
          x: x - w / 2,
          y: y - 30,
        },
      };
    });

    return { nodes: layoutedNodes, edges };
  }, []);

  // --- 2. Data Processing (The "Boss vs Clerk" Logic) ---
  useEffect(() => {
    if (!repo) return;

    // A. Maps & Basic Stats
    const fileMap = new Map<string, string>();
    repo.files.forEach(f => fileMap.set(f.name, f.id));
    repo.files.forEach(f => fileMap.set(f.name.replace('.md', ''), f.id)); 
    const idToName = new Map<string, string>();
    repo.files.forEach(f => idToName.set(f.id, f.name.replace('.md', '')));

    const inDegree = new Map<string, number>();
    const outDegree = new Map<string, number>();
    const neighbors = new Map<string, string[]>(); // Directed neighbors

    repo.files.forEach(f => {
        inDegree.set(f.id, 0);
        outDegree.set(f.id, 0);
        neighbors.set(f.id, []);
    });

    // B. Parse Links & Build Directed Graph
    const rawEdges: any[] = [];
    repo.files.forEach(sourceFile => {
        const linkRegex = /\[\[(.*?)\]\]/g;
        let match;
        while ((match = linkRegex.exec(sourceFile.content)) !== null) {
            const targetName = match[1];
            let targetId = fileMap.get(targetName);
            if (!targetId) targetId = fileMap.get(targetName + '.md');

            if (targetId && targetId !== sourceFile.id) {
                // Update Degrees
                outDegree.set(sourceFile.id, (outDegree.get(sourceFile.id) || 0) + 1);
                inDegree.set(targetId, (inDegree.get(targetId) || 0) + 1);
                neighbors.get(sourceFile.id)?.push(targetId);

                rawEdges.push({
                    id: `${sourceFile.id}-${targetId}`,
                    source: sourceFile.id,
                    target: targetId,
                    type: 'custom-delete', 
                    animated: true,
                    style: { strokeWidth: 1 }, 
                    markerEnd: { type: MarkerType.ArrowClosed },
                    data: {
                        sourceName: sourceFile.name.replace('.md', ''),
                        targetName: idToName.get(targetId) || targetName,
                        onDelete: () => {
                            if (onDisconnectNodes) onDisconnectNodes(sourceFile.id, targetId!);
                        }
                    },
                });
            }
        }
    });

    // C. Identify "Mother Themes" (Seeds)
    // Logic: 
    // 1. In-Degree == 0 (Absolute Root)
    // 2. README is always a seed.
    // 3. High Out-Degree (Local Hubs) if unconnected to existing seeds.

    const seeds: string[] = [];
    const seedColorMap = new Map<string, string>();

    // 1. README check
    const readme = repo.files.find(f => f.name.toLowerCase() === 'readme.md');
    if (readme) seeds.push(readme.id);

    // 2. True Roots (In-Degree 0)
    repo.files.forEach(f => {
        if (f.id !== readme?.id && (inDegree.get(f.id) || 0) === 0) {
            // Only count as seed if it connects to something (Out-Degree > 0)
            // Or if it's the only file in the repo.
            if ((outDegree.get(f.id) || 0) > 0 || repo.files.length === 1) {
                seeds.push(f.id);
            }
        }
    });

    // 3. Fallback: If we have separate clusters but no true roots (cycles), find local heavy hitters
    // (This part is complex, simplified here: we trust the Root detection mostly)

    // Assign Colors to Seeds
    seeds.forEach((seedId, idx) => {
        seedColorMap.set(seedId, CLUSTER_PALETTES[idx % CLUSTER_PALETTES.length].main);
    });

    // D. Propagate Colors (Territory Claim)
    // BFS from Seeds to children. 
    // If a node is reached by Seed A, it becomes Color A.
    // If a node is reached by Seed A and Seed B, it keeps the color of the *first* one that reached it (shortest path)
    // or we can make it a "Bridge" color. For now, first claim wins to keep distinct visual islands.
    const nodeColors = new Map<string, string>();
    const queue: string[] = [...seeds];

    // Initialize seeds
    seeds.forEach(s => nodeColors.set(s, seedColorMap.get(s)!));

    while (queue.length > 0) {
        const currentId = queue.shift()!;
        const currentColor = nodeColors.get(currentId)!;

        const myNeighbors = neighbors.get(currentId) || [];
        myNeighbors.forEach(targetId => {
            if (!nodeColors.has(targetId)) {
                nodeColors.set(targetId, currentColor);
                queue.push(targetId);
            }
        });
    }

    // Default color for orphans or unconnected cycles
    repo.files.forEach(f => {
        if (!nodeColors.has(f.id)) {
            nodeColors.set(f.id, '#52525B'); // Grey for neutral/orphans
        }
    });

    // E. Build Nodes
    const rawNodes: Node[] = [];
    repo.files.forEach(file => {
        const isReadme = file.name.toLowerCase() === 'readme.md';
        const isSeed = seeds.includes(file.id);
        const myColor = nodeColors.get(file.id) || '#52525B';
        const myIn = inDegree.get(file.id) || 0;
        const myOut = outDegree.get(file.id) || 0;

        // F. Sizing Logic (The "Clerk" Fix)
        // Base size
        // Bonus for Out-Degree (Management Power) -> High multiplier
        // Small Bonus for In-Degree (Clerk Work) -> Low multiplier

        let width = 160;
        let fontSize = 12;
        let zIndex = 1;

        if (isReadme) {
            width = 240;
            fontSize = 16;
            zIndex = 10;
        } else if (isSeed) {
            // Mother Themes are large
            width = 200 + (myOut * 5); 
            fontSize = 14;
            zIndex = 5;
        } else {
            // Standard nodes
            // If I have high Out-Degree, I am a sub-manager, make me bigger
            // If I have high In-Degree, I am just a reference doc, don't make me huge
            width = 150 + (myOut * 10) + (Math.min(myIn, 10) * 2);
        }

        // Cap width
        width = Math.min(width, 300);

        // Styling
        let style: React.CSSProperties = {
            background: '#030303',
            color: myColor,
            border: `1px solid ${myColor}`,
            boxShadow: `0 4px 6px -1px rgba(0, 0, 0, 0.5)`,
            borderRadius: '2px',
            padding: '12px',
            fontFamily: 'monospace',
            textAlign: 'center',
            width: width,
            fontSize: `${fontSize}px`,
            transition: 'all 0.3s ease',
            zIndex
        };

        if (isReadme) {
            style = {
                ...style,
                background: 'linear-gradient(135deg, #18181B 0%, #000 100%)',
                color: '#FFD700',
                border: '2px solid #FFD700',
                fontWeight: '900',
                boxShadow: '0 0 30px rgba(255, 215, 0, 0.2)',
                textTransform: 'uppercase',
            };
        } else if (isSeed) {
            // Mother Theme Style
            style = {
                ...style,
                background: '#0F0F11',
                color: '#fff',
                border: `2px solid ${myColor}`,
                fontWeight: 'bold',
                boxShadow: `0 0 20px ${myColor}40`, // 40 is hex opacity
            };
        } else if (myIn === 0 && myOut === 0) {
             // True Orphan
             style = {
                ...style,
                border: '1px dashed #52525B',
                color: '#52525B',
                opacity: 0.6
            };
        }

        rawNodes.push({
            id: file.id,
            data: { label: file.name.replace('.md', '') },
            position: { x: 0, y: 0 },
            connectable: true,
            style
        });
    });

    // G. Color Edges based on Source Node
    const coloredEdges = rawEdges.map(edge => {
        const sourceColor = nodeColors.get(edge.source) || '#52525B';
        const markerEndSafe = typeof edge.markerEnd === 'object' ? edge.markerEnd : {};

        return {
            ...edge,
            data: { ...edge.data, color: sourceColor },
            style: { ...edge.style, stroke: sourceColor },
            markerEnd: { ...markerEndSafe, color: sourceColor }
        };
    });

    // Apply Layout
    const { nodes: layoutedNodes, edges: layoutedEdges } = getLayoutedElements(rawNodes, coloredEdges);
    setNodes(layoutedNodes);
    setEdges(layoutedEdges);

    setTimeout(() => {
        window.requestAnimationFrame(() => fitView({ padding: 0.2 }));
    }, 100);

  }, [repo, getLayoutedElements, setNodes, setEdges, fitView, onDisconnectNodes]);

  const onNodeClick = (_: React.MouseEvent, node: Node) => {
      navigate(`/${repo.id}/${node.id}`);
  };

  const onConnect = useCallback((params: Connection) => {
    if (params.source && params.target && onLinkNodes) {
        onLinkNodes(params.source, params.target);
    }
  }, [onLinkNodes]);

  const onEdgesDelete = useCallback((deletedEdges: Edge[]) => {
      if (onDisconnectNodes) {
          deletedEdges.forEach((edge) => {
              onDisconnectNodes(edge.source, edge.target);
          });
      }
  }, [onDisconnectNodes]);

  return (
    <div className="w-full h-[calc(100vh-180px)] border border-zenith-border bg-zenith-bg relative group">

        {/* Graph Toolbar */}
        <div className="absolute top-4 right-4 z-10 flex gap-2">
            <button 
                onClick={onAddFile}
                className="bg-zenith-orange text-black px-4 py-2 font-mono text-xs font-bold uppercase tracking-widest hover:bg-white transition-colors shadow-lg flex items-center gap-2"
            >
                <Icons.Plus size={14} /> Add Node
            </button>
        </div>

        {/* Empty State */}
        {nodes.length === 0 && (
             <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
                 <div className="text-center">
                     <div className="text-zenith-muted font-mono text-xs uppercase tracking-widest mb-2">No Data Points Detected</div>
                     <div className="text-zenith-orange/50 font-mono text-[10px]">Add a file to initialize graph</div>
                 </div>
             </div>
        )}

        <ReactFlow
            nodes={nodes}
            edges={edges}
            onNodesChange={onNodesChange}
            onEdgesChange={onEdgesChange}
            onNodeClick={onNodeClick}
            onConnect={onConnect}
            onEdgesDelete={onEdgesDelete} 
            deleteKeyCode={['Backspace', 'Delete']} 
            edgeTypes={edgeTypes}
            connectionLineType={ConnectionLineType.SmoothStep}
            fitView
            style={flowStyles}
            minZoom={0.2}
            maxZoom={4}
            defaultEdgeOptions={{ 
                type: 'custom-delete',
                markerEnd: { type: MarkerType.ArrowClosed } 
            }}
        >
            <Background color="#27272A" gap={20} size={1} />
            <Controls 
                className="bg-zenith-surface border border-zenith-border fill-white text-white" 
                style={{ borderRadius: 0, padding: 2 }} 
            />
            <MiniMap 
                nodeStrokeColor="#27272A"
                nodeColor="#18181B"
                maskColor="rgba(0,0,0, 0.7)"
                style={{ backgroundColor: '#030303', border: '1px solid #27272A' }}
            />
        </ReactFlow>

        {/* HUD Overlay */}
        <div className="absolute bottom-4 left-4 pointer-events-none">
            <div className="font-mono text-[10px] text-zenith-orange uppercase tracking-widest flex items-center gap-2">
                <Icons.Zap size={10} className="animate-pulse"/>
                PROTOCOL: Source Propagation // {nodes.length} Nodes
            </div>
            <div className="font-mono text-[10px] text-zenith-muted mt-1">
                Drag handles to link nodes | Click '×' on line to unlink
            </div>
        </div>
    </div>
  );
};

