    // A. Maps & Basic Stats
    const fileMap = new Map<string, string>();
    repo.files.forEach(f => fileMap.set(f.name, f.id));
    repo.files.forEach(f => fileMap.set(f.name.replace('.md', ''), f.id)); 
    const idToName = new Map<string, string>();
    repo.files.forEach(f => idToName.set(f.id, f.name.replace('.md', '')));

    const inDegree = new Map<string, number>();
    const outDegree = new Map<string, number>();
    const neighbors = new Map<string, string[]>(); // Undirected for Clustering
    const directedNeighbors = new Map<string, string[]>(); // Directed for Logic

    repo.files.forEach(f => {
        inDegree.set(f.id, 0);
        outDegree.set(f.id, 0);
        neighbors.set(f.id, []);
        directedNeighbors.set(f.id, []);
    });

    // B. Parse Links
    const rawEdges: any[] = [];
    repo.files.forEach(sourceFile => {
        const linkRegex = /\[\[(.*?)\]\]/g;
        let match;
        while ((match = linkRegex.exec(sourceFile.content)) !== null) {
            const targetName = match[1];
            let targetId = fileMap.get(targetName);
            if (!targetId) targetId = fileMap.get(targetName + '.md');

            if (targetId && targetId !== sourceFile.id) {
                outDegree.set(sourceFile.id, (outDegree.get(sourceFile.id) || 0) + 1);
                inDegree.set(targetId, (inDegree.get(targetId) || 0) + 1);

                // Undirected neighbors for Cluster discovery
                neighbors.get(sourceFile.id)?.push(targetId);
                neighbors.get(targetId)?.push(sourceFile.id);

                // Directed neighbors
                directedNeighbors.get(sourceFile.id)?.push(targetId);

                rawEdges.push({
                    id: `${sourceFile.id}-${targetId}`,
                    source: sourceFile.id,
                    target: targetId,
                    type: 'custom-delete', 
                    animated: true,
                    style: { strokeWidth: 1 }, 
                    markerEnd: { type: MarkerType.ArrowClosed },
                    data: {
                        sourceName: sourceFile.name.replace('.md', ''),
                        targetName: idToName.get(targetId) || targetName,
                        onDelete: () => {
                            if (onDisconnectNodes) onDisconnectNodes(sourceFile.id, targetId!);
                        }
                    },
                });
            }
        }
    });

    // C. IDENTIFY CLUSTERS (Connected Components)
    // We do this to ensure even circular dependencies get a "Realm" color
    const visited = new Set<string>();
    const clusters: string[][] = [];

    repo.files.forEach(file => {
        if (!visited.has(file.id)) {
            const cluster: string[] = [];
            const queue = [file.id];
            visited.add(file.id);

            while (queue.length > 0) {
                const node = queue.shift()!;
                cluster.push(node);

                const myNeighbors = neighbors.get(node) || [];
                myNeighbors.forEach(n => {
                    if (!visited.has(n)) {
                        visited.add(n);
                        queue.push(n);
                    }
                });
            }
            clusters.push(cluster);
        }
    });

    // Sort clusters by size
    clusters.sort((a, b) => b.length - a.length);

    // D. ASSIGN COLORS TO CLUSTERS (The "Empire" Logic)
    const nodeColors = new Map<string, string>();
    const seeds = new Set<string>();

    // Iterate through every cluster and assign it a distinct color from palette
    clusters.forEach((clusterNodes, idx) => {
        const palette = CLUSTER_PALETTES[idx % CLUSTER_PALETTES.length];

        // Pick a "King" for this cluster to be the visual anchor (Seed)
        // Priority: 1. README, 2. Max Out-Degree (Source), 3. Max In-Degree (Hub)
        let kingId = clusterNodes[0];
        let maxScore = -1;

        clusterNodes.forEach(nodeId => {
            const isReadme = idToName.get(nodeId)?.toLowerCase() === 'readme';
            const outD = outDegree.get(nodeId) || 0;
            const inD = inDegree.get(nodeId) || 0;

            // Score formula: Readme is god (1000), Sources are Kings (Out * 2), Hubs are Barons (In * 1)
            const score = (isReadme ? 1000 : 0) + (outD * 2) + inD;

            if (score > maxScore) {
                maxScore = score;
                kingId = nodeId;
            }
        });

        seeds.add(kingId);

        // Assign Color to everyone in this cluster
        clusterNodes.forEach(nodeId => {
            nodeColors.set(nodeId, palette.main);
        });
    });


    // E. Build Nodes
    const rawNodes: Node[] = [];
    repo.files.forEach(file => {
        const isReadme = file.name.toLowerCase() === 'readme.md';
        const isSeed = seeds.has(file.id);
        const myColor = nodeColors.get(file.id) || '#52525B';
        const myIn = inDegree.get(file.id) || 0;
        const myOut = outDegree.get(file.id) || 0;

        // Size Calculation
        let width = 160;
        let fontSize = 12;
        let zIndex = 1;

        if (isReadme) {
            width = 240;
            fontSize = 16;
            zIndex = 10;
        } else if (isSeed) {
            // Cluster Leaders are large
            width = 180 + (myOut * 5); 
            fontSize = 14;
            zIndex = 5;
        } else {
            // Regular Nodes
            width = 140 + (myOut * 5) + (Math.min(myIn, 5) * 2);
        }
        width = Math.min(width, 300);

        // Styling
        let style: React.CSSProperties = {
            background: '#030303',
            color: myColor,
            border: `1px solid ${myColor}`,
            boxShadow: `0 4px 10px -2px rgba(0, 0, 0, 0.8)`,
            borderRadius: '2px',
            padding: '12px',
            fontFamily: 'monospace',
            textAlign: 'center',
            width: width,
            fontSize: `${fontSize}px`,
            transition: 'all 0.3s ease',
            zIndex
        };

        if (isReadme) {
            style = {
                ...style,
                background: 'linear-gradient(135deg, #18181B 0%, #000 100%)',
                color: '#FFD700',
                border: '2px solid #FFD700',
                fontWeight: '900',
                boxShadow: '0 0 30px rgba(255, 215, 0, 0.2)',
                textTransform: 'uppercase',
            };
        } else if (isSeed) {
            style = {
                ...style,
                background: '#0F0F11',
                color: '#fff',
                border: `2px solid ${myColor}`,
                fontWeight: 'bold',
                boxShadow: `0 0 25px ${myColor}40`,
            };
        }

        rawNodes.push({
            id: file.id,
            data: { label: file.name.replace('.md', '') },
            position: { x: 0, y: 0 },
            connectable: true,
            style
        });
    });

    // F. Edge Coloring (Diplomacy)
    const coloredEdges = rawEdges.map(edge => {
        const sourceColor = nodeColors.get(edge.source) || '#52525B';
        const targetColor = nodeColors.get(edge.target) || '#52525B';

        const markerEndSafe = typeof edge.markerEnd === 'object' ? edge.markerEnd : {};

        // If colors are different, we technically could do a gradient, but React Flow gradients are complex.
        // Simple logic: Source colors the line (Outbound influence).

        return {
            ...edge,
            data: { ...edge.data, color: sourceColor },
            style: { ...edge.style, stroke: sourceColor },
            markerEnd: { ...markerEndSafe, color: sourceColor }
        };
    });

    // Apply Layout
    const { nodes: layoutedNodes, edges: layoutedEdges } = getLayoutedElements(rawNodes, coloredEdges);
    setNodes(layoutedNodes);
    setEdges(layoutedEdges);

    setTimeout(() => {
        window.requestAnimationFrame(() => fitView({ padding: 0.2 }));
    }, 100);

  }, [repo, getLayoutedElements, setNodes, setEdges, fitView, onDisconnectNodes]);

  const onNodeClick = (_: React.MouseEvent, node: Node) => {
      navigate(`/${repo.id}/${node.id}`);
  };

  const onConnect = useCallback((params: Connection) => {
    if (params.source && params.target && onLinkNodes) {
        onLinkNodes(params.source, params.target);
    }
  }, [onLinkNodes]);

  const onEdgesDelete = useCallback((deletedEdges: Edge[]) => {
      if (onDisconnectNodes) {
          deletedEdges.forEach((edge) => {
              onDisconnectNodes(edge.source, edge.target);
          });
      }
  }, [onDisconnectNodes]);

  return (
    <div className="w-full h-[calc(100vh-180px)] border border-zenith-border bg-zenith-bg relative group">

        {/* Graph Toolbar */}
        <div className="absolute top-4 right-4 z-10 flex gap-2">
            <button 
                onClick={onAddFile}
                className="bg-zenith-orange text-black px-4 py-2 font-mono text-xs font-bold uppercase tracking-widest hover:bg-white transition-colors shadow-lg flex items-center gap-2"
            >
                <Icons.Plus size={14} /> Add Node
            </button>
        </div>

        {/* Empty State */}
        {nodes.length === 0 && (
             <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
                 <div className="text-center">
                     <div className="text-zenith-muted font-mono text-xs uppercase tracking-widest mb-2">No Data Points Detected</div>
                     <div className="text-zenith-orange/50 font-mono text-[10px]">Add a file to initialize graph</div>
                 </div>
             </div>
        )}

        <ReactFlow
            nodes={nodes}
            edges={edges}
            onNodesChange={onNodesChange}
            onEdgesChange={onEdgesChange}
            onNodeClick={onNodeClick}
            onConnect={onConnect}
            onEdgesDelete={onEdgesDelete} 
            deleteKeyCode={['Backspace', 'Delete']} 
            edgeTypes={edgeTypes}
            connectionLineType={ConnectionLineType.SmoothStep}
            fitView
            style={flowStyles}
            minZoom={0.2}
            maxZoom={4}
            defaultEdgeOptions={{ 
                type: 'custom-delete',
                markerEnd: { type: MarkerType.ArrowClosed } 
            }}
        >
            <Background color="#27272A" gap={20} size={1} />
            <Controls 
                className="bg-zenith-surface border border-zenith-border fill-white text-white" 
                style={{ borderRadius: 0, padding: 2 }} 
            />
            <MiniMap 
                nodeStrokeColor="#27272A"
                nodeColor="#18181B"
                maskColor="rgba(0,0,0, 0.7)"
                style={{ backgroundColor: '#030303', border: '1px solid #27272A' }}
            />
        </ReactFlow>

        {/* HUD Overlay */}
        <div className="absolute bottom-4 left-4 pointer-events-none">
            <div className="font-mono text-[10px] text-zenith-orange uppercase tracking-widest flex items-center gap-2">
                <Icons.Zap size={10} className="animate-pulse"/>
                PROTOCOL: Empire Claims // {nodes.length} Nodes
            </div>
            <div className="font-mono text-[10px] text-zenith-muted mt-1">
                Drag handles to link nodes | Click '×' on line to unlink
            </div>
        </div>
    </div>
  );
};

