import React, { useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { Repository } from '../types';
import { Icons } from '../components/Icon';
import MarkdownPreview from '../components/MarkdownPreview';
import DeleteConfirmModal from '../components/DeleteConfirmModal';
import RepoSettingsModal from '../components/RepoSettingsModal';
import GraphViewWrapper from '../components/GraphView';

interface RepositoryViewProps {
  repos: Repository[];
  onAddFile: (repoId: string, filename: string) => void;
  onDeleteRepo: (repoId: string) => void;
  onUpdateRepo: (repoId: string, name: string, description: string) => void;
  onUpdateFile: (repoId: string, fileId: string, content: string) => void; // Added for graph connection
  isAuthenticated: boolean;
}

const RepositoryView: React.FC<RepositoryViewProps> = ({ repos, onAddFile, onDeleteRepo, onUpdateRepo, onUpdateFile, isAuthenticated }) => {
  const { repoId } = useParams<{ repoId: string }>();
  const navigate = useNavigate();
  const repo = repos.find(r => r.id === repoId);

  const [showAddFile, setShowAddFile] = useState(false);
  const [newFileName, setNewFileName] = useState('');

  // View State: 'list' or 'graph'
  const [viewMode, setViewMode] = useState<'list' | 'graph'>('list');

  // Graph Scope: 'local' or 'global' - Persisted preference
  const [graphScope, setGraphScopeState] = useState<'local' | 'global'>(() => {
      return (localStorage.getItem('gitnotes_graph_scope') as 'local' | 'global') || 'local';
  });

  const setGraphScope = (scope: 'local' | 'global') => {
      setGraphScopeState(scope);
      localStorage.setItem('gitnotes_graph_scope', scope);
  };

  // Modal states
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);

  if (!repo) {
    return <div className="h-screen flex items-center justify-center font-mono text-zenith-orange">ERROR: MODULE NOT FOUND</div>;
  }

  const handleAddFile = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newFileName.trim()) return;
    let name = newFileName.trim();
    if (!name.endsWith('.md')) name += '.md';

    onAddFile(repo.id, name);
    setShowAddFile(false);
    setNewFileName('');
  };

  const handleDeleteConfirm = () => {
    onDeleteRepo(repo.id);
    navigate('/');
  };

  const handleConnectNodes = (sourceId: string, targetId: string) => {
      if (!isAuthenticated) return;

      // Find files across ALL repos if global, or just local if local logic (though helper keeps it simple)
      let sourceFile = repo.files.find(f => f.id === sourceId);
      let targetFile = repo.files.find(f => f.id === targetId);
      let targetRepoId = repo.id;

      // Global Search for node connection
      if (!sourceFile || !targetFile) {
          repos.forEach(r => {
              const s = r.files.find(f => f.id === sourceId);
              if (s) sourceFile = s;
              const t = r.files.find(f => f.id === targetId);
              if (t) {
                  targetFile = t;
                  targetRepoId = r.id;
              }
          });
      }

      if (sourceFile && targetFile) {
          const linkName = targetFile.name.replace('.md', '');
          // Check if link already exists to prevent duplication
          if (!sourceFile.content.includes(`[[${linkName}]]`)) {
             const newContent = sourceFile.content + `\n\nRelated: [[${linkName}]]`;
             // We need to find the repo ID of the SOURCE file to update it
             const sourceRepo = repos.find(r => r.files.some(f => f.id === sourceId));
             if (sourceRepo) {
                 onUpdateFile(sourceRepo.id, sourceId, newContent);
             }
          }
      }
  };

  const handleDisconnectNodes = (sourceId: string, targetId: string) => {
      if (!isAuthenticated) return;

      let sourceFile = repo.files.find(f => f.id === sourceId);
      let targetFile = repo.files.find(f => f.id === targetId);

      // Global Search
      if (!sourceFile || !targetFile) {
          repos.forEach(r => {
              const s = r.files.find(f => f.id === sourceId);
              if (s) sourceFile = s;
              const t = r.files.find(f => f.id === targetId);
              if (t) targetFile = t;
          });
      }

      if (sourceFile && targetFile) {
          const linkName = targetFile.name.replace('.md', '');
          const escapedLinkName = linkName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

          const lines = sourceFile.content.split('\n');
          const newLines = lines.filter(line => {
              const linkRegex = new RegExp(`\\[\\[${escapedLinkName}(?:\\.md)?\\]\\]`, 'i');
              if (!linkRegex.test(line)) return true;
              const listItemRegex = new RegExp(`^\\s*(?:[-*+]|\\d+\\.)\\s*\\[\\[${escapedLinkName}(?:\\.md)?\\]\\].*$`, 'i');
              if (listItemRegex.test(line)) return false; 
              const propRegex = new RegExp(`^\\s*(?:Related|Parent|Child|See|Source|Upstream|Ref)\\s*:?\\s*\\[\\[${escapedLinkName}(?:\\.md)?\\]\\].*$`, 'i');
              if (propRegex.test(line)) return false; 
              if (line.trim() === `[[${linkName}]]` || line.trim() === `[[${linkName}.md]]`) return false;
              return true;
          }).map(line => {
              const linkRegex = new RegExp(`\\[\\[(${escapedLinkName})(?:\\.md)?\\]\\]`, 'gi');
              return line.replace(linkRegex, '$1'); 
          });

          let newContent = newLines.join('\n');
          newContent = newContent.replace(/\n{3,}/g, '\n\n').trim();

          const sourceRepo = repos.find(r => r.files.some(f => f.id === sourceId));
          if (sourceRepo) {
            onUpdateFile(sourceRepo.id, sourceId, newContent);
          }
      }
  };

  // Find README for preview
  const readme = repo.files.find(f => f.name.toLowerCase() === 'readme.md');

  return (
    <div className="min-h-screen bg-zenith-bg p-6 md:p-12 max-w-[1600px] mx-auto">

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 mb-8 border-b border-zenith-border pb-6">
        <div>
            <div className="flex items-center gap-2 font-mono text-xs text-zenith-muted mb-2">
                <Link to="/" className="hover:text-zenith-orange">ROOT</Link>
                <span>/</span>
                <span className="text-white">{repo.id.toUpperCase()}</span>
            </div>
            <h1 className="text-4xl font-bold tracking-tight text-white mb-2">{repo.name}</h1>
            <p className="text-zenith-muted font-mono text-sm max-w-2xl">{repo.description}</p>
        </div>

        {isAuthenticated && (
          <div className="flex items-center gap-4">
              {/* View Toggle */}
              <div className="flex border border-zenith-border p-0.5 bg-zenith-surface mr-4">
                 <button 
                    onClick={() => setViewMode('list')}
                    className={`px-3 py-2 text-xs font-mono uppercase transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="List View"
                 >
                    <Icons.List size={14} />
                 </button>
                 <button 
                    onClick={() => setViewMode('graph')}
                    className={`px-3 py-2 text-xs font-mono uppercase transition-all flex items-center gap-2 border-l border-zenith-border ${viewMode === 'graph' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Constellation View"
                 >
                    <Icons.Network size={14} />
                 </button>
              </div>

              <button 
                  onClick={() => setIsSettingsModalOpen(true)}
                  className="bg-zenith-surface border border-zenith-border text-zenith-muted px-3 py-2 text-xs font-mono uppercase hover:text-white hover:border-white transition-colors duration-75 flex items-center gap-2"
                  title="Configure Module"
              >
                  <Icons.Settings size={14} />
              </button>
              <div className="w-px h-6 bg-zenith-border"></div>
              <button 
                  onClick={() => setShowAddFile(true)}
                  className="bg-zenith-surface border border-zenith-border text-white px-4 py-2 text-xs font-mono tracking-widest uppercase hover:bg-white hover:text-black transition-colors duration-75 flex items-center gap-2"
              >
                  <Icons.Plus size={14} /> Add File
              </button>
              <button 
                  onClick={() => setIsDeleteModalOpen(true)}
                  className="border border-zenith-border text-zenith-muted px-4 py-2 text-xs font-mono tracking-widest uppercase hover:border-zenith-orange hover:text-zenith-orange transition-colors duration-75"
              >
                  Delete
              </button>
          </div>
        )}
      </div>

      {/* Add File Input (Global for this view) */}
      {showAddFile && isAuthenticated && (
        <div className="mb-8 p-6 border border-zenith-orange bg-zenith-surface/50 animate-in slide-in-from-top-2">
           <form onSubmit={handleAddFile} className="flex gap-4 items-center">
               <span className="font-mono text-zenith-orange text-lg">/</span>
               <input 
                 autoFocus
                 type="text" 
                 placeholder="filename.md" 
                 className="bg-transparent border-b border-zenith-border text-white p-2 font-mono text-sm flex-1 outline-none focus:border-zenith-orange"
                 value={newFileName}
                 onChange={e => setNewFileName(e.target.value)}
               />
               <button type="submit" className="text-zenith-orange font-mono text-xs uppercase hover:underline">Execute</button>
               <button type="button" onClick={() => setShowAddFile(false)} className="text-zenith-muted font-mono text-xs uppercase hover:text-white">Cancel</button>
           </form>
        </div>
      )}

      {/* Main Content Switcher */}
      {viewMode === 'graph' ? (
          <div className="border border-zenith-border bg-zenith-surface/20 animate-in fade-in duration-500 relative">

             {/* Scope Toggle (Floating inside Graph) */}
             <div className="absolute top-4 left-4 z-20 flex gap-2">
                <button 
                   onClick={() => setGraphScope('local')}
                   className={`px-3 py-1 text-[10px] font-mono uppercase tracking-widest border transition-colors ${graphScope === 'local' ? 'bg-zenith-orange text-black border-zenith-orange' : 'bg-black text-zenith-muted border-zenith-border hover:border-white'}`}
                >
                   Local Sector
                </button>
                <button 
                   onClick={() => setGraphScope('global')}
                   className={`px-3 py-1 text-[10px] font-mono uppercase tracking-widest border transition-colors ${graphScope === 'global' ? 'bg-zenith-green text-black border-zenith-green' : 'bg-black text-zenith-muted border-zenith-border hover:border-white'}`}
                >
                   Galaxy View
                </button>
             </div>

             <GraphViewWrapper 
                activeRepoId={repo.id}
                repos={repos} // Pass ALL repos now
                scope={graphScope}
                onAddFile={() => setShowAddFile(true)}
                onLinkNodes={handleConnectNodes}
                onDisconnectNodes={handleDisconnectNodes}
             />
          </div>
      ) : (
          <div className="grid lg:grid-cols-3 gap-8 animate-in fade-in duration-300">
              {/* File List Table */}
              <div className="lg:col-span-2">
                <div className="border border-zenith-border">
                    <div className="bg-zenith-surface border-b border-zenith-border px-4 py-2 font-mono text-[10px] tracking-widest text-zenith-muted uppercase flex justify-between">
                        <span>File Index</span>
                        <span>Count: {repo.files.length}</span>
                    </div>

                    <div className="divide-y divide-zenith-border bg-black">
                        {repo.files.map(file => (
                            <div key={file.id} className="group flex items-center justify-between p-4 hover:bg-zenith-surface transition-colors duration-75">
                                <div className="flex items-center gap-4">
                                    <Icons.File size={16} className="text-zenith-muted group-hover:text-zenith-orange" />
                                    <Link to={`/${repo.id}/${file.id}`} className="font-mono text-sm text-zenith-text group-hover:text-white group-hover:underline decoration-zenith-orange underline-offset-4">
                                        {file.name}
                                    </Link>
                                </div>
                                <div className="flex items-center gap-6">
                                    <span className="font-mono text-[10px] text-zenith-muted hidden sm:block">
                                        {(file.size / 1024).toFixed(2)} KB
                                    </span>
                                    <span className="font-mono text-[10px] text-zenith-muted">
                                        {new Date(file.updatedAt).toLocaleDateString()}
                                    </span>
                                </div>
                            </div>
                        ))}
                        {repo.files.length === 0 && (
                            <div className="p-8 text-center font-mono text-xs text-zenith-muted uppercase">
                                No files detected in sector
                            </div>
                        )}
                    </div>
                </div>
              </div>

              {/* README Preview Panel */}
              <div className="lg:col-span-1">
                {readme ? (
                    <div className="border border-zenith-border sticky top-20">
                        <div className="bg-zenith-surface border-b border-zenith-border px-4 py-2 font-mono text-[10px] tracking-widest text-zenith-muted uppercase flex items-center gap-2">
                            <div className="w-2 h-2 bg-zenith-green rounded-full"></div>
                            <span>Preview: README.md</span>
                        </div>
                        <div className="p-6 bg-zenith-bg max-h-[calc(100vh-200px)] overflow-y-auto">
                            <MarkdownPreview content={readme.content} />
                        </div>
                    </div>
                ) : (
                    <div className="border border-zenith-border border-dashed p-8 text-center">
                        <span className="font-mono text-xs text-zenith-muted">NO README DETECTED</span>
                    </div>
                )}
              </div>
          </div>
      )}

      <DeleteConfirmModal 
        isOpen={isDeleteModalOpen}
        onClose={() => setIsDeleteModalOpen(false)}
        onConfirm={handleDeleteConfirm}
        title="Delete Module"
        itemName={repo.name}
        warningText="Deleting this repository will permanently erase all contained files and version history. This action cannot be reversed."
      />

      <RepoSettingsModal 
        isOpen={isSettingsModalOpen}
        onClose={() => setIsSettingsModalOpen(false)}
        onSave={(name, desc) => onUpdateRepo(repo.id, name, desc)}
        initialName={repo.name}
        initialDesc={repo.description}
      />
    </div>
  );
};

export default RepositoryView;

import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { 
  ReactFlow, 
  useNodesState, 
  useEdgesState, 
  Background, 
  Controls,
  MiniMap,
  Node,
  Edge,
  MarkerType,
  ConnectionLineType,
  useReactFlow,
  Connection,
  ReactFlowProvider,
  BaseEdge,
  EdgeLabelRenderer,
  EdgeProps,
  getSmoothStepPath
} from '@xyflow/react';
import dagre from 'dagre';
import { Repository } from '../types';
import { useNavigate } from 'react-router-dom';
import { Icons } from './Icon';

interface GraphViewProps {
  repos: Repository[]; // Now receives all repos
  activeRepoId: string; // The repo currently being viewed (for filtering in local mode)
  scope: 'local' | 'global';
  onAddFile: () => void;
  onLinkNodes?: (sourceId: string, targetId: string) => void;
  onDisconnectNodes?: (sourceId: string, targetId: string) => void;
}

const flowStyles = {
    background: '#030303',
};

// --- COLOR PALETTES ---
const SOVEREIGN_PALETTES = [
    '#FF4D00', // Zenith Orange
    '#00E676', // Matrix Green
    '#2979FF', // Electric Blue
    '#D500F9', // Neon Purple
    '#FFEA00', // Cyber Yellow
    '#00BCD4', // Cyan
    '#FF1744', // Crimson Red
];

// --- Custom Edge Component ---
const CustomDeleteEdge = ({
  id,
  sourceX,
  sourceY,
  targetX,
  targetY,
  sourcePosition,
  targetPosition,
  style = {},
  markerEnd,
  data,
}: EdgeProps) => {
  const [isHovered, setIsHovered] = useState(false);

  // Clean Aesthetic: Default edge is strictly Neutral
  // We respect the style passed from the parent (which determines solid vs dashed)
  const baseColor = style.stroke?.toString() || '#27272A';

  const [edgePath, labelX, labelY] = getSmoothStepPath({
    sourceX,
    sourceY,
    sourcePosition,
    targetX,
    targetY,
    targetPosition,
  });

  const onEdgeClick = (evt: React.MouseEvent, id: string) => {
    evt.stopPropagation();
    if (data && typeof data.onDelete === 'function') {
        (data.onDelete as () => void)();
    }
  };

  const markerEndSafe = typeof markerEnd === 'object' ? markerEnd : {};

  // Delete State (Red)
  const activeStyle = {
      ...style,
      stroke: '#ef4444', 
      strokeWidth: 2,
      strokeDasharray: 'none', // Force solid on hover for clarity
      filter: 'drop-shadow(0 0 3px rgba(239, 68, 68, 0.6))',
      transition: 'all 0.3s ease',
      zIndex: 100
  };

  // Normal State
  const defaultStyle = {
      ...style,
      opacity: 0.8,
      transition: 'all 0.3s ease',
  };

  return (
    <>
      <BaseEdge path={edgePath} markerEnd={{...markerEndSafe, color: isHovered ? '#ef4444' : baseColor} as any} style={isHovered ? activeStyle : defaultStyle} />
      <EdgeLabelRenderer>
        <div
          style={{
            position: 'absolute',
            transform: `translate(-50%, -50%) translate(${labelX}px,${labelY}px)`,
            fontSize: 12,
            pointerEvents: 'all',
          }}
          className="nodrag nopan group flex flex-col items-center justify-center"
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
        >
          {/* Interaction Zone - Only visible on hover */}
          <button
            className={`w-5 h-5 rounded-full flex items-center justify-center transition-all duration-200 border shadow-lg ${
                isHovered 
                ? 'bg-red-600 text-white border-red-500 scale-110 opacity-100' 
                : 'bg-black border-zenith-border opacity-0 group-hover:opacity-100 scale-90'
            }`}
            style={{ color: isHovered ? 'white' : baseColor }}
            onClick={(event) => onEdgeClick(event, id)}
            title="Sever Connection"
          >
            <span className="leading-none mb-[1px] font-bold">×</span>
          </button>
        </div>
      </EdgeLabelRenderer>
    </>
  );
};

const GraphView: React.FC<GraphViewProps> = ({ repos, activeRepoId, scope, onAddFile, onLinkNodes, onDisconnectNodes }) => {
  const navigate = useNavigate();
  const [nodes, setNodes, onNodesChange] = useNodesState([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);
  const { fitView } = useReactFlow();

  // Legend State
  const [showLegend, setShowLegend] = useState(false);

  const edgeTypes = useMemo(() => ({
    'custom-delete': CustomDeleteEdge,
  }), []);

  // --- 1. Layout Engine ---
  const getLayoutedElements = useCallback((nodes: Node[], edges: Edge[]) => {
    const dagreGraph = new dagre.graphlib.Graph();
    dagreGraph.setDefaultEdgeLabel(() => ({}));

    dagreGraph.setGraph({ 
        rankdir: 'LR', 
        align: 'DL',
        nodesep: 60,
        ranksep: 100 
    });

    nodes.forEach((node) => {
      const w = node.style?.width ? parseInt(node.style.width.toString()) : 180;
      const h = 60; 
      dagreGraph.setNode(node.id, { width: w, height: h });
    });

    edges.forEach((edge) => {
      dagreGraph.setEdge(edge.source, edge.target);
    });

    dagre.layout(dagreGraph);

    const layoutedNodes = nodes.map((node) => {
      const nodeWithPosition = dagreGraph.node(node.id);
      const x = nodeWithPosition ? nodeWithPosition.x : 0;
      const y = nodeWithPosition ? nodeWithPosition.y : 0;
      const w = node.style?.width ? parseInt(node.style.width.toString()) : 180;

      return {
        ...node,
        position: {
          x: x - w / 2,
          y: y - 30,
        },
      };
    });

    return { nodes: layoutedNodes, edges };
  }, []);

  // --- 2. GRAPH ALGORITHM ---
  useEffect(() => {
    if (!repos || repos.length === 0) return;

    // A. DETERMINE SCOPE
    // If scope is local, filter files to active repo. If global, use all.
    const activeRepo = repos.find(r => r.id === activeRepoId);
    if (scope === 'local' && !activeRepo) return;

    // Flatten files for Global View, or use single repo files for Local View
    const targetFiles = scope === 'global' 
        ? repos.flatMap(r => r.files.map(f => ({ ...f, _repoId: r.id, _repoName: r.name })))
        : activeRepo!.files.map(f => ({ ...f, _repoId: activeRepo!.id, _repoName: activeRepo!.name }));

    // B. BUILD MAPS
    const fileMap = new Map<string, string>(); // Name -> ID
    const idToNodeData = new Map<string, { name: string, repoId: string, repoName: string }>(); 

    targetFiles.forEach(f => {
        fileMap.set(f.name, f.id);
        fileMap.set(f.name.replace('.md', ''), f.id);
        idToNodeData.set(f.id, { name: f.name.replace('.md', ''), repoId: f._repoId, repoName: f._repoName });
    });

    const adjacency = new Map<string, string[]>(); 
    const degree = new Map<string, number>();
    const connectionRegistry = new Set<string>(); // For bi-directional check
    const rawConnections: { source: string, target: string }[] = [];

    targetFiles.forEach(f => {
        adjacency.set(f.id, []);
        degree.set(f.id, 0);
    });

    // C. PARSE LINKS (Cross-Repo aware in Global Mode because fileMap contains all files)
    targetFiles.forEach(sourceFile => {
        const linkRegex = /\[\[(.*?)\]\]/g;
        let match;
        const fileLinks = new Set<string>();

        while ((match = linkRegex.exec(sourceFile.content)) !== null) {
            const targetName = match[1];
            let targetId = fileMap.get(targetName);
            if (!targetId) targetId = fileMap.get(targetName + '.md');

            if (targetId && targetId !== sourceFile.id) {
                // Ensure target exists in our current scope
                if (idToNodeData.has(targetId)) {
                    if (!fileLinks.has(targetId)) {
                        fileLinks.add(targetId);
                        connectionRegistry.add(`${sourceFile.id}|${targetId}`);
                        rawConnections.push({ source: sourceFile.id, target: targetId });

                        adjacency.get(sourceFile.id)?.push(targetId);
                        adjacency.get(targetId)?.push(sourceFile.id);
                        degree.set(sourceFile.id, (degree.get(sourceFile.id) || 0) + 1);
                        degree.set(targetId, (degree.get(targetId) || 0) + 1);
                    }
                }
            }
        }
    });

    // D. ASSIGN COLORS
    const nodeColorMap = new Map<string, string>();
    const NEUTRAL_COLOR = '#52525B';

    if (scope === 'global') {
        // --- GALAXY MODE: Color by REPOSITORY ---
        // Each repo gets a consistent color from the palette
        repos.forEach((repo, idx) => {
            const repoColor = SOVEREIGN_PALETTES[idx % SOVEREIGN_PALETTES.length];
            repo.files.forEach(f => {
                nodeColorMap.set(f.id, repoColor);
            });
        });
    } else {
        // --- LOCAL MODE: Color by SOVEREIGNTY (Centrality) ---
        // This preserves the original logic for detailed local analysis
        const sortedNodes = [...targetFiles].sort((a, b) => {
            const degA = degree.get(a.id) || 0;
            const degB = degree.get(b.id) || 0;
            if (a.name.toLowerCase() === 'readme.md') return -1;
            if (b.name.toLowerCase() === 'readme.md') return 1;
            return degB - degA; 
        });

        const sovereigns = new Set<string>();
        let colorIdx = 0;

        // 1. README
        const readme = targetFiles.find(f => f.name.toLowerCase() === 'readme.md');
        if (readme) {
            sovereigns.add(readme.id);
            nodeColorMap.set(readme.id, SOVEREIGN_PALETTES[colorIdx % SOVEREIGN_PALETTES.length]);
            colorIdx++;
        }

        // 2. Hubs
        sortedNodes.forEach(node => {
            if (sovereigns.has(node.id)) return;
            const myDegree = degree.get(node.id) || 0;
            if (myDegree < 2) return;

            const neighbors = adjacency.get(node.id) || [];
            const connectedToSovereign = neighbors.some(n => sovereigns.has(n));

            if (!connectedToSovereign) {
                sovereigns.add(node.id);
                nodeColorMap.set(node.id, SOVEREIGN_PALETTES[colorIdx % SOVEREIGN_PALETTES.length]);
                colorIdx++;
            }
        });

        targetFiles.forEach(node => {
            if (sovereigns.has(node.id)) return;
            const neighbors = adjacency.get(node.id) || [];
            const rulingSovereigns = new Set<string>();
            neighbors.forEach(n => {
                if (sovereigns.has(n)) rulingSovereigns.add(n);
            });

            if (rulingSovereigns.size === 1) {
                const kingId = Array.from(rulingSovereigns)[0];
                nodeColorMap.set(node.id, nodeColorMap.get(kingId)!);
            } else {
                nodeColorMap.set(node.id, NEUTRAL_COLOR);
            }
        });
    }

    // E. CONSTRUCT NODES
    const rawNodes: Node[] = targetFiles.map(file => {
        const myColor = nodeColorMap.get(file.id) || NEUTRAL_COLOR;
        const deg = degree.get(file.id) || 0;
        const isNeutral = myColor === NEUTRAL_COLOR;

        // Size calculation
        // In global mode, we reduce size slightly to accommodate density
        let baseWidth = scope === 'global' ? 140 : 160;
        let width = baseWidth;
        let fontSize = 12;
        let zIndex = 1;

        // Logic for highlighting "Important" nodes
        // In Local: Sovereigns are important
        // In Global: High degree nodes are important
        const isImportant = scope === 'local' 
            ? !isNeutral // In local, anything colored is a Sovereign or Subject
            : deg > 3;   // In global, only hubs are highlighted

        if (isImportant) {
            width = baseWidth + (Math.min(deg, 15) * 4);
            zIndex = 10;
        }

        let style: React.CSSProperties = {
            background: '#030303',
            color: isImportant ? '#fff' : '#A1A1AA',
            border: `1px solid ${myColor}`,
            boxShadow: `0 4px 10px -2px rgba(0, 0, 0, 0.8)`,
            borderRadius: '2px',
            padding: '12px',
            fontFamily: 'monospace',
            textAlign: 'center',
            width: width,
            fontSize: `${fontSize}px`,
            transition: 'all 0.3s ease',
            zIndex
        };

        if (isImportant) {
            style = {
                ...style,
                borderWidth: '2px',
                fontWeight: 'bold',
                boxShadow: `0 0 15px ${myColor}30`,
            };
        } else if (isNeutral && scope === 'local') {
            style = {
                ...style,
                borderStyle: 'dashed',
                opacity: 0.8
            }
        }

        // Label Logic
        let label = file.name.replace('.md', '');
        // In Global view, if we have files from multiple repos, showing Repo name helps context, 
        // but might be too cluttered. Let's just use tooltip or color.
        // Let's rely on Color = Repo.

        return {
            id: file.id,
            data: { label },
            position: { x: 0, y: 0 },
            connectable: true,
            style
        };
    });

    // F. CONSTRUCT EDGES
    const finalEdges = rawConnections.map(conn => {
        const isBiDirectional = connectionRegistry.has(`${conn.target}|${conn.source}`);
        const targetData = idToNodeData.get(conn.target);

        return {
            id: `${conn.source}-${conn.target}`,
            source: conn.source,
            target: conn.target,
            type: 'custom-delete', 
            animated: false,
            style: { 
                strokeWidth: 1,
                strokeDasharray: isBiDirectional ? 'none' : '4 4',
                stroke: isBiDirectional ? '#52525B' : '#27272A', 
            }, 
            markerEnd: { 
                type: MarkerType.ArrowClosed,
                color: isBiDirectional ? '#52525B' : '#27272A',
            },
            data: {
                sourceName: idToNodeData.get(conn.source)?.name,
                targetName: targetData?.name,
                onDelete: () => {
                    if (onDisconnectNodes) onDisconnectNodes(conn.source, conn.target);
                }
            },
        };
    });

    const { nodes: layoutedNodes, edges: layoutedEdges } = getLayoutedElements(rawNodes, finalEdges);
    setNodes(layoutedNodes);
    setEdges(layoutedEdges);

    setTimeout(() => {
        window.requestAnimationFrame(() => fitView({ padding: 0.2 }));
    }, 100);

  }, [repos, activeRepoId, scope, getLayoutedElements, setNodes, setEdges, fitView, onDisconnectNodes]);

  const onNodeClick = (_: React.MouseEvent, node: Node) => {
      // In Global View, we need to know which repo the node belongs to.
      // We can find it by searching the input repos.
      let foundRepoId = activeRepoId;
      if (scope === 'global') {
          for (const r of repos) {
              if (r.files.some(f => f.id === node.id)) {
                  foundRepoId = r.id;
                  break;
              }
          }
      }
      navigate(`/${foundRepoId}/${node.id}`);
  };

  const onConnect = useCallback((params: Connection) => {
    if (params.source && params.target && onLinkNodes) {
        onLinkNodes(params.source, params.target);
    }
  }, [onLinkNodes]);

  const onEdgesDelete = useCallback((deletedEdges: Edge[]) => {
      if (onDisconnectNodes) {
          deletedEdges.forEach((edge) => {
              onDisconnectNodes(edge.source, edge.target);
          });
      }
  }, [onDisconnectNodes]);

  return (
    <div className="w-full h-[calc(100vh-180px)] border border-zenith-border bg-zenith-bg relative group">

        {/* Graph Toolbar */}
        <div className="absolute top-4 right-4 z-10 flex gap-2">
            <button 
                onClick={() => setShowLegend(!showLegend)}
                className="bg-zenith-surface border border-zenith-border text-zenith-muted hover:text-white p-2 rounded-sm shadow-lg transition-colors"
                title="Graph Legend"
            >
                <Icons.Help size={16} />
            </button>
            <div className="w-px h-8 bg-zenith-border/50 mx-1"></div>
            <button 
                onClick={onAddFile}
                className="bg-zenith-orange text-black px-4 py-2 font-mono text-xs font-bold uppercase tracking-widest hover:bg-white transition-colors shadow-lg flex items-center gap-2"
            >
                <Icons.Plus size={14} /> Add Node
            </button>
        </div>

        {/* Legend Modal/Overlay */}
        {showLegend && (
            <div className="absolute top-16 right-4 z-50 w-72 bg-black/90 backdrop-blur border border-zenith-border shadow-2xl p-4 animate-in fade-in slide-in-from-top-2">
                <h4 className="font-mono text-[10px] text-zenith-muted uppercase tracking-widest mb-4 border-b border-zenith-border pb-2">
                    Visual Taxonomy
                </h4>

                {scope === 'global' ? (
                     <div className="space-y-4 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
                        <div className="text-[10px] text-zenith-muted italic mb-2">Galaxy Mode: Colors indicate Repository</div>
                        {repos.map((r, idx) => (
                             <div key={r.id} className="flex gap-3 items-center">
                                <div className="w-3 h-3 rounded-sm shrink-0" style={{ backgroundColor: SOVEREIGN_PALETTES[idx % SOVEREIGN_PALETTES.length] }}></div>
                                <div className="text-white text-xs font-mono uppercase truncate">{r.name}</div>
                             </div>
                        ))}
                     </div>
                ) : (
                    <div className="space-y-4">
                        {/* Sovereign */}
                        <div className="flex gap-3 items-start">
                            <div className="w-4 h-4 rounded-sm border-2 border-zenith-orange shadow-[0_0_10px_rgba(255,77,0,0.3)] shrink-0 mt-0.5"></div>
                            <div>
                                <div className="text-white text-xs font-bold uppercase">Sovereign Node</div>
                                <p className="text-[10px] text-zenith-muted leading-tight mt-1">A central topic or "Hub". Inherits a unique color based on its cluster.</p>
                            </div>
                        </div>
                        {/* Subject */}
                        <div className="flex gap-3 items-start">
                            <div className="w-4 h-4 rounded-sm border border-zenith-orange shrink-0 mt-0.5 opacity-70"></div>
                            <div>
                                <div className="text-zenith-text text-xs font-bold uppercase">Subject Node</div>
                                <p className="text-[10px] text-zenith-muted leading-tight mt-1">Exclusively linked to one Sovereign. Inherits the Sovereign's color.</p>
                            </div>
                        </div>
                        {/* Neutral */}
                        <div className="flex gap-3 items-start">
                            <div className="w-4 h-4 rounded-sm border border-dashed border-zenith-muted shrink-0 mt-0.5"></div>
                            <div>
                                <div className="text-zenith-muted text-xs font-bold uppercase">Neutral / Bridge</div>
                                <p className="text-[10px] text-zenith-muted leading-tight mt-1">Connects multiple Sovereigns. Remains grey to avoid color pollution.</p>
                            </div>
                        </div>
                    </div>
                )}

                <div className="h-px bg-zenith-border my-4"></div>

                {/* Edge Styles */}
                <div className="space-y-4">
                    <div className="flex gap-3 items-center">
                        <div className="w-8 h-0.5 bg-zenith-muted shrink-0"></div>
                        <div>
                            <div className="text-white text-xs font-bold uppercase">Solid Line</div>
                            <p className="text-[10px] text-zenith-muted leading-tight">Bi-directional link (Strong bond).</p>
                        </div>
                    </div>
                    <div className="flex gap-3 items-center">
                        <div className="w-8 h-0.5 border-t border-dashed border-zenith-muted shrink-0"></div>
                        <div>
                            <div className="text-zenith-muted text-xs font-bold uppercase">Dashed Line</div>
                            <p className="text-[10px] text-zenith-muted leading-tight">One-way reference (Weak link).</p>
                        </div>
                    </div>
                </div>
            </div>
        )}

        {/* Empty State */}
        {nodes.length === 0 && (
             <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
                 <div className="text-center">
                     <div className="text-zenith-muted font-mono text-xs uppercase tracking-widest mb-2">No Data Points Detected</div>
                     <div className="text-zenith-orange/50 font-mono text-[10px]">Add a file to initialize graph</div>
                 </div>
             </div>
        )}

        <ReactFlow
            nodes={nodes}
            edges={edges}
            onNodesChange={onNodesChange}
            onEdgesChange={onEdgesChange}
            onNodeClick={onNodeClick}
            onConnect={onConnect}
            onEdgesDelete={onEdgesDelete} 
            deleteKeyCode={['Backspace', 'Delete']} 
            edgeTypes={edgeTypes}
            connectionLineType={ConnectionLineType.SmoothStep}
            fitView
            style={flowStyles}
            minZoom={0.2}
            maxZoom={4}
            defaultEdgeOptions={{ 
                type: 'custom-delete',
                markerEnd: { type: MarkerType.ArrowClosed } 
            }}
        >
            <Background color="#27272A" gap={20} size={1} />
            <Controls 
                className="bg-zenith-surface border border-zenith-border fill-white text-white" 
                style={{ borderRadius: 0, padding: 2 }} 
            />
            <MiniMap 
                nodeStrokeColor="#27272A"
                nodeColor="#18181B"
                maskColor="rgba(0,0,0, 0.7)"
                style={{ backgroundColor: '#030303', border: '1px solid #27272A' }}
            />
        </ReactFlow>

        {/* HUD Overlay */}
        <div className="absolute bottom-4 left-4 pointer-events-none">
            <div className="font-mono text-[10px] text-zenith-orange uppercase tracking-widest flex items-center gap-2">
                <Icons.Zap size={10} className="animate-pulse"/>
                PROTOCOL: {scope === 'global' ? 'GALAXY (CROSS-REPO)' : 'SECTOR (LOCAL)'} // {nodes.length} Nodes
            </div>
            <div className="font-mono text-[10px] text-zenith-muted mt-1">
                {scope === 'global' ? 'Nodes colored by Repository Origin.' : 'Nodes colored by Structural Sovereignty.'}
            </div>
        </div>
    </div>
  );
};

const GraphViewWrapper: React.FC<GraphViewProps> = (props) => (
    <div className="w-full h-full">
         <ReactFlowProviderWrapper {...props} />
    </div>
);

const ReactFlowProviderWrapper: React.FC<GraphViewProps> = (props) => {
    return (
        <ReactFlowProvider>
            <GraphView {...props} />
        </ReactFlowProvider>
    );
}

export default GraphViewWrapper;

import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { 
  ReactFlow, 
  useNodesState, 
  useEdgesState, 
  Background, 
  Controls,
  MiniMap,
  Node,
  Edge,
  MarkerType,
  ConnectionLineType,
  useReactFlow,
  Connection,
  ReactFlowProvider,
  BaseEdge,
  EdgeLabelRenderer,
  EdgeProps,
  getSmoothStepPath
} from '@xyflow/react';
import dagre from 'dagre';
import { Repository } from '../types';
import { useNavigate } from 'react-router-dom';
import { Icons } from './Icon';

interface GraphViewProps {
  repos: Repository[]; 
  activeRepoId: string; 
  scope: 'local' | 'global';
  onAddFile: () => void;
  onLinkNodes?: (sourceId: string, targetId: string) => void;
  onDisconnectNodes?: (sourceId: string, targetId: string) => void;
}

const flowStyles = {
    background: '#030303',
};

// --- COLOR PALETTES ---
const SOVEREIGN_PALETTES = [
    '#FF4D00', // Zenith Orange
    '#00E676', // Matrix Green
    '#2979FF', // Electric Blue
    '#D500F9', // Neon Purple
    '#FFEA00', // Cyber Yellow
    '#00BCD4', // Cyan
    '#FF1744', // Crimson Red
];

// --- Custom Edge Component ---
const CustomDeleteEdge = ({
  id,
  sourceX,
  sourceY,
  targetX,
  targetY,
  sourcePosition,
  targetPosition,
  style = {},
  markerEnd,
  data,
}: EdgeProps) => {
  const [isHovered, setIsHovered] = useState(false);

  const baseColor = style.stroke?.toString() || '#27272A';

  const [edgePath, labelX, labelY] = getSmoothStepPath({
    sourceX,
    sourceY,
    sourcePosition,
    targetX,
    targetY,
    targetPosition,
  });

  const onEdgeClick = (evt: React.MouseEvent, id: string) => {
    evt.stopPropagation();
    if (data && typeof data.onDelete === 'function') {
        (data.onDelete as () => void)();
    }
  };

  const markerEndSafe = typeof markerEnd === 'object' ? markerEnd : {};

  // Delete State (Red)
  const activeStyle = {
      ...style,
      stroke: '#ef4444', 
      strokeWidth: 2,
      strokeDasharray: 'none', 
      filter: 'drop-shadow(0 0 3px rgba(239, 68, 68, 0.6))',
      transition: 'all 0.3s ease',
      zIndex: 100
  };

  // Normal State
  const defaultStyle = {
      ...style,
      opacity: 0.8,
      transition: 'all 0.3s ease',
  };

  return (
    <>
      <BaseEdge path={edgePath} markerEnd={{...markerEndSafe, color: isHovered ? '#ef4444' : baseColor} as any} style={isHovered ? activeStyle : defaultStyle} />
      <EdgeLabelRenderer>
        <div
          style={{
            position: 'absolute',
            transform: `translate(-50%, -50%) translate(${labelX}px,${labelY}px)`,
            fontSize: 12,
            pointerEvents: 'all',
          }}
          className="nodrag nopan group flex flex-col items-center justify-center"
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
        >
          {/* Interaction Zone - Only visible on hover */}
          <button
            className={`w-5 h-5 rounded-full flex items-center justify-center transition-all duration-200 border shadow-lg ${
                isHovered 
                ? 'bg-red-600 text-white border-red-500 scale-110 opacity-100' 
                : 'bg-black border-zenith-border opacity-0 group-hover:opacity-100 scale-90'
            }`}
            style={{ color: isHovered ? 'white' : baseColor }}
            onClick={(event) => onEdgeClick(event, id)}
            title="Sever Connection"
          >
            <span className="leading-none mb-[1px] font-bold">×</span>
          </button>
        </div>
      </EdgeLabelRenderer>
    </>
  );
};

const GraphView: React.FC<GraphViewProps> = ({ repos, activeRepoId, scope, onAddFile, onLinkNodes, onDisconnectNodes }) => {
  const navigate = useNavigate();
  const [nodes, setNodes, onNodesChange] = useNodesState([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);
  const { fitView } = useReactFlow();

  // Legend State
  const [showLegend, setShowLegend] = useState(false);

  const edgeTypes = useMemo(() => ({
    'custom-delete': CustomDeleteEdge,
  }), []);

  // --- 1. Layout Engine ---
  const getLayoutedElements = useCallback((nodes: Node[], edges: Edge[]) => {
    const dagreGraph = new dagre.graphlib.Graph();
    dagreGraph.setDefaultEdgeLabel(() => ({}));

    dagreGraph.setGraph({ 
        rankdir: 'LR', 
        align: 'DL',
        nodesep: 60,
        ranksep: 100 
    });

    nodes.forEach((node) => {
      const w = node.style?.width ? parseInt(node.style.width.toString()) : 180;
      const h = 60; 
      dagreGraph.setNode(node.id, { width: w, height: h });
    });

    edges.forEach((edge) => {
      dagreGraph.setEdge(edge.source, edge.target);
    });

    dagre.layout(dagreGraph);

    const layoutedNodes = nodes.map((node) => {
      const nodeWithPosition = dagreGraph.node(node.id);
      const x = nodeWithPosition ? nodeWithPosition.x : 0;
      const y = nodeWithPosition ? nodeWithPosition.y : 0;
      const w = node.style?.width ? parseInt(node.style.width.toString()) : 180;

      return {
        ...node,
        position: {
          x: x - w / 2,
          y: y - 30,
        },
      };
    });

    return { nodes: layoutedNodes, edges };
  }, []);

  // --- 2. GRAPH ALGORITHM ---
  useEffect(() => {
    if (!repos || repos.length === 0) return;

    // A. PRE-PROCESSING: Build the "Universe"
    // We need to know about ALL files to resolve links, even if we don't display them all.
    const allFiles = repos.flatMap(r => r.files.map(f => ({ ...f, _repoId: r.id, _repoName: r.name })));

    // Quick Lookup Maps
    const globalNameMap = new Map<string, string>(); // Name -> ID
    const globalNodeDataMap = new Map<string, { name: string, repoId: string, repoName: string }>(); 

    allFiles.forEach(f => {
        globalNameMap.set(f.name, f.id);
        globalNameMap.set(f.name.replace('.md', ''), f.id);
        globalNodeDataMap.set(f.id, { name: f.name.replace('.md', ''), repoId: f._repoId, repoName: f._repoName });
    });

    // B. BUILD GLOBAL ADJACENCY LIST
    // We scan EVERYTHING first to establish the full network. 
    // This allows us to find incoming links from "invisible" repos.
    const globalAdjacency = new Map<string, Set<string>>(); // sourceId -> Set<targetId>
    const globalIncoming = new Map<string, Set<string>>();  // targetId -> Set<sourceId>

    allFiles.forEach(f => {
        if (!globalAdjacency.has(f.id)) globalAdjacency.set(f.id, new Set());
        if (!globalIncoming.has(f.id)) globalIncoming.set(f.id, new Set());
    });

    const connectionRegistry = new Set<string>(); // "source|target" for bi-directional check

    allFiles.forEach(sourceFile => {
        const linkRegex = /\[\[(.*?)\]\]/g;
        let match;
        while ((match = linkRegex.exec(sourceFile.content)) !== null) {
            const targetName = match[1];
            let targetId = globalNameMap.get(targetName);
            if (!targetId) targetId = globalNameMap.get(targetName + '.md');

            if (targetId && targetId !== sourceFile.id) {
                // Register valid connection
                globalAdjacency.get(sourceFile.id)?.add(targetId);
                globalIncoming.get(targetId)?.add(sourceFile.id);
                connectionRegistry.add(`${sourceFile.id}|${targetId}`);
            }
        }
    });

    // C. FILTERING (SMART CONTEXT)
    const filesToRenderSet = new Set<string>();

    if (scope === 'local') {
        // Simple: Only active repo files
        const activeRepoFiles = repos.find(r => r.id === activeRepoId)?.files || [];
        activeRepoFiles.forEach(f => filesToRenderSet.add(f.id));
    } else {
        // GALAXY (Smart Context):
        // 1. Add ALL files from Active Repo
        // 2. Add ANY file from OTHER Repos that is DIRECTLY connected (Incoming OR Outgoing) to Active Repo files

        const activeRepoFiles = repos.find(r => r.id === activeRepoId)?.files || [];
        const activeRepoFileIds = new Set(activeRepoFiles.map(f => f.id));

        // Add Active Repo Files
        activeRepoFileIds.forEach(id => filesToRenderSet.add(id));

        // Add Neighbors (Incoming/Outgoing)
        activeRepoFileIds.forEach(rootId => {
            // Outgoing neighbors
            const outgoing = globalAdjacency.get(rootId);
            if (outgoing) {
                outgoing.forEach(targetId => filesToRenderSet.add(targetId));
            }

            // Incoming neighbors (Critical for "Explosion" prevention: we scan the inverse map)
            const incoming = globalIncoming.get(rootId);
            if (incoming) {
                incoming.forEach(sourceId => filesToRenderSet.add(sourceId));
            }
        });
    }

    // D. FINALIZE NODE LIST
    // Convert Set back to Array of File objects
    const targetFiles = allFiles.filter(f => filesToRenderSet.has(f.id));

    // Calculate local degree for sizing (based on filtered view)
    const viewDegree = new Map<string, number>();
    targetFiles.forEach(f => viewDegree.set(f.id, 0));

    const finalConnections: { source: string, target: string }[] = [];

    // Re-scan connections ONLY among the filtered nodes
    targetFiles.forEach(sourceFile => {
        const outgoing = globalAdjacency.get(sourceFile.id);
        if (outgoing) {
            outgoing.forEach(targetId => {
                if (filesToRenderSet.has(targetId)) {
                    finalConnections.push({ source: sourceFile.id, target: targetId });

                    viewDegree.set(sourceFile.id, (viewDegree.get(sourceFile.id) || 0) + 1);
                    viewDegree.set(targetId, (viewDegree.get(targetId) || 0) + 1);
                }
            });
        }
    });


    // E. ASSIGN COLORS
    const nodeColorMap = new Map<string, string>();
    const NEUTRAL_COLOR = '#52525B';

    if (scope === 'global') {
        // --- GALAXY MODE: Color by REPOSITORY ---
        repos.forEach((repo, idx) => {
            const repoColor = SOVEREIGN_PALETTES[idx % SOVEREIGN_PALETTES.length];
            repo.files.forEach(f => {
                nodeColorMap.set(f.id, repoColor);
            });
        });
    } else {
        // --- LOCAL MODE: Color by SOVEREIGNTY ---
        // (Existing Local Logic)
        const sortedNodes = [...targetFiles].sort((a, b) => {
            const degA = viewDegree.get(a.id) || 0;
            const degB = viewDegree.get(b.id) || 0;
            if (a.name.toLowerCase() === 'readme.md') return -1;
            if (b.name.toLowerCase() === 'readme.md') return 1;
            return degB - degA; 
        });

        const sovereigns = new Set<string>();
        let colorIdx = 0;

        const readme = targetFiles.find(f => f.name.toLowerCase() === 'readme.md');
        if (readme) {
            sovereigns.add(readme.id);
            nodeColorMap.set(readme.id, SOVEREIGN_PALETTES[colorIdx % SOVEREIGN_PALETTES.length]);
            colorIdx++;
        }

        sortedNodes.forEach(node => {
            if (sovereigns.has(node.id)) return;
            const myDegree = viewDegree.get(node.id) || 0;
            if (myDegree < 2) return;

            // Simplified Cluster check for local
            sovereigns.add(node.id);
            nodeColorMap.set(node.id, SOVEREIGN_PALETTES[colorIdx % SOVEREIGN_PALETTES.length]);
            colorIdx++;
        });

        targetFiles.forEach(node => {
            if (!nodeColorMap.has(node.id)) nodeColorMap.set(node.id, NEUTRAL_COLOR);
        });
    }

    // F. CONSTRUCT NODES
    const rawNodes: Node[] = targetFiles.map(file => {
        const myColor = nodeColorMap.get(file.id) || NEUTRAL_COLOR;
        const deg = viewDegree.get(file.id) || 0;
        const isNeutral = myColor === NEUTRAL_COLOR;
        const isExternal = file._repoId !== activeRepoId;

        // Size calculation
        let baseWidth = scope === 'global' ? 140 : 160;
        let width = baseWidth;
        let fontSize = 12;
        let zIndex = 1;

        const isImportant = deg > 2 || (scope === 'global' && isExternal);

        if (isImportant) {
            width = baseWidth + (Math.min(deg, 15) * 4);
            zIndex = 10;
        }

        let style: React.CSSProperties = {
            background: '#030303',
            color: isImportant ? '#fff' : '#A1A1AA',
            border: `1px solid ${myColor}`,
            boxShadow: `0 4px 10px -2px rgba(0, 0, 0, 0.8)`,
            borderRadius: '2px',
            padding: '12px',
            fontFamily: 'monospace',
            textAlign: 'center',
            width: width,
            fontSize: `${fontSize}px`,
            transition: 'all 0.3s ease',
            zIndex
        };

        if (isImportant) {
            style = {
                ...style,
                borderWidth: '2px',
                fontWeight: 'bold',
                boxShadow: `0 0 15px ${myColor}30`,
            };
        } else if (isNeutral && scope === 'local') {
            style = {
                ...style,
                borderStyle: 'dashed',
                opacity: 0.8
            }
        }

        return {
            id: file.id,
            data: { label: file.name.replace('.md', '') },
            position: { x: 0, y: 0 },
            connectable: true,
            style
        };
    });

    // G. CONSTRUCT EDGES
    const finalEdges = finalConnections.map(conn => {
        const isBiDirectional = connectionRegistry.has(`${conn.target}|${conn.source}`);
        const targetData = globalNodeDataMap.get(conn.target);
        const sourceData = globalNodeDataMap.get(conn.source);

        return {
            id: `${conn.source}-${conn.target}`,
            source: conn.source,
            target: conn.target,
            type: 'custom-delete', 
            animated: false,
            style: { 
                strokeWidth: 1,
                strokeDasharray: isBiDirectional ? 'none' : '4 4',
                stroke: isBiDirectional ? '#52525B' : '#27272A', 
            }, 
            markerEnd: { 
                type: MarkerType.ArrowClosed,
                color: isBiDirectional ? '#52525B' : '#27272A',
            },
            data: {
                sourceName: sourceData?.name,
                targetName: targetData?.name,
                onDelete: () => {
                    if (onDisconnectNodes) onDisconnectNodes(conn.source, conn.target);
                }
            },
        };
    });

    const { nodes: layoutedNodes, edges: layoutedEdges } = getLayoutedElements(rawNodes, finalEdges);
    setNodes(layoutedNodes);
    setEdges(layoutedEdges);

    setTimeout(() => {
        window.requestAnimationFrame(() => fitView({ padding: 0.2 }));
    }, 100);

  }, [repos, activeRepoId, scope, getLayoutedElements, setNodes, setEdges, fitView, onDisconnectNodes]);

  const onNodeClick = (_: React.MouseEvent, node: Node) => {
      // Find which repo this node belongs to for navigation
      let foundRepoId = activeRepoId;
      if (scope === 'global') {
          for (const r of repos) {
              if (r.files.some(f => f.id === node.id)) {
                  foundRepoId = r.id;
                  break;
              }
          }
      }
      navigate(`/${foundRepoId}/${node.id}`);
  };

  const onConnect = useCallback((params: Connection) => {
    if (params.source && params.target && onLinkNodes) {
        onLinkNodes(params.source, params.target);
    }
  }, [onLinkNodes]);

  const onEdgesDelete = useCallback((deletedEdges: Edge[]) => {
      if (onDisconnectNodes) {
          deletedEdges.forEach((edge) => {
              onDisconnectNodes(edge.source, edge.target);
          });
      }
  }, [onDisconnectNodes]);

  return (
    <div className="w-full h-[calc(100vh-180px)] border border-zenith-border bg-zenith-bg relative group">

        {/* Graph Toolbar */}
        <div className="absolute top-4 right-4 z-10 flex gap-2">
            <button 
                onClick={() => setShowLegend(!showLegend)}
                className="bg-zenith-surface border border-zenith-border text-zenith-muted hover:text-white p-2 rounded-sm shadow-lg transition-colors"
                title="Graph Legend"
            >
                <Icons.Help size={16} />
            </button>
            <div className="w-px h-8 bg-zenith-border/50 mx-1"></div>
            <button 
                onClick={onAddFile}
                className="bg-zenith-orange text-black px-4 py-2 font-mono text-xs font-bold uppercase tracking-widest hover:bg-white transition-colors shadow-lg flex items-center gap-2"
            >
                <Icons.Plus size={14} /> Add Node
            </button>
        </div>

        {/* Legend Modal/Overlay */}
        {showLegend && (
            <div className="absolute top-16 right-4 z-50 w-72 bg-black/90 backdrop-blur border border-zenith-border shadow-2xl p-4 animate-in fade-in slide-in-from-top-2">
