import MarkdownPreview, { generateSlug } from '../components/MarkdownPreview';
import DeleteConfirmModal from '../components/DeleteConfirmModal';
import EditorToolbar from '../components/EditorToolbar';
import LinkSelectorModal from '../components/LinkSelectorModal';
import { convertHtmlToMarkdown } from '../utils/markdownPaste';
import BacklinksPanel from '../components/Editor/BacklinksPanel';
import TableOfContents, { TocItem } from '../components/Editor/TableOfContents';

interface FileEditorProps {
  repos: Repository[];
  onUpdateFile: (repoId: string, fileId: string, newContent: string) => void;
  onRenameFile: (repoId: string, fileId: string, newName: string) => void;
  onDeleteFile: (repoId: string, fileId: string) => void;
  isAuthenticated: boolean;
}

type ViewMode = 'write' | 'preview' | 'split';

const FileEditor: React.FC<FileEditorProps> = ({ repos, onUpdateFile, onRenameFile, onDeleteFile, isAuthenticated }) => {
  const { repoId, fileId } = useParams<{ repoId: string; fileId: string }>();
  const navigate = useNavigate();
  const textAreaRef = useRef<HTMLTextAreaElement>(null);

  const repo = repos.find(r => r.id === repoId);
  const file = repo?.files.find(f => f.id === fileId);

  const [viewMode, setViewMode] = useState<ViewMode>('preview');
  const [content, setContent] = useState('');
  const [hasChanges, setHasChanges] = useState(false);
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [conversionStatus, setConversionStatus] = useState<string | null>(null);
  const [isLinkSelectorOpen, setIsLinkSelectorOpen] = useState(false);

  // Renaming State
  const [isRenaming, setIsRenaming] = useState(false);
  const [renameValue, setRenameValue] = useState('');

  useEffect(() => {
    if (file) {
      setContent(file.content);
      setRenameValue(file.name);
    }
  }, [file]);

  // --- Backlinks Logic ---
  const backlinks = useMemo(() => {
    if (!repoId || !fileId) return [];
    const targetLink = `/${repoId}/${fileId}`;
    const links: any[] = [];

    repos.forEach(r => {
        r.files.forEach(f => {
            if (f.id === fileId) return;
            if (f.content.includes(targetLink)) {
                const lines = f.content.split('\n');
                const matchLine = lines.find(l => l.includes(targetLink)) || "Link found in document";
                const cleanContext = matchLine.replace(/\[(.*?)\]\(.*?\)/g, '$1').trim();

                links.push({
                    fileId: f.id,
                    fileName: f.name,
                    repoId: r.id,
                    repoName: r.name,
                    context: cleanContext.length > 60 ? cleanContext.substring(0, 60) + "..." : cleanContext
                });
            }
        })
    });
    return links;
  }, [repos, repoId, fileId]);

  // --- Table of Contents Logic ---
  const toc: TocItem[] = useMemo(() => {
    if (!content) return [];
    const items: TocItem[] = [];
    const lines = content.split('\n');
    let inCodeBlock = false;

    lines.forEach(line => {
        if (line.trim().startsWith('```')) {
            inCodeBlock = !inCodeBlock;
            return;
        }
        if (inCodeBlock) return;

        const headingMatch = line.match(/^(#{1,3})\s+(.+)$/);
        if (headingMatch) {
            const level = headingMatch[1].length;
            const text = headingMatch[2].trim();
            const cleanText = text.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1').replace(/(\*\*|__)(.*?)\1/g, '$2');

            items.push({
                id: generateSlug(cleanText),
                text: cleanText,
                level
            });
        }
    });
    return items;
  }, [content]);

  if (!repo || !file) {
    return <div className="h-screen flex items-center justify-center font-mono text-zenith-orange">ERROR: FILE DATA CORRUPTED OR MISSING</div>;
  }

  const handleSave = () => {
    if (!isAuthenticated) return;
    onUpdateFile(repoId!, fileId!, content);
    setHasChanges(false);
  };

  const handleRenameSubmit = () => {
    if (!isAuthenticated) return;
    if (renameValue.trim() && renameValue.trim() !== file.name) {
        let name = renameValue.trim();
        if (!name.endsWith('.md')) name += '.md';
        onRenameFile(repoId!, fileId!, name);
        setConversionStatus("REFACTORING LINKS...");
        setTimeout(() => setConversionStatus(null), 2000);
    }
    setIsRenaming(false);
  };

  const handleContentChange = (val: string) => {
      setContent(val);
      setHasChanges(val !== file.content);
      if (val.endsWith('[[')) setIsLinkSelectorOpen(true);
  }

  const handleDeleteConfirm = () => {
      if (!isAuthenticated) return;
      onDeleteFile(repoId!, fileId!);
      navigate(`/${repoId}`);
  }

  const handleInsert = (prefix: string, suffix: string = '') => {
    if (!textAreaRef.current) return;
    const start = textAreaRef.current.selectionStart;
    const end = textAreaRef.current.selectionEnd;
    const text = textAreaRef.current.value;
    const newText = text.substring(0, start) + prefix + text.substring(start, end) + suffix + text.substring(end);

    setContent(newText);
    setHasChanges(true);

    setTimeout(() => {
      if(textAreaRef.current) {
        textAreaRef.current.focus();
        textAreaRef.current.selectionStart = start + prefix.length;
        textAreaRef.current.selectionEnd = end + prefix.length;
      }
    }, 0);
  };

  const insertTextAtCursor = (textToInsert: string) => {
      if (!textAreaRef.current) return;
      const start = textAreaRef.current.selectionStart;
      const end = textAreaRef.current.selectionEnd;
      const currentText = textAreaRef.current.value;
      const newText = currentText.substring(0, start) + textToInsert + currentText.substring(end);

      setContent(newText);
      setHasChanges(true);

      setTimeout(() => {
          if (textAreaRef.current) {
              textAreaRef.current.focus();
              const newCursorPos = start + textToInsert.length;
              textAreaRef.current.selectionStart = newCursorPos;
              textAreaRef.current.selectionEnd = newCursorPos;
          }
      }, 0);
  };

  const handleLinkSelect = (targetRepoId: string, targetFileId: string, targetName: string) => {
      if (textAreaRef.current) {
         const val = textAreaRef.current.value;
         const end = textAreaRef.current.selectionEnd;
         if (val.substring(end - 2, end) === '[[') {
             const before = val.substring(0, end - 2);
             const after = val.substring(end);
             const linkMd = `[[${targetName.replace('.md', '')}]]`;
             const newText = before + linkMd + after;
             setContent(newText);
             setHasChanges(true);
             setTimeout(() => {
                 if(textAreaRef.current) {
                     textAreaRef.current.focus();
                     textAreaRef.current.selectionStart = before.length + linkMd.length;
                     textAreaRef.current.selectionEnd = before.length + linkMd.length;
                 }
             }, 0);
             return;
         }
      }
      const linkMd = `[[${targetName.replace('.md', '')}]]`;
      insertTextAtCursor(linkMd);
  };

  const handlePaste = (e: React.ClipboardEvent<HTMLTextAreaElement>) => {
    if (!isAuthenticated) return;
    const clipboardData = e.clipboardData;
    if (clipboardData.types.includes('text/html')) {
        e.preventDefault();
        try {
            const html = clipboardData.getData('text/html');
            const markdown = convertHtmlToMarkdown(html);
            insertTextAtCursor(markdown);
            setConversionStatus("SMART PASTE: CLEANED");
            setTimeout(() => setConversionStatus(null), 3000);
        } catch (err) {
            const plainText = clipboardData.getData('text/plain');
            insertTextAtCursor(plainText);
            setConversionStatus("PASTE FALLBACK: PLAIN TEXT");
            setTimeout(() => setConversionStatus(null), 3000);
        }
    }
  };

  const lineCount = content.split('\n').length;

  return (
    <div className="h-[calc(100vh-56px)] flex flex-col bg-zenith-bg relative">

      {/* Toast Notification */}
      {conversionStatus && (
          <div className="fixed bottom-12 right-6 z-50 animate-in slide-in-from-bottom-5 duration-300">
              <div className="bg-zenith-surface border border-zenith-orange px-4 py-3 shadow-[0_0_15px_rgba(255,77,0,0.2)] flex items-center gap-3">
                  <div className="bg-zenith-orange text-black p-1">
                      <Icons.Zap size={14} />
                  </div>
                  <span className="font-mono text-white font-bold text-xs tracking-widest uppercase">{conversionStatus}</span>
              </div>
          </div>
      )}

      {/* File Toolbar */}
      <div className="h-14 border-b border-zenith-border bg-zenith-bg flex items-center justify-between px-4 sm:px-6 shrink-0 relative z-10 gap-2">
          <div className="flex items-center gap-3 sm:gap-4 min-w-0 flex-1">
              <Link to={`/${repoId}`} className="text-zenith-muted hover:text-white transition-colors shrink-0">
                  <Icons.ChevronRight className="rotate-180" size={18} />
              </Link>
              <div className="h-6 w-px bg-zenith-border shrink-0"></div>

              {isRenaming && isAuthenticated ? (
                  <input 
                    autoFocus
                    type="text"
                    value={renameValue}
                    onChange={(e) => setRenameValue(e.target.value)}
                    onBlur={handleRenameSubmit}
                    onKeyDown={(e) => e.key === 'Enter' && handleRenameSubmit()}
                    className="bg-black border border-zenith-orange text-white font-mono text-sm font-bold tracking-wide px-2 py-1 outline-none min-w-[200px]"
                  />
              ) : (
                  <div className="flex items-center gap-2 group cursor-pointer" onClick={() => isAuthenticated && setIsRenaming(true)}>
                    <span className="font-mono text-sm text-white font-bold tracking-wide truncate group-hover:text-zenith-orange transition-colors" title={file.name}>
                        {file.name}
                    </span>
                    {isAuthenticated && <Icons.Edit size={12} className="text-zenith-border group-hover:text-zenith-orange opacity-0 group-hover:opacity-100 transition-all"/>}
                  </div>
              )}

              {hasChanges && <span className="text-[10px] bg-zenith-orange text-black px-2 py-0.5 font-bold font-mono shrink-0">UNSAVED</span>}
              {!isAuthenticated && <span className="text-[10px] border border-zenith-border text-zenith-muted px-2 py-0.5 font-mono uppercase shrink-0 hidden sm:block">Read Only</span>}
          </div>

          <div className="flex items-center gap-2 sm:gap-3 shrink-0">
             <div className="flex border border-zenith-border p-0.5 bg-zenith-surface">
                 <button 
                    onClick={() => setViewMode('write')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'write' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Write Mode"
                 >
                    <Icons.Edit size={12} /> <span className="hidden sm:inline">Write</span>
                 </button>
                 <button 
                    onClick={() => setViewMode('split')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 border-l border-r border-zenith-border ${viewMode === 'split' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Split View"
                 >
                    <Icons.Layout size={12} /> <span className="hidden sm:inline">Split</span>
                 </button>
                 <button 
                    onClick={() => setViewMode('preview')}
                    className={`px-3 py-1.5 text-[10px] font-mono tracking-widest uppercase transition-all flex items-center gap-2 ${viewMode === 'preview' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Preview Mode"
                 >
                    <Icons.File size={12} /> <span className="hidden sm:inline">Render</span>
                 </button>
             </div>

             {isAuthenticated && (
                <>
                 <button 
                    onClick={handleSave}
                    disabled={!hasChanges}
                    className={`flex items-center gap-2 px-4 py-2 border text-xs font-mono tracking-widest uppercase transition-colors ${hasChanges ? 'border-zenith-orange text-zenith-orange hover:bg-zenith-orange hover:text-black' : 'border-zenith-border text-zenith-muted cursor-not-allowed'}`}
                 >
                    <Icons.Save size={14} /> <span className="hidden sm:inline">Save</span>
                 </button>
                 <button onClick={() => setIsDeleteModalOpen(true)} className="p-2 text-zenith-muted hover:text-red-600 transition-colors"><Icons.Trash size={16} /></button>
                </>
             )}
          </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-hidden relative flex z-0">
         {(viewMode === 'write' || viewMode === 'split') && (
           <div className={`flex flex-col border-r border-zenith-border ${viewMode === 'split' ? 'w-1/2' : 'w-full'}`}>
             {isAuthenticated && <EditorToolbar onInsert={handleInsert} onLinkNote={() => setIsLinkSelectorOpen(true)} />}
             <div className="flex flex-1 overflow-hidden">
                <div className="hidden sm:block w-10 bg-zenith-surface border-r border-zenith-border text-right py-4 pr-2 font-mono text-xs text-zenith-border select-none overflow-hidden shrink-0">
                    {Array.from({length: Math.max(lineCount, 20)}).map((_, i) => <div key={i}>{i+1}</div>)}
                </div>
                <textarea
                    ref={textAreaRef}
                    readOnly={!isAuthenticated}
                    value={content}
                    onChange={(e) => handleContentChange(e.target.value)}
                    onPaste={handlePaste}
                    className={`w-full h-full bg-zenith-bg text-zenith-text font-mono text-sm p-4 resize-none outline-none transition-colors leading-relaxed ${!isAuthenticated ? 'cursor-not-allowed text-zenith-muted' : 'focus:bg-[#050505]'}`}
                    spellCheck={false}
                    placeholder={!isAuthenticated ? "Editing is disabled in visitor mode." : "Start typing... Tip: Type '[[' to link another note."}
                />
             </div>
           </div>
         )}

         {(viewMode === 'preview' || viewMode === 'split') && (
           <div className={`flex flex-1 overflow-hidden bg-zenith-bg ${viewMode === 'split' ? 'bg-[#080808]' : ''}`}>
               <div className="flex-1 overflow-y-auto overflow-x-hidden">
                   <div className={`p-8 mx-auto ${viewMode === 'split' ? 'max-w-none' : 'max-w-4xl'}`}>
                       <MarkdownPreview content={content} />
                       <BacklinksPanel backlinks={backlinks} />
                   </div>
                   <div className="h-32"></div>
               </div>
               {viewMode === 'preview' && <TableOfContents items={toc} />}
           </div>
         )}
      </div>

      <div className="h-8 border-t border-zenith-border bg-zenith-surface flex items-center justify-between px-4 font-mono text-[10px] text-zenith-muted uppercase tracking-widest shrink-0">
         <div>Ln {lineCount}, Col {content.length}</div>
         <div>{isAuthenticated ? 'Markdown Environment' : 'Visitor View'}</div>
      </div>

      <DeleteConfirmModal 
        isOpen={isDeleteModalOpen}
        onClose={() => setIsDeleteModalOpen(false)}
        onConfirm={handleDeleteConfirm}
        title="Delete File"
        itemName={file.name}
      />

      <LinkSelectorModal
        isOpen={isLinkSelectorOpen}
        onClose={() => setIsLinkSelectorOpen(false)}
        repos={repos}
        onSelect={handleLinkSelect}
      />
    </div>
  );
};

export default FileEditor;

import React, { useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { Repository } from '../types';
import { Icons } from '../components/Icon';
import MarkdownPreview from '../components/MarkdownPreview';
import DeleteConfirmModal from '../components/DeleteConfirmModal';
import RepoSettingsModal from '../components/RepoSettingsModal';
import GraphViewWrapper from '../components/GraphView';

interface RepositoryViewProps {
  repos: Repository[];
  onAddFile: (repoId: string, filename: string) => void;
  onDeleteRepo: (repoId: string) => void;
  onUpdateRepo: (repoId: string, name: string, description: string) => void;
  onUpdateFile: (repoId: string, fileId: string, content: string) => void; // Added for graph connection
  isAuthenticated: boolean;
}

const RepositoryView: React.FC<RepositoryViewProps> = ({ repos, onAddFile, onDeleteRepo, onUpdateRepo, onUpdateFile, isAuthenticated }) => {
  const { repoId } = useParams<{ repoId: string }>();
  const navigate = useNavigate();
  const repo = repos.find(r => r.id === repoId);

  const [showAddFile, setShowAddFile] = useState(false);
  const [newFileName, setNewFileName] = useState('');

  // View State: 'list' or 'graph'
  const [viewMode, setViewMode] = useState<'list' | 'graph'>('list');

  // Graph Scope: 'local' or 'global' - Persisted preference
  const [graphScope, setGraphScopeState] = useState<'local' | 'global'>(() => {
      return (localStorage.getItem('gitnotes_graph_scope') as 'local' | 'global') || 'local';
  });

  const setGraphScope = (scope: 'local' | 'global') => {
      setGraphScopeState(scope);
      localStorage.setItem('gitnotes_graph_scope', scope);
  };

  // Modal states
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [isSettingsModalOpen, setIsSettingsModalOpen] = useState(false);

  if (!repo) {
    return <div className="h-screen flex items-center justify-center font-mono text-zenith-orange">ERROR: MODULE NOT FOUND</div>;
  }

  const handleAddFile = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newFileName.trim()) return;
    let name = newFileName.trim();
    if (!name.endsWith('.md')) name += '.md';

    onAddFile(repo.id, name);
    setShowAddFile(false);
    setNewFileName('');
  };

  const handleDeleteConfirm = () => {
    onDeleteRepo(repo.id);
    navigate('/');
  };

  const handleConnectNodes = (sourceId: string, targetId: string) => {
      if (!isAuthenticated) return;

      // Find files across ALL repos if global, or just local if local logic (though helper keeps it simple)
      let sourceFile = repo.files.find(f => f.id === sourceId);
      let targetFile = repo.files.find(f => f.id === targetId);
      let targetRepoId = repo.id;

      // Global Search for node connection
      if (!sourceFile || !targetFile) {
          repos.forEach(r => {
              const s = r.files.find(f => f.id === sourceId);
              if (s) sourceFile = s;
              const t = r.files.find(f => f.id === targetId);
              if (t) {
                  targetFile = t;
                  targetRepoId = r.id;
              }
          });
      }

      if (sourceFile && targetFile) {
          const linkName = targetFile.name.replace('.md', '');
          // Check if link already exists to prevent duplication
          if (!sourceFile.content.includes(`[[${linkName}]]`)) {
             const newContent = sourceFile.content + `\n\nRelated: [[${linkName}]]`;
             // We need to find the repo ID of the SOURCE file to update it
             const sourceRepo = repos.find(r => r.files.some(f => f.id === sourceId));
             if (sourceRepo) {
                 onUpdateFile(sourceRepo.id, sourceId, newContent);
             }
          }
      }
  };

  const handleDisconnectNodes = (sourceId: string, targetId: string) => {
      if (!isAuthenticated) return;

      let sourceFile = repo.files.find(f => f.id === sourceId);
      let targetFile = repo.files.find(f => f.id === targetId);

      // Global Search
      if (!sourceFile || !targetFile) {
          repos.forEach(r => {
              const s = r.files.find(f => f.id === sourceId);
              if (s) sourceFile = s;
              const t = r.files.find(f => f.id === targetId);
              if (t) targetFile = t;
          });
      }

      if (sourceFile && targetFile) {
          const linkName = targetFile.name.replace('.md', '');
          const escapedLinkName = linkName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

          const lines = sourceFile.content.split('\n');
          const newLines = lines.filter(line => {
              const linkRegex = new RegExp(`\\[\\[${escapedLinkName}(?:\\.md)?\\]\\]`, 'i');
              if (!linkRegex.test(line)) return true;
              const listItemRegex = new RegExp(`^\\s*(?:[-*+]|\\d+\\.)\\s*\\[\\[${escapedLinkName}(?:\\.md)?\\]\\].*$`, 'i');
              if (listItemRegex.test(line)) return false; 
              const propRegex = new RegExp(`^\\s*(?:Related|Parent|Child|See|Source|Upstream|Ref)\\s*:?\\s*\\[\\[${escapedLinkName}(?:\\.md)?\\]\\].*$`, 'i');
              if (propRegex.test(line)) return false; 
              if (line.trim() === `[[${linkName}]]` || line.trim() === `[[${linkName}.md]]`) return false;
              return true;
          }).map(line => {
              const linkRegex = new RegExp(`\\[\\[(${escapedLinkName})(?:\\.md)?\\]\\]`, 'gi');
              return line.replace(linkRegex, '$1'); 
          });

          let newContent = newLines.join('\n');
          newContent = newContent.replace(/\n{3,}/g, '\n\n').trim();

          const sourceRepo = repos.find(r => r.files.some(f => f.id === sourceId));
          if (sourceRepo) {
            onUpdateFile(sourceRepo.id, sourceId, newContent);
          }
      }
  };

  // Find README for preview
  const readme = repo.files.find(f => f.name.toLowerCase() === 'readme.md');

  return (
    <div className="min-h-screen bg-zenith-bg p-6 md:p-12 max-w-[1600px] mx-auto">

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 mb-8 border-b border-zenith-border pb-6">
        <div>
            <div className="flex items-center gap-2 font-mono text-xs text-zenith-muted mb-2">
                <Link to="/" className="hover:text-zenith-orange">ROOT</Link>
                <span>/</span>
                <span className="text-white">{repo.id.toUpperCase()}</span>
            </div>
            <h1 className="text-4xl font-bold tracking-tight text-white mb-2">{repo.name}</h1>
            <p className="text-zenith-muted font-mono text-sm max-w-2xl">{repo.description}</p>
        </div>

        {isAuthenticated && (
          <div className="flex items-center gap-4">
              {/* View Toggle (Hidden on Mobile) */}
              <div className="hidden md:flex border border-zenith-border p-0.5 bg-zenith-surface mr-4">
                 <button 
                    onClick={() => setViewMode('list')}
                    className={`px-3 py-2 text-xs font-mono uppercase transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="List View"
                 >
                    <Icons.List size={14} />
                 </button>
                 <button 
                    onClick={() => setViewMode('graph')}
                    className={`px-3 py-2 text-xs font-mono uppercase transition-all flex items-center gap-2 border-l border-zenith-border ${viewMode === 'graph' ? 'bg-white text-black font-bold' : 'text-zenith-muted hover:text-white'}`}
                    title="Constellation View"
                 >
                    <Icons.Network size={14} />
                 </button>
              </div>

              <button 
                  onClick={() => setIsSettingsModalOpen(true)}
                  className="bg-zenith-surface border border-zenith-border text-zenith-muted px-3 py-2 text-xs font-mono uppercase hover:text-white hover:border-white transition-colors duration-75 flex items-center gap-2"
                  title="Configure Module"
              >
                  <Icons.Settings size={14} />
              </button>
              <div className="w-px h-6 bg-zenith-border"></div>
              <button 
                  onClick={() => setShowAddFile(true)}
                  className="bg-zenith-surface border border-zenith-border text-white px-4 py-2 text-xs font-mono tracking-widest uppercase hover:bg-white hover:text-black transition-colors duration-75 flex items-center gap-2"
              >
                  <Icons.Plus size={14} /> Add File
              </button>
              <button 
                  onClick={() => setIsDeleteModalOpen(true)}
                  className="border border-zenith-border text-zenith-muted px-4 py-2 text-xs font-mono tracking-widest uppercase hover:border-zenith-orange hover:text-zenith-orange transition-colors duration-75"
              >
                  Delete
              </button>
          </div>
        )}
      </div>

      {/* Add File Input (Global for this view) */}
      {showAddFile && isAuthenticated && (
        <div className="mb-8 p-6 border border-zenith-orange bg-zenith-surface/50 animate-in slide-in-from-top-2">
           <form onSubmit={handleAddFile} className="flex gap-4 items-center">
               <span className="font-mono text-zenith-orange text-lg">/</span>
               <input 
                 autoFocus
                 type="text" 
                 placeholder="filename.md" 
                 className="bg-transparent border-b border-zenith-border text-white p-2 font-mono text-sm flex-1 outline-none focus:border-zenith-orange"
                 value={newFileName}
                 onChange={e => setNewFileName(e.target.value)}
               />
               <button type="submit" className="text-zenith-orange font-mono text-xs uppercase hover:underline">Execute</button>
               <button type="button" onClick={() => setShowAddFile(false)} className="text-zenith-muted font-mono text-xs uppercase hover:text-white">Cancel</button>
           </form>
        </div>
      )}

      {/* Main Content Switcher */}
      {viewMode === 'graph' ? (
          <div className="border border-zenith-border bg-zenith-surface/20 animate-in fade-in duration-500 relative hidden md:block">

             {/* Scope Toggle (Floating inside Graph) */}
             <div className="absolute top-4 left-4 z-20 flex gap-2">
                <button 
                   onClick={() => setGraphScope('local')}
                   className={`px-3 py-1 text-[10px] font-mono uppercase tracking-widest border transition-colors ${graphScope === 'local' ? 'bg-zenith-orange text-black border-zenith-orange' : 'bg-black text-zenith-muted border-zenith-border hover:border-white'}`}
                >
                   Local Sector
                </button>
                <button 
                   onClick={() => setGraphScope('global')}
                   className={`px-3 py-1 text-[10px] font-mono uppercase tracking-widest border transition-colors ${graphScope === 'global' ? 'bg-zenith-green text-black border-zenith-green' : 'bg-black text-zenith-muted border-zenith-border hover:border-white'}`}
                >
                   Galaxy View
                </button>
             </div>

             <GraphViewWrapper 
                activeRepoId={repo.id}
                repos={repos} // Pass ALL repos now
                scope={graphScope}
                onAddFile={() => setShowAddFile(true)}
                onLinkNodes={handleConnectNodes}
                onDisconnectNodes={handleDisconnectNodes}
             />
          </div>
      ) : (
          <div className="grid lg:grid-cols-3 gap-8 animate-in fade-in duration-300">
              {/* File List Table */}
              <div className="lg:col-span-2">
                <div className="border border-zenith-border">
                    <div className="bg-zenith-surface border-b border-zenith-border px-4 py-2 font-mono text-[10px] tracking-widest text-zenith-muted uppercase flex justify-between">
                        <span>File Index</span>
                        <span>Count: {repo.files.length}</span>
                    </div>

                    <div className="divide-y divide-zenith-border bg-black">
                        {repo.files.map(file => (
                            <div key={file.id} className="group flex items-center justify-between p-4 hover:bg-zenith-surface transition-colors duration-75">
                                <div className="flex items-center gap-4">
                                    <Icons.File size={16} className="text-zenith-muted group-hover:text-zenith-orange" />
                                    <Link to={`/${repo.id}/${file.id}`} className="font-mono text-sm text-zenith-text group-hover:text-white group-hover:underline decoration-zenith-orange underline-offset-4">
                                        {file.name}
                                    </Link>
                                </div>
                                <div className="flex items-center gap-6">
                                    <span className="font-mono text-[10px] text-zenith-muted hidden sm:block">
                                        {(file.size / 1024).toFixed(2)} KB
                                    </span>
                                    <span className="font-mono text-[10px] text-zenith-muted">
                                        {new Date(file.updatedAt).toLocaleDateString()}
                                    </span>
                                </div>
                            </div>
                        ))}
                        {repo.files.length === 0 && (
                            <div className="p-8 text-center font-mono text-xs text-zenith-muted uppercase">
                                No files detected in sector
                            </div>
                        )}
                    </div>
                </div>
              </div>

              {/* README Preview Panel */}
              <div className="lg:col-span-1">
                {readme ? (
                    <div className="border border-zenith-border sticky top-20">
                        <div className="bg-zenith-surface border-b border-zenith-border px-4 py-2 font-mono text-[10px] tracking-widest text-zenith-muted uppercase flex items-center gap-2">
                            <div className="w-2 h-2 bg-zenith-green rounded-full"></div>
                            <span>Preview: README.md</span>
                        </div>
                        <div className="p-6 bg-zenith-bg max-h-[calc(100vh-200px)] overflow-y-auto">
                            <MarkdownPreview content={readme.content} />
                        </div>
                    </div>
                ) : (
                    <div className="border border-zenith-border border-dashed p-8 text-center">
                        <span className="font-mono text-xs text-zenith-muted">NO README DETECTED</span>
                    </div>
                )}
              </div>
          </div>
      )}

      {/* Mobile Fallback for Graph Mode Persistence */}
      {viewMode === 'graph' && (
          <div className="md:hidden border border-zenith-border bg-zenith-surface/10 p-8 text-center">
              <div className="text-zenith-orange font-mono text-xs uppercase tracking-widest mb-2">Display Error</div>
              <div className="text-zenith-muted text-xs">Constellation View is not available on mobile interfaces.</div>
              <button 
                onClick={() => setViewMode('list')}
                className="mt-4 bg-zenith-surface border border-zenith-border px-4 py-2 text-xs font-mono text-white hover:border-white uppercase"
              >
                  Return to List View
              </button>
          </div>
      )}

      <DeleteConfirmModal 
        isOpen={isDeleteModalOpen}
        onClose={() => setIsDeleteModalOpen(false)}
        onConfirm={handleDeleteConfirm}
        title="Delete Module"
        itemName={repo.name}
        warningText="Deleting this repository will permanently erase all contained files and version history. This action cannot be reversed."
      />

      <RepoSettingsModal 
        isOpen={isSettingsModalOpen}
        onClose={() => setIsSettingsModalOpen(false)}
        onSave={(name, desc) => onUpdateRepo(repo.id, name, desc)}
        initialName={repo.name}
        initialDesc={repo.description}
      />
    </div>
  );
};

export default RepositoryView;
